const i=[{id:"advanced-agents/cre-management/kpc-producing-cre/ceftazidime-avibactam-1",diseaseId:"advanced-agents",diseaseName:"Advanced & Resistant Pathogen Agents",diseaseIcon:"🛡",subcategoryId:"cre-management",subcategoryName:"Carbapenem-Resistant Enterobacteriaceae (CRE)",line:"KPC-producing CRE",regimen:"Ceftazidime-Avibactam 2.5g IV q8h (adjust for renal function)",notes:"Preferred for KPC-CRE and OXA-48. Does NOT cover NDM. Check local susceptibility.",drug:"ceftazidime-avibactam",monographId:"ceftazidime-avibactam",evidence:"A-II",evidenceSource:"IDSA 2022",evidenceSourceIds:["idsa-2022-amr"]},{id:"advanced-agents/cre-management/kpc-producing-cre/meropenem-vaborbactam-2",diseaseId:"advanced-agents",diseaseName:"Advanced & Resistant Pathogen Agents",diseaseIcon:"🛡",subcategoryId:"cre-management",subcategoryName:"Carbapenem-Resistant Enterobacteriaceae (CRE)",line:"KPC-producing CRE",regimen:"Meropenem-Vaborbactam 4g IV q8h (infuse over 3h)",notes:"Alternative for KPC-CRE. Does NOT cover NDM, OXA-48, or Acinetobacter.",drug:"meropenem-vaborbactam",monographId:"meropenem-vaborbactam",evidence:"A-II",evidenceSource:"IDSA 2022",evidenceSourceIds:["idsa-2022-amr"]},{id:"advanced-agents/cre-management/ndm-producing-cre/ceftazidime-avibactam-1",diseaseId:"advanced-agents",diseaseName:"Advanced & Resistant Pathogen Agents",diseaseIcon:"🛡",subcategoryId:"cre-management",subcategoryName:"Carbapenem-Resistant Enterobacteriaceae (CRE)",line:"NDM-producing CRE",regimen:"Ceftazidime-Avibactam 2.5g IV q8h + Aztreonam 2g IV q6h (extended infusion)",notes:"Combination required — CAZ-AVI restores aztreonam activity against MBL-producers. Ceftazidime-avibactam protects aztreonam from hydrolysis. ID consult mandatory.",drug:"ceftazidime-avibactam",monographId:"ceftazidime-avibactam",evidence:"B-II",evidenceSource:"IDSA 2022",evidenceSourceIds:["idsa-2022-amr"]},{id:"advanced-agents/cre-management/salvage-pan-resistant/colistin-1",diseaseId:"advanced-agents",diseaseName:"Advanced & Resistant Pathogen Agents",diseaseIcon:"🛡",subcategoryId:"cre-management",subcategoryName:"Carbapenem-Resistant Enterobacteriaceae (CRE)",line:"Salvage / Pan-resistant",regimen:"Colistin (CMS) — load 9 MU IV, then 4.5 MU IV q12h (CrCl-adjusted), always in combination",notes:"Use only when all other options exhausted. Nephrotoxicity in 30-50%. Never monotherapy. Combination with meropenem, rifampin, or fosfomycin based on MIC data.",drug:"colistin",monographId:"colistin",evidence:"C-III",evidenceSource:"IDSA 2022",evidenceSourceIds:["idsa-2022-amr"]},{id:"advanced-agents/mdr-pseudomonas/preferred-dtr-pa/ceftolozane-tazobactam-1",diseaseId:"advanced-agents",diseaseName:"Advanced & Resistant Pathogen Agents",diseaseIcon:"🛡",subcategoryId:"mdr-pseudomonas",subcategoryName:"Difficult-to-Treat Pseudomonas aeruginosa (DTR-PA)",line:"Preferred (DTR-PA)",regimen:"Ceftolozane-Tazobactam 3g IV q8h (HAP/VAP: 1.5g q8h for cUTI/IAI) — standard infusion 1h",notes:"Excellent anti-pseudomonal activity. Stable against most Pseudomonas resistance mechanisms except MBL.",drug:"ceftolozane-tazobactam",monographId:"ceftolozane-tazobactam",evidence:"A-II",evidenceSource:"IDSA 2022",evidenceSourceIds:["idsa-2022-amr"]},{id:"advanced-agents/mdr-pseudomonas/preferred-dtr-pa/imipenem-cilastatin-relebactam-2",diseaseId:"advanced-agents",diseaseName:"Advanced & Resistant Pathogen Agents",diseaseIcon:"🛡",subcategoryId:"mdr-pseudomonas",subcategoryName:"Difficult-to-Treat Pseudomonas aeruginosa (DTR-PA)",line:"Preferred (DTR-PA)",regimen:"Imipenem-Cilastatin-Relebactam 1.25g IV q6h (infuse over 30 min)",notes:"Active against KPC and AmpC producers. Restores imipenem activity. RESTORE-IMI trials support use.",drug:"imipenem-cilastatin-relebactam",monographId:"imipenem-cilastatin-relebactam",evidence:"A-II",evidenceSource:"IDSA 2022",evidenceSourceIds:["idsa-2022-amr"]},{id:"amr-gn/ampc-e/avoid-for-invasive-ampc-e-infections/ceftriaxone-avoid-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"ampc-e",subcategoryName:"AmpC β-Lactamase-Producing Enterobacterales (AmpC-E)",line:"Avoid for Invasive AmpC-E Infections",regimen:"Ceftriaxone — NOT recommended for invasive E. cloacae, K. aerogenes, C. freundii",notes:"EVEN IF SUSCEPTIBLE on initial AST. ~20% resistance emergence during therapy. Ceftriaxone is a substrate for AmpC hydrolysis — once ampC is induced/derepressed, ceftriaxone fails. This is the most common AmpC treatment error. Exception: uncomplicated cystitis (high urinary concentrations) or step-down after clear clinical improvement with no ongoing source.",drug:"ceftriaxone-avoid"},{id:"amr-gn/ampc-e/avoid-for-invasive-ampc-e-infections/pip-tazo-ampc-avoid-2",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"ampc-e",subcategoryName:"AmpC β-Lactamase-Producing Enterobacterales (AmpC-E)",line:"Avoid for Invasive AmpC-E Infections",regimen:"Piperacillin-tazobactam — NOT recommended for invasive AmpC-E infections",notes:"Tazobactam is a POOR inhibitor of AmpC enzymes (unlike avibactam/relebactam/vaborbactam). Multiple observational studies show poorer outcomes with pip-tazo vs cefepime or carbapenems for AmpC-E bacteremia. Pilot RCT showed higher microbiological failure with pip-tazo vs meropenem for AmpC-E BSI.",drug:"pip-tazo-ampc-avoid"},{id:"amr-gn/ampc-e/preferred-invasive-infections-e-cloacae-k-aeroge/cefepime-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"ampc-e",subcategoryName:"AmpC β-Lactamase-Producing Enterobacterales (AmpC-E)",line:"Preferred — Invasive Infections (E. cloacae, K. aerogenes, C. freundii)",regimen:"Cefepime 2g IV q8h (extended infusion over 3h)",notes:"IDSA 2024 preferred for AmpC-E infections. Weak ampC inducer AND stable against AmpC hydrolysis (forms stable acyl enzyme complexes). Observational studies and meta-analysis show similar outcomes to carbapenems. No clinical trial exists comparing cefepime vs carbapenem for AmpC-E, but mechanism and observational data strongly support cefepime. CARBAPENEM-SPARING — this is the critical stewardship advantage.",drug:"cefepime",monographId:"cefepime"},{id:"amr-gn/ampc-e/preferred-invasive-infections-e-cloacae-k-aeroge/meropenem-2",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"ampc-e",subcategoryName:"AmpC β-Lactamase-Producing Enterobacterales (AmpC-E)",line:"Preferred — Invasive Infections (E. cloacae, K. aerogenes, C. freundii)",regimen:"Meropenem 1g IV q8h (extended infusion)",notes:"Carbapenems are stable against AmpC hydrolysis. Use for AmpC-E when cefepime cannot be used (allergy, cefepime neurotoxicity, polymicrobial infection requiring broader coverage). Imipenem is a potent ampC inducer but remains stable to hydrolysis. Ertapenem reasonable for stable, non-critically ill.",drug:"meropenem",monographId:"meropenem"},{id:"amr-gn/ampc-e/preferred-uncomplicated-cystitis/nitrofurantoin-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"ampc-e",subcategoryName:"AmpC β-Lactamase-Producing Enterobacterales (AmpC-E)",line:"Preferred — Uncomplicated Cystitis",regimen:"Nitrofurantoin 100mg PO BID × 5 days",notes:"IDSA 2024 preferred for AmpC-E uncomplicated cystitis. Not a beta-lactam — unaffected by AmpC. Ceftriaxone is also acceptable for uncomplicated cystitis (high urinary concentrations overcome AmpC concerns).",drug:"nitrofurantoin",monographId:"nitrofurantoin"},{id:"amr-gn/ampc-e/preferred-uncomplicated-cystitis/tmp-smx-2",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"ampc-e",subcategoryName:"AmpC β-Lactamase-Producing Enterobacterales (AmpC-E)",line:"Preferred — Uncomplicated Cystitis",regimen:"TMP-SMX DS 1 tab PO BID × 3 days",notes:"IDSA 2024 preferred for AmpC-E cystitis if susceptible. Not a beta-lactam substrate.",drug:"tmp-smx",monographId:"tmp-smx"},{id:"amr-gn/crab-steno/alternative-crab-if-sulbactam-durlobactam-unavai/high-dose-amp-sulb-crab-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"crab-steno",subcategoryName:"CRAB & Stenotrophomonas maltophilia",line:"Alternative — CRAB (If Sulbactam-Durlobactam Unavailable)",regimen:"High-dose ampicillin-sulbactam 9g IV q8h (= 27g/day total: 18g ampicillin + 9g sulbactam) + at least 1 additional agent",notes:"IDSA 2024 alternative (downgraded from preferred in 2023 update). Sulbactam component provides intrinsic Acinetobacter activity. Must be combined with at least one other agent: polymyxin B, minocycline (preferred over tigecycline), or cefiderocol. The 27g/day dosing (9g sulbactam) maximizes the sulbactam PK/PD target.",drug:"high-dose-amp-sulb-crab"},{id:"amr-gn/crab-steno/alternative-crab-if-sulbactam-durlobactam-unavai/polymyxin-b-crab-2",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"crab-steno",subcategoryName:"CRAB & Stenotrophomonas maltophilia",line:"Alternative — CRAB (If Sulbactam-Durlobactam Unavailable)",regimen:"Polymyxin B 2.5-3 mg/kg/day IV divided q12h (NOT colistimethate for systemic CRAB)",notes:"Component of CRAB combination therapy. Polymyxin B preferred over colistimethate (colistin) for systemic infections: more predictable PK, does not require conversion from prodrug, less nephrotoxic. Colistimethate has a role in urinary tract infections (converts to active colistin in urine) and nebulized therapy. Never use polymyxin monotherapy for CRAB — always combine.",drug:"polymyxin-b-crab"},{id:"amr-gn/crab-steno/preferred-crab-infections/sulbactam-durlobactam-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"crab-steno",subcategoryName:"CRAB & Stenotrophomonas maltophilia",line:"Preferred — CRAB Infections",regimen:"Sulbactam-durlobactam 1g/0.5g IV q6h + Imipenem-cilastatin 500mg IV q6h (or Meropenem 2g IV q8h)",notes:"IDSA 2024 preferred for CRAB. ATTACK trial: 28-day mortality 19% vs 32% with colistin. Durlobactam is a diazabicyclooctane BLI that inhibits Acinetobacter OXA carbapenemases + Class A/C enzymes. Sulbactam provides the intrinsic anti-Acinetobacter killing. Carbapenem backbone adds additional activity and covers potential co-pathogens. Brand name: Xacduro.",drug:"sulbactam-durlobactam"},{id:"amr-gn/crab-steno/preferred-s-maltophilia-infections-in-order-of-p/cefiderocol-steno-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"crab-steno",subcategoryName:"CRAB & Stenotrophomonas maltophilia",line:"Preferred — S. maltophilia Infections (in order of preference)",regimen:"Cefiderocol 2g IV q8h (with a second agent at least initially)",notes:"IDSA 2024 preferred (listed first). Stable against S. maltophilia's intrinsic L1 MBL and L2 serine BL. Siderophore entry bypasses efflux/porin resistance. Add a second agent initially (minocycline, TMP-SMX, or levofloxacin) until clinical improvement, then consider cefiderocol monotherapy.",drug:"cefiderocol-steno"},{id:"amr-gn/crab-steno/preferred-s-maltophilia-infections-in-order-of-p/caz-avi-aztreonam-steno-2",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"crab-steno",subcategoryName:"CRAB & Stenotrophomonas maltophilia",line:"Preferred — S. maltophilia Infections (in order of preference)",regimen:"Ceftazidime-avibactam 2.5g IV q8h + Aztreonam 2g IV q8h",notes:"IDSA 2024 preferred (listed second). Same rationale as for MBL-CRE: aztreonam stable to L1 MBL, avibactam inhibits L2 serine BL. BDE testing endorsed by CLSI for this combination against S. maltophilia.",drug:"caz-avi-aztreonam-steno"},{id:"amr-gn/crab-steno/preferred-s-maltophilia-infections-in-order-of-p/minocycline-steno-4",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"crab-steno",subcategoryName:"CRAB & Stenotrophomonas maltophilia",line:"Preferred — S. maltophilia Infections (in order of preference)",regimen:"Minocycline 200mg IV/PO q12h (with a second agent)",notes:"IDSA 2024 preferred (with second agent). Minocycline is preferred over tigecycline for S. maltophilia (better activity, fewer GI side effects). Good oral bioavailability for step-down. 70-80% S. maltophilia susceptibility in most centers.",drug:"minocycline-steno"},{id:"amr-gn/crab-steno/preferred-s-maltophilia-infections-in-order-of-p/tmp-smx-steno-3",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"crab-steno",subcategoryName:"CRAB & Stenotrophomonas maltophilia",line:"Preferred — S. maltophilia Infections (in order of preference)",regimen:"TMP-SMX 15 mg/kg/day IV divided q6-8h (with a second agent)",notes:"IDSA 2024 preferred (with second agent). Historically the first-line agent for S. maltophilia. Still effective but rising resistance (10-20% in some centers). IV dosing uses the TMP component for calculation. Combine with minocycline, levofloxacin, or cefiderocol.",drug:"tmp-smx-steno"},{id:"amr-gn/cre-kpc/alternative-kpc-cre/cefiderocol-cre-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"cre-kpc",subcategoryName:"CRE — KPC-Producing Enterobacterales",line:"Alternative — KPC-CRE",regimen:"Cefiderocol 2g IV q8h (infused over 3h)",notes:"IDSA 2024 alternative for KPC-CRE. Siderophore cephalosporin — uses bacterial iron transport for cell entry. >95% activity against KPC-CRE. Reserved as alternative to preserve for MBL-CRE and CRAB where fewer options exist. Clinical data for KPC-CRE more limited than the three preferred BL-BLIs.",drug:"cefiderocol-cre"},{id:"amr-gn/cre-kpc/preferred-cre-pyelonephritis-complicated-uti/caz-avi-cre-uti-2",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"cre-kpc",subcategoryName:"CRE — KPC-Producing Enterobacterales",line:"Preferred — CRE Pyelonephritis / Complicated UTI",regimen:"Ceftazidime-avibactam, meropenem-vaborbactam, or imipenem-relebactam (any preferred for CRE UTI)",notes:"Use novel BL-BLIs for CRE pyelonephritis/cUTI when TMP-SMX/FQ not available. Aminoglycosides (once-daily) are alternative for CRE UTI — good renal cortex concentrations, convenient dosing for short courses.",drug:"caz-avi-cre-uti"},{id:"amr-gn/cre-kpc/preferred-cre-pyelonephritis-complicated-uti/tmp-smx-cre-uti-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"cre-kpc",subcategoryName:"CRE — KPC-Producing Enterobacterales",line:"Preferred — CRE Pyelonephritis / Complicated UTI",regimen:"TMP-SMX, ciprofloxacin, or levofloxacin (if susceptible)",notes:"IDSA 2024: if susceptibility confirmed, non-beta-lactam agents are preferred for CRE UTI to preserve novel BL-BLIs. Minority of CRE will be susceptible to these agents, but always check. Oral agents allow outpatient completion.",drug:"tmp-smx-cre-uti"},{id:"amr-gn/cre-kpc/preferred-kpc-producing-cre-non-urinary-infectio/ceftazidime-avibactam-2",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"cre-kpc",subcategoryName:"CRE — KPC-Producing Enterobacterales",line:"Preferred — KPC-Producing CRE (Non-Urinary Infections)",regimen:"Ceftazidime-avibactam 2.5g IV q8h (infused over 2h)",notes:"IDSA 2024 preferred. >95% activity against KPC-CRE. Avibactam inhibits KPC, ESBL, AmpC, and OXA-48-like enzymes. Most clinical experience of any novel BL-BLI for CRE. CAUTION: higher resistance emergence risk than mer-vab (KPC mutations in omega loop can cause caz-avi resistance). 2.5g = 2g ceftazidime + 0.5g avibactam.",drug:"ceftazidime-avibactam",monographId:"ceftazidime-avibactam"},{id:"amr-gn/cre-kpc/preferred-kpc-producing-cre-non-urinary-infectio/imipenem-relebactam-3",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"cre-kpc",subcategoryName:"CRE — KPC-Producing Enterobacterales",line:"Preferred — KPC-Producing CRE (Non-Urinary Infections)",regimen:"Imipenem-cilastatin-relebactam 1.25g IV q6h (infused over 30 min)",notes:"IDSA 2024 preferred. RESTORE-IMI 1: 71% favorable response vs 40% for imipenem + colistin. >95% activity against KPC-CRE. Relebactam inhibits KPC and AmpC. Fewest clinical data of the three preferred agents, hence ranked third. 1.25g = 500mg imipenem + 500mg cilastatin + 250mg relebactam.",drug:"imipenem-relebactam"},{id:"amr-gn/cre-kpc/preferred-kpc-producing-cre-non-urinary-infectio/meropenem-vaborbactam-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"cre-kpc",subcategoryName:"CRE — KPC-Producing Enterobacterales",line:"Preferred — KPC-Producing CRE (Non-Urinary Infections)",regimen:"Meropenem-vaborbactam 4g IV q8h (extended infusion over 3h)",notes:"IDSA 2024: slightly favored among the three preferred agents. TANGO II trial: 59% clinical cure vs 26% with BAT for CRE. >95% activity against KPC-producing CRE. Vaborbactam is a potent boronic acid inhibitor of KPCs. Lowest resistance emergence risk of the three preferred agents. 4g = 2g meropenem + 2g vaborbactam per dose.",drug:"meropenem-vaborbactam",monographId:"meropenem-vaborbactam"},{id:"amr-gn/cre-mbl/alternative-mbl-cre/aztreonam-mervab-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"cre-mbl",subcategoryName:"CRE — Metallo-β-Lactamase Producers (NDM, VIM, IMP)",line:"Alternative — MBL-CRE",regimen:"Aztreonam 2g IV q8h + meropenem-vaborbactam or imipenem-relebactam",notes:"If caz-avi + aztreonam or cefiderocol not possible (allergy, intolerance). Limited clinical data. Rationale: vaborbactam/relebactam inhibit co-produced serine beta-lactamases, allowing aztreonam to function. NOT effective if OXA-type carbapenemases are also present.",drug:"aztreonam-mervab"},{id:"amr-gn/cre-mbl/alternative-mbl-cre/tigecycline-mbl-2",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"cre-mbl",subcategoryName:"CRE — Metallo-β-Lactamase Producers (NDM, VIM, IMP)",line:"Alternative — MBL-CRE",regimen:"Tigecycline 100mg IV load then 50mg IV q12h (or eravacycline 1mg/kg IV q12h)",notes:"Alternative for non-BSI, non-UTI MBL-CRE infections (IAI, SSTI, pneumonia). Activity is independent of carbapenemase type. NOT for BSI (low serum concentrations) or UTI (minimal urinary excretion). Nausea/vomiting common. FDA boxed warning for increased mortality.",drug:"tigecycline-mbl"},{id:"amr-gn/cre-mbl/preferred-mbl-producing-cre-non-urinary-infectio/cefiderocol-2",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"cre-mbl",subcategoryName:"CRE — Metallo-β-Lactamase Producers (NDM, VIM, IMP)",line:"Preferred — MBL-Producing CRE (Non-Urinary Infections)",regimen:"Cefiderocol 2g IV q8h (infused over 3h)",notes:"IDSA 2024 preferred for MBL-CRE. Siderophore cephalosporin — enters bacteria via iron transporters, bypassing porin-dependent entry. Stable against MBL hydrolysis. ~92% activity against MBL-producing Enterobacterales. Limited clinical trial data specifically for MBL-CRE but clinical trial showed 80% cure vs 0% for BAT in MBL-E infections. Monitor for resistance emergence — described with and without prior cefiderocol exposure.",drug:"cefiderocol",monographId:"cefiderocol"},{id:"amr-gn/cre-mbl/preferred-mbl-producing-cre-non-urinary-infectio/caz-avi-aztreonam-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"cre-mbl",subcategoryName:"CRE — Metallo-β-Lactamase Producers (NDM, VIM, IMP)",line:"Preferred — MBL-Producing CRE (Non-Urinary Infections)",regimen:"Ceftazidime-avibactam 2.5g IV q8h + Aztreonam 2g IV q8h (simultaneous administration)",notes:"IDSA 2024 preferred for MBL-CRE. Rationale: aztreonam is intrinsically stable to MBL hydrolysis, but MBL-producers usually co-produce ESBLs/AmpC that would hydrolyze aztreonam. Avibactam inhibits those co-produced serine beta-lactamases, allowing aztreonam to work. ~90% activity against MBL-producing Enterobacterales. Observational data: 19% mortality vs 44% for other regimens. Administer q8h simultaneously. Monitor LFTs (elevated in ~40% in phase 1 study).",drug:"caz-avi-aztreonam"},{id:"amr-gn/dtr-pa/first-if-susceptible-to-any-traditional-agent-us/cefepime-dtr-traditional-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"dtr-pa",subcategoryName:"DTR Pseudomonas aeruginosa",line:"FIRST: If Susceptible to ANY Traditional Agent — Use It",regimen:"Cefepime 2g IV q8h (extended infusion over 3h) — or whichever traditional agent retains activity",notes:"IDSA 2024: If isolate is NOT susceptible to carbapenems but IS susceptible to cefepime (or vice versa), use the susceptible traditional agent as high-dose extended infusion. This is NOT truly DTR — it's resistant to some but not all standard agents. Reserve novel BL-BLIs for TRUE DTR (resistant to ALL traditional agents).",drug:"cefepime-dtr-traditional"},{id:"amr-gn/dtr-pa/preferred-dtr-p-aeruginosa-uti/ceftolozane-taz-uti-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"dtr-pa",subcategoryName:"DTR Pseudomonas aeruginosa",line:"Preferred — DTR P. aeruginosa UTI",regimen:"Ceftolozane-tazobactam 1.5g IV q8h (UTI dose)",notes:"Standard UTI/cUTI dose (lower than HAP/VAP dose). Any of the four preferred novel agents can be used for DTR-PA UTI. Once-daily tobramycin or amikacin are IDSA 2024 alternatives for DTR-PA UTI (prolonged renal cortex activity, convenient dosing).",drug:"ceftolozane-taz-uti"},{id:"amr-gn/dtr-pa/preferred-true-dtr-p-aeruginosa-non-urinary-infe/cefiderocol-dtr-4",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"dtr-pa",subcategoryName:"DTR Pseudomonas aeruginosa",line:"Preferred — True DTR P. aeruginosa (Non-Urinary Infections)",regimen:"Cefiderocol 2g IV q8h (infused over 3h)",notes:"IDSA 2024 preferred. Siderophore mechanism bypasses porin loss and efflux — two major Pseudomonal resistance mechanisms. Broadest activity against DTR-PA of any single agent. Some experts prefer to use combination therapy initially, transitioning to monotherapy if clinical improvement occurs.",drug:"cefiderocol-dtr"},{id:"amr-gn/dtr-pa/preferred-true-dtr-p-aeruginosa-non-urinary-infe/ceftazidime-avibactam-dtr-2",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"dtr-pa",subcategoryName:"DTR Pseudomonas aeruginosa",line:"Preferred — True DTR P. aeruginosa (Non-Urinary Infections)",regimen:"Ceftazidime-avibactam 2.5g IV q8h (infused over 2h)",notes:"IDSA 2024 preferred. Avibactam inhibits Pseudomonal AmpC and some OXA enzymes. Activity varies by regional resistance mechanisms — some areas show lower DTR-PA susceptibility to caz-avi than to ceftolozane-tazobactam.",drug:"ceftazidime-avibactam-dtr"},{id:"amr-gn/dtr-pa/preferred-true-dtr-p-aeruginosa-non-urinary-infe/ceftolozane-tazobactam-dtr-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"dtr-pa",subcategoryName:"DTR Pseudomonas aeruginosa",line:"Preferred — True DTR P. aeruginosa (Non-Urinary Infections)",regimen:"Ceftolozane-tazobactam 3g IV q8h (infused over 3h) — use HAP/VAP dose for all serious infections",notes:"IDSA 2024 preferred for DTR-PA. Ceftolozane has intrinsic anti-pseudomonal potency greater than ceftazidime. 3g dose (2g ceftolozane + 1g tazobactam) is the HAP/VAP dose — many experts use this dose for all serious DTR-PA infections. Activity is independent of MBL/KPC status — relies on ceftolozane's stability to Pseudomonal AmpC and efflux resistance.",drug:"ceftolozane-tazobactam-dtr"},{id:"amr-gn/dtr-pa/preferred-true-dtr-p-aeruginosa-non-urinary-infe/imipenem-relebactam-dtr-3",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"dtr-pa",subcategoryName:"DTR Pseudomonas aeruginosa",line:"Preferred — True DTR P. aeruginosa (Non-Urinary Infections)",regimen:"Imipenem-cilastatin-relebactam 1.25g IV q6h (infused over 30 min)",notes:"IDSA 2024 preferred. Relebactam restores imipenem activity against Pseudomonas with AmpC/OXA-mediated resistance. RESTORE-IMI 1 trial supports efficacy. Less data specifically for DTR-PA compared to ceftolozane-tazobactam.",drug:"imipenem-relebactam-dtr"},{id:"amr-gn/esbl-e/avoid-for-esbl-e-even-if-susceptible-on-report/cefepime-avoid-2",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"esbl-e",subcategoryName:"ESBL-Producing Enterobacterales (ESBL-E)",line:"Avoid for ESBL-E (Even If Susceptible on Report)",regimen:"Cefepime — NOT recommended for ESBL-E",notes:"ESBLs commonly hydrolyze cefepime. Cefepime MIC testing unreliable for ESBL-E. Clinical trial arm terminated early for high failure signal in ESBL-E pyelonephritis/cUTI despite MICs of 1-2. Observational data show poorer outcomes vs carbapenems for invasive ESBL-E. Do NOT trust cefepime susceptibility for confirmed ESBL-E.",drug:"cefepime-avoid"},{id:"amr-gn/esbl-e/avoid-for-esbl-e-even-if-susceptible-on-report/pip-tazo-avoid-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"esbl-e",subcategoryName:"ESBL-Producing Enterobacterales (ESBL-E)",line:"Avoid for ESBL-E (Even If Susceptible on Report)",regimen:"Piperacillin-tazobactam — NOT recommended for ESBL-E",notes:"MERINO trial: pip-tazo FAILED non-inferiority vs meropenem for ESBL-E BSI (12% vs 4% mortality). Mechanistic concerns: tazobactam may not reliably inhibit ESBLs (low tazobactam:piperacillin ratio of 1:8, MIC testing unreliable, inoculum effect). In vitro susceptibility does NOT guarantee clinical efficacy. Exception: if pip-tazo was started empirically for uncomplicated cystitis and patient improves, no change needed.",drug:"pip-tazo-avoid"},{id:"amr-gn/esbl-e/preferred-non-urinary-infections-bsi-iai-pneumon/ertapenem-2",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"esbl-e",subcategoryName:"ESBL-Producing Enterobacterales (ESBL-E)",line:"Preferred — Non-Urinary Infections (BSI, IAI, Pneumonia)",regimen:"Ertapenem 1g IV daily",notes:"IDSA 2024 preferred for non-critically ill with normal albumin. Once-daily dosing ideal for OPAT. Ertapenem clearance increases with hypoalbuminemia (highly protein-bound) — observational data showed 5× higher mortality in hypoalbuminemic patients receiving ertapenem vs meropenem.",drug:"ertapenem",monographId:"ertapenem"},{id:"amr-gn/esbl-e/preferred-non-urinary-infections-bsi-iai-pneumon/meropenem-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"esbl-e",subcategoryName:"ESBL-Producing Enterobacterales (ESBL-E)",line:"Preferred — Non-Urinary Infections (BSI, IAI, Pneumonia)",regimen:"Meropenem 1g IV q8h (extended infusion over 3h)",notes:"IDSA 2024 preferred for ESBL-E infections outside urinary tract. MERINO trial standard of care. Extended infusion optimizes T>MIC. For critically ill or hypoalbuminemic patients, use meropenem or imipenem — NOT ertapenem.",drug:"meropenem",monographId:"meropenem"},{id:"amr-gn/esbl-e/preferred-pyelonephritis-complicated-uti/ciprofloxacin-2",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"esbl-e",subcategoryName:"ESBL-Producing Enterobacterales (ESBL-E)",line:"Preferred — Pyelonephritis / Complicated UTI",regimen:"Ciprofloxacin 500mg PO BID × 5-7 days (or Levofloxacin 750mg PO daily)",notes:"IDSA 2024 preferred for ESBL-E pyelonephritis/cUTI if susceptible. High bioavailability. However, ESBL-E frequently co-resistant to FQs. Reserve for confirmed susceptible isolates to limit further FQ selection pressure.",drug:"ciprofloxacin",monographId:"ciprofloxacin"},{id:"amr-gn/esbl-e/preferred-pyelonephritis-complicated-uti/ertapenem-3",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"esbl-e",subcategoryName:"ESBL-Producing Enterobacterales (ESBL-E)",line:"Preferred — Pyelonephritis / Complicated UTI",regimen:"Ertapenem 1g IV daily",notes:"IDSA 2024 preferred when TMP-SMX/FQ are not options (resistance or toxicity). Transition to oral TMP-SMX or FQ when susceptible and clinically improving. NOT for critically ill or hypoalbuminemic patients — use meropenem instead.",drug:"ertapenem",monographId:"ertapenem"},{id:"amr-gn/esbl-e/preferred-pyelonephritis-complicated-uti/tmp-smx-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"esbl-e",subcategoryName:"ESBL-Producing Enterobacterales (ESBL-E)",line:"Preferred — Pyelonephritis / Complicated UTI",regimen:"TMP-SMX DS 1 tab PO BID × 5-7 days",notes:"IDSA 2024 preferred for ESBL-E pyelonephritis/cUTI if susceptible. High urinary AND renal parenchymal concentrations. Oral step-down target from carbapenems. Achieves adequate serum levels for tissue penetration.",drug:"tmp-smx",monographId:"tmp-smx"},{id:"amr-gn/esbl-e/preferred-uncomplicated-cystitis/nitrofurantoin-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"esbl-e",subcategoryName:"ESBL-Producing Enterobacterales (ESBL-E)",line:"Preferred — Uncomplicated Cystitis",regimen:"Nitrofurantoin 100mg PO BID × 5 days",notes:"IDSA 2024 preferred for ESBL-E uncomplicated cystitis. NOT affected by ESBL enzymes (different mechanism). Achieves high urinary concentrations. Does NOT achieve systemic levels — for cystitis ONLY, never for pyelonephritis or bacteremia.",drug:"nitrofurantoin",monographId:"nitrofurantoin"},{id:"amr-gn/esbl-e/preferred-uncomplicated-cystitis/tmp-smx-2",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"esbl-e",subcategoryName:"ESBL-Producing Enterobacterales (ESBL-E)",line:"Preferred — Uncomplicated Cystitis",regimen:"TMP-SMX DS 1 tab PO BID × 3 days",notes:"IDSA 2024 preferred for ESBL-E uncomplicated cystitis IF susceptible. Not a beta-lactam — unaffected by ESBLs. Co-resistance is common (ESBL-E often carry additional resistance genes), so susceptibility must be confirmed.",drug:"tmp-smx",monographId:"tmp-smx"},{id:"bacteremia-endocarditis/gram-negative-bacteremia/directed-therapy-duration-by-source/duration-gn-iai-2",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"gram-negative-bacteremia",subcategoryName:"Gram-Negative Bacteremia",line:"Directed Therapy — Duration by Source",regimen:"Intra-abdominal source: 4-7 days after source control",notes:"STOP-IT trial established 4 days of antibiotics after adequate source control for complicated intra-abdominal infections. If source control is inadequate, longer duration is needed. Bacteremia from IAI source does not independently mandate longer therapy if source is controlled.",drug:"duration-gn-iai"},{id:"bacteremia-endocarditis/gram-negative-bacteremia/directed-therapy-duration-by-source/duration-gn-unknown-3",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"gram-negative-bacteremia",subcategoryName:"Gram-Negative Bacteremia",line:"Directed Therapy — Duration by Source",regimen:"Unknown/other source: 7-14 days based on clinical response",notes:"Without clear source, treat for 10-14 days. If source is identified and controlled, shorter courses may be appropriate. Pseudomonas bacteremia: generally 14 days due to higher relapse risk. CRE bacteremia: 14 days with close follow-up.",drug:"duration-gn-unknown"},{id:"bacteremia-endocarditis/gram-negative-bacteremia/directed-therapy-duration-by-source/duration-gn-uti-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"gram-negative-bacteremia",subcategoryName:"Gram-Negative Bacteremia",line:"Directed Therapy — Duration by Source",regimen:"Urinary source: 7-14 days (shorter for uncomplicated, longer for complicated)",notes:"IDSA 2025 cUTI guideline supports 7 days for most complicated UTI with bacteremia, with IV-to-PO switch when clinically improving and susceptibilities allow. Fluoroquinolones and TMP-SMX have excellent oral bioavailability and can be used for step-down.",drug:"duration-gn-uti"},{id:"bacteremia-endocarditis/gram-negative-bacteremia/empiric-community-acquired-low-resistance-risk/ceftriaxone-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"gram-negative-bacteremia",subcategoryName:"Gram-Negative Bacteremia",line:"Empiric — Community-Acquired, Low Resistance Risk",regimen:"Ceftriaxone 2g IV daily",notes:"Excellent first-line empiric for community-acquired GN bacteremia from urinary or intra-abdominal source. Covers most community E. coli, Klebsiella, Proteus. Does NOT cover ESBL producers, AmpC producers (Enterobacter, Citrobacter, Serratia), or Pseudomonas. Add metronidazole if intra-abdominal source suspected (anaerobic coverage).",drug:"ceftriaxone",monographId:"ceftriaxone"},{id:"bacteremia-endocarditis/gram-negative-bacteremia/empiric-healthcare-associated-or-mdr-risk-factor/meropenem-2",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"gram-negative-bacteremia",subcategoryName:"Gram-Negative Bacteremia",line:"Empiric — Healthcare-Associated or MDR Risk Factors",regimen:"Meropenem 1g IV q8h (extended infusion over 3h preferred)",notes:"Reserve for high suspicion of ESBL or AmpC-producing organisms, or critically ill patients. Definitive therapy for confirmed ESBL bacteremia (per MERINO trial). De-escalate as soon as susceptibilities allow — carbapenem stewardship matters.",drug:"meropenem",monographId:"meropenem"},{id:"bacteremia-endocarditis/gram-negative-bacteremia/empiric-healthcare-associated-or-mdr-risk-factor/piperacillin-tazobactam-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"gram-negative-bacteremia",subcategoryName:"Gram-Negative Bacteremia",line:"Empiric — Healthcare-Associated or MDR Risk Factors",regimen:"Piperacillin-tazobactam 4.5g IV q6h (extended infusion over 4h)",notes:"Broader empiric coverage including Pseudomonas. Extended infusion optimizes PK/PD for beta-lactams. Consider if recent healthcare exposure, prior resistant organisms, or immunocompromised. MERINO trial reminder: for ESBL bacteremia, pip-tazo was INFERIOR to meropenem (30-day mortality 12.3% vs 3.7%). De-escalate based on susceptibilities.",drug:"piperacillin-tazobactam"},{id:"bacteremia-endocarditis/native-valve-ie/empiric-native-valve-pending-cultures/vancomycin-plus-ceftriaxone-empiric-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"native-valve-ie",subcategoryName:"Native Valve Infective Endocarditis",line:"Empiric — Native Valve (Pending Cultures)",regimen:"Vancomycin IV (AUC-guided) + Ceftriaxone 2g IV q12h",notes:"Covers MRSA + MSSA + Streptococci + Enterococci + HACEK. Broad empiric regimen for acute IE when organism is unknown. Narrow once cultures return. If hemodynamically unstable, some add gentamicin 1mg/kg IV q8h for the first 3-5 days for synergistic killing (controversial — not routinely recommended due to nephrotoxicity).",drug:"vancomycin-plus-ceftriaxone-empiric",evidence:"A-I",evidenceSource:"AHA 2015 IE Guideline",evidenceSourceIds:["aha-2015-ie"]},{id:"bacteremia-endocarditis/native-valve-ie/enterococcal-native-valve-ie/ampicillin-ceftriaxone-ie-2",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"native-valve-ie",subcategoryName:"Native Valve Infective Endocarditis",line:"Enterococcal Native Valve IE",regimen:"Ampicillin 2g IV q4h + Ceftriaxone 2g IV q12h × 6 weeks",notes:"PREFERRED regimen for E. faecalis IE per many experts. The double beta-lactam combination provides synergistic killing via binding of complementary PBPs (ampicillin = PBP4/5, ceftriaxone = PBP3). KEY ADVANTAGE: avoids aminoglycoside nephrotoxicity and ototoxicity over a 6-week course. Works even in HLGR strains (because synergy is beta-lactam based, not aminoglycoside based). Data from Spanish cohort studies (Fernández-Hidalgo) showed equivalent outcomes with less toxicity.",drug:"ampicillin-ceftriaxone-ie"},{id:"bacteremia-endocarditis/native-valve-ie/enterococcal-native-valve-ie/ampicillin-gent-ie-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"native-valve-ie",subcategoryName:"Native Valve Infective Endocarditis",line:"Enterococcal Native Valve IE",regimen:"Ampicillin 2g IV q4h + Gentamicin 1mg/kg IV q8h × 4-6 weeks",notes:"Traditional regimen for ampicillin-susceptible, non-high-level gentamicin resistant (non-HLGR) E. faecalis. Gentamicin provides synergistic bactericidal activity. HLGR testing is mandatory — if HLGR positive, gentamicin is useless and should not be used. Duration: 4 weeks for native valve with symptoms <3 months, 6 weeks if symptoms >3 months.",drug:"ampicillin-gent-ie"},{id:"bacteremia-endocarditis/native-valve-ie/enterococcal-native-valve-ie/daptomycin-vre-ie-3",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"native-valve-ie",subcategoryName:"Native Valve Infective Endocarditis",line:"Enterococcal Native Valve IE",regimen:"Daptomycin 10-12 mg/kg IV daily ± ampicillin (if ampicillin-susceptible) × 6 weeks",notes:"For VRE (E. faecium) endocarditis — one of the most challenging IE organisms. High-dose daptomycin is the backbone. Adding ampicillin (even if the organism is 'ampicillin-susceptible' VRE, which is rare) enhances daptomycin activity by increasing cell membrane binding. Linezolid 600mg IV/PO BID is an alternative but bacteriostatic — less ideal for endocarditis. Consult ID. Mortality for VRE IE approaches 40-50%.",drug:"daptomycin-vre-ie"},{id:"bacteremia-endocarditis/native-valve-ie/mrsa-native-valve-ie/daptomycin-2",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"native-valve-ie",subcategoryName:"Native Valve Infective Endocarditis",line:"MRSA Native Valve IE",regimen:"Daptomycin 8-10 mg/kg IV daily × 6 weeks",notes:"FDA-approved for right-sided S. aureus IE at 6 mg/kg, but most experts use 8-10 mg/kg for all IE. Preferred over vancomycin for MRSA IE by many ID pharmacists because of: concentration-dependent bactericidal activity, less nephrotoxicity, once-daily dosing, no need for therapeutic drug monitoring (just CPK). AHA guidelines list vancomycin as first-line and daptomycin as alternative, but practice is shifting.",drug:"daptomycin",monographId:"daptomycin"},{id:"bacteremia-endocarditis/native-valve-ie/mrsa-native-valve-ie/vancomycin-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"native-valve-ie",subcategoryName:"Native Valve Infective Endocarditis",line:"MRSA Native Valve IE",regimen:"Vancomycin IV (AUC/MIC 400-600) × 6 weeks",notes:"Standard therapy for MRSA IE. AUC-guided dosing with Bayesian software. Monitor renal function closely — 6 weeks of vancomycin carries significant nephrotoxicity risk. Consider early switch to daptomycin if renal function deteriorates.",drug:"vancomycin",monographId:"vancomycin"},{id:"bacteremia-endocarditis/native-valve-ie/mssa-native-valve-ie/cefazolin-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"native-valve-ie",subcategoryName:"Native Valve Infective Endocarditis",line:"MSSA Native Valve IE",regimen:"Cefazolin 2g IV q8h × 6 weeks",notes:"Preferred over nafcillin/oxacillin based on safety profile and practical advantages (q8h dosing enables OPAT). Non-inferior to nafcillin in multiple observational studies. AHA 2015 lists nafcillin/oxacillin as first-line but most ID pharmacists and many ID physicians have shifted to cefazolin.",drug:"cefazolin",monographId:"cefazolin",evidence:"A-I",evidenceSource:"AHA 2015 IE Guideline",evidenceSourceIds:["aha-2015-ie"]},{id:"bacteremia-endocarditis/native-valve-ie/mssa-native-valve-ie/nafcillin-oxacillin-2",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"native-valve-ie",subcategoryName:"Native Valve Infective Endocarditis",line:"MSSA Native Valve IE",regimen:"Nafcillin or Oxacillin 12g/day IV continuous infusion or 2g IV q4h × 6 weeks",notes:"Traditional gold standard. Still preferred by some for aortic valve IE or complicated cases. Continuous infusion optimizes time-dependent killing. Major disadvantages: phlebitis, hepatotoxicity (oxacillin), interstitial nephritis (nafcillin), q4h dosing if intermittent.",drug:"nafcillin-oxacillin",evidence:"A-I",evidenceSource:"AHA 2015 IE Guideline",evidenceSourceIds:["aha-2015-ie"]},{id:"bacteremia-endocarditis/native-valve-ie/streptococcal-native-valve-ie-viridans-group-s-g/ceftriaxone-2",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"native-valve-ie",subcategoryName:"Native Valve Infective Endocarditis",line:"Streptococcal Native Valve IE (Viridans group, S. gallolyticus)",regimen:"Ceftriaxone 2g IV once daily × 4 weeks",notes:"Equivalent efficacy to penicillin G. MAJOR ADVANTAGE: once-daily dosing makes it the preferred agent for OPAT. Can combine with gentamicin for 2-week short course (same criteria as penicillin). S. gallolyticus (formerly S. bovis) endocarditis: ALWAYS get colonoscopy — strong association with colorectal neoplasia (adenomas and carcinomas).",drug:"ceftriaxone",monographId:"ceftriaxone"},{id:"bacteremia-endocarditis/native-valve-ie/streptococcal-native-valve-ie-viridans-group-s-g/penicillin-strep-ie-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"native-valve-ie",subcategoryName:"Native Valve Infective Endocarditis",line:"Streptococcal Native Valve IE (Viridans group, S. gallolyticus)",regimen:"Penicillin G 12-18 million units/day IV continuous or divided q4h × 4 weeks",notes:"For penicillin-susceptible strains (MIC ≤0.12). Can shorten to 2 weeks if combined with gentamicin 3mg/kg/day IV divided q8h (2-week short-course regimen — AHA endorsed for uncomplicated native valve IE with penicillin-susceptible Streptococci in patients with normal renal function).",drug:"penicillin-strep-ie"},{id:"bacteremia-endocarditis/native-valve-ie/surgical-indications-refer-to-ct-surgery/surgery-indications-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"native-valve-ie",subcategoryName:"Native Valve Infective Endocarditis",line:"Surgical Indications (Refer to CT Surgery)",regimen:"Early surgical consultation for ALL left-sided IE",notes:"CLASS I (STRONG) indications for surgery: (1) Heart failure due to valve dysfunction (most common surgical indication), (2) Valve dehiscence/perforation/fistula, (3) Perivalvular abscess/pseudoaneurysm, (4) Persistent bacteremia >5-7 days despite appropriate therapy and source control, (5) Recurrent emboli despite appropriate antibiotics (especially with persistent vegetations >10mm), (6) Fungal IE (almost always requires surgery). CLASS IIa indications: large mobile vegetations >10mm (particularly with prior embolic event), early IE caused by highly virulent organisms (S. aureus, fungi) with valve destruction. Timing: emergency (within 24h) for refractory pulmonary edema or cardiogenic shock; urgent (within days) for uncontrolled infection or high embolic risk; elective (within 1-2 weeks) for progressive valve dysfunction.",drug:"surgery-indications"},{id:"bacteremia-endocarditis/opat-considerations/monitoring-on-opat/opat-monitoring-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"opat-considerations",subcategoryName:"OPAT — Outpatient Parenteral Antibiotic Therapy",line:"Monitoring on OPAT",regimen:"Weekly labs: CBC, CMP, CRP. Drug-specific: vancomycin AUC, aminoglycoside levels, CPK (daptomycin), LFTs (ceftriaxone, rifampin)",notes:"Standard OPAT monitoring: CBC with differential (neutropenia from prolonged beta-lactams), BMP (renal function), hepatic panel, CRP trending (inflammatory marker response). Drug-specific monitoring is essential. Vancomycin OPAT requires AUC-guided dosing — coordinate with pharmacy for levels and adjustments. Weekly clinical assessment by nurse or physician for line complications, drug adverse effects, and clinical response. PICC line care: dressing changes q7 days, flush per protocol, monitor for infection/thrombosis.",drug:"opat-monitoring"},{id:"bacteremia-endocarditis/opat-considerations/opat-friendly-agents-dosing-frequency-matters/cefazolin-2",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"opat-considerations",subcategoryName:"OPAT — Outpatient Parenteral Antibiotic Therapy",line:"OPAT-Friendly Agents — Dosing Frequency Matters",regimen:"Cefazolin 2g IV q8h (or q12h with probenecid in select cases)",notes:"Workhorse for MSSA infections (bacteremia, endocarditis, osteomyelitis). Q8h dosing is manageable with elastomeric pump (24h pump refilled daily by home health). The probenecid trick (1g PO BID) extends half-life for potential q12h dosing — used at some OPAT programs, limited evidence.",drug:"cefazolin",monographId:"cefazolin"},{id:"bacteremia-endocarditis/opat-considerations/opat-friendly-agents-dosing-frequency-matters/ceftriaxone-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"opat-considerations",subcategoryName:"OPAT — Outpatient Parenteral Antibiotic Therapy",line:"OPAT-Friendly Agents — Dosing Frequency Matters",regimen:"Ceftriaxone 2g IV once daily",notes:"THE ideal OPAT antibiotic — once-daily dosing, stable in elastomeric pump, broad spectrum, well-tolerated. First-line for Streptococcal IE, GN bacteremia step-down, many osteomyelitis regimens. Biliary sludging/pseudolithiasis risk with prolonged use — monitor LFTs, warn patients about RUQ pain.",drug:"ceftriaxone",monographId:"ceftriaxone"},{id:"bacteremia-endocarditis/opat-considerations/opat-friendly-agents-dosing-frequency-matters/daptomycin-3",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"opat-considerations",subcategoryName:"OPAT — Outpatient Parenteral Antibiotic Therapy",line:"OPAT-Friendly Agents — Dosing Frequency Matters",regimen:"Daptomycin 6-10 mg/kg IV once daily",notes:"Excellent OPAT agent for MRSA/VRE: once-daily dosing, no therapeutic drug monitoring needed (just weekly CPK), minimal drug interactions. Gravity infusion over 30 min or IV push over 2 min (push approved for doses ≤500mg). Cost is the main limitation.",drug:"daptomycin",monographId:"daptomycin"},{id:"bacteremia-endocarditis/opat-considerations/opat-friendly-agents-dosing-frequency-matters/ertapenem-4",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"opat-considerations",subcategoryName:"OPAT — Outpatient Parenteral Antibiotic Therapy",line:"OPAT-Friendly Agents — Dosing Frequency Matters",regimen:"Ertapenem 1g IV once daily",notes:"Once-daily carbapenem for ESBL infections, complex polymicrobial infections (including anaerobes). Does NOT cover Pseudomonas or Acinetobacter. Ideal for OPAT when broader coverage is needed. Seizure risk (lower than other carbapenems but still present, especially in renal impairment).",drug:"ertapenem",monographId:"ertapenem"},{id:"bacteremia-endocarditis/opat-considerations/patient-selection-criteria/opat-selection-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"opat-considerations",subcategoryName:"OPAT — Outpatient Parenteral Antibiotic Therapy",line:"Patient Selection Criteria",regimen:"Clinical stability + reliable access + ability to recognize complications",notes:"Ideal OPAT candidates: clinically stable (afebrile ≥48h, improving), reliable IV access (PICC or midline), able to manage or have caregiver for infusion equipment, have reliable follow-up with ID/pharmacy, can recognize and report complications (fever, line issues, drug reactions). Contraindications to OPAT: active IDU (high line misuse risk — consider alternatives like daily infusion center), unstable housing, inability to comply with monitoring, ongoing hemodynamic instability. POET trial oral step-down may eliminate OPAT need for selected IE patients.",drug:"opat-selection"},{id:"bacteremia-endocarditis/prosthetic-valve-ie/empiric-early-pve-12-months-post-surgery/vanc-gent-rifampin-early-pve-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"prosthetic-valve-ie",subcategoryName:"Prosthetic Valve Endocarditis",line:"Empiric — Early PVE (<12 months post-surgery)",regimen:"Vancomycin IV + Gentamicin 1mg/kg IV q8h + Rifampin 300-450mg PO q8h",notes:"Broad coverage for healthcare-associated organisms: Staphylococci (including MRSA and CoNS), Enterococci, gram-negatives. Rifampin is included for biofilm-active coverage (prosthetic material). Narrow based on culture results. Gentamicin for synergy — use for first 2 weeks only, then reassess based on pathogen.",drug:"vanc-gent-rifampin-early-pve"},{id:"bacteremia-endocarditis/prosthetic-valve-ie/empiric-late-pve-12-months-post-surgery/vanc-ceftriaxone-late-pve-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"prosthetic-valve-ie",subcategoryName:"Prosthetic Valve Endocarditis",line:"Empiric — Late PVE (>12 months post-surgery)",regimen:"Vancomycin IV + Ceftriaxone 2g IV q12h",notes:"Similar coverage to native valve empiric regimen. Late PVE organisms resemble native valve IE (Streptococci, Staphylococci, Enterococci). Add rifampin once Staphylococcal PVE is confirmed. Narrow based on cultures.",drug:"vanc-ceftriaxone-late-pve"},{id:"bacteremia-endocarditis/prosthetic-valve-ie/staphylococcal-pve-directed-therapy/mssa-pve-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"prosthetic-valve-ie",subcategoryName:"Prosthetic Valve Endocarditis",line:"Staphylococcal PVE (Directed Therapy)",regimen:"Nafcillin/Cefazolin + Rifampin 300-450mg PO q8h × 6 weeks + Gentamicin × first 2 weeks",notes:"MSSA PVE: beta-lactam backbone + rifampin for biofilm + gentamicin for early synergistic killing. Rifampin is ESSENTIAL for prosthetic valve infections — it is the only commonly used antibiotic that penetrates and kills within biofilm. NEVER use rifampin as monotherapy (rapid resistance). Always use with a companion drug that has good activity against the organism.",drug:"mssa-pve"},{id:"bacteremia-endocarditis/prosthetic-valve-ie/staphylococcal-pve-directed-therapy/mrsa-pve-2",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"prosthetic-valve-ie",subcategoryName:"Prosthetic Valve Endocarditis",line:"Staphylococcal PVE (Directed Therapy)",regimen:"Vancomycin IV (AUC-guided) + Rifampin 300-450mg PO q8h × 6 weeks + Gentamicin × first 2 weeks",notes:"MRSA PVE: vancomycin + rifampin + gentamicin. This is the ONE scenario where rifampin IS recommended in S. aureus infection (prosthetic material — unlike native valve SAB per ARREST trial). Duration: minimum 6 weeks from first negative blood culture. Higher surgical threshold — but surgery still indicated for valve dysfunction, abscess, persistent bacteremia, recurrent emboli.",drug:"mrsa-pve"},{id:"bacteremia-endocarditis/prosthetic-valve-ie/surgical-indications-pve-specific/surgery-pve-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"prosthetic-valve-ie",subcategoryName:"Prosthetic Valve Endocarditis",line:"Surgical Indications — PVE Specific",regimen:"Lower threshold for surgery than native valve IE",notes:"Surgery is indicated for: valve dehiscence, perivalvular abscess, new paravalvular regurgitation, heart failure from prosthetic dysfunction, persistent bacteremia despite appropriate therapy, relapsing PVE, fungal PVE. Early PVE (especially Staphylococcal) has higher surgical rates (>50%). The endocarditis team (ID, CT surgery, cardiology) should evaluate ALL PVE patients for surgical candidacy.",drug:"surgery-pve"},{id:"bacteremia-endocarditis/sab-workup/complicated-vs-uncomplicated-sab-duration-decisi/uncomplicated-sab-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"sab-workup",subcategoryName:"S. aureus Bacteremia — Workup & Risk Stratification",line:"Complicated vs. Uncomplicated SAB — Duration Decision",regimen:"14 days IV therapy from first negative blood culture",notes:"ALL of the following must be met for uncomplicated SAB: (1) Follow-up blood cultures negative within 72h, (2) No endocarditis on TTE/TEE, (3) No prosthetic valves or intracardiac devices, (4) No metastatic infection (no osteomyelitis, septic arthritis, epidural abscess, septic emboli), (5) Removable source identified AND removed (e.g., line-related with line pulled). If ANY criterion is NOT met → complicated SAB.",drug:"uncomplicated-sab"},{id:"bacteremia-endocarditis/sab-workup/complicated-vs-uncomplicated-sab-duration-decisi/complicated-sab-2",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"sab-workup",subcategoryName:"S. aureus Bacteremia — Workup & Risk Stratification",line:"Complicated vs. Uncomplicated SAB — Duration Decision",regimen:"4-6 weeks IV therapy from first negative blood culture",notes:"Complicated SAB = endocarditis, metastatic infection, persistent bacteremia >72h, no removable source, prosthetic material, or failure to meet all uncomplicated criteria. Duration: 4 weeks for native valve IE, 6 weeks for prosthetic valve IE. Some metastatic foci (e.g., vertebral osteomyelitis) may warrant even longer therapy. ORAL STEP-DOWN: consider per POET trial criteria for selected patients after ≥10 days IV + clinical stability.",drug:"complicated-sab"},{id:"bacteremia-endocarditis/sab-workup/empiric-pending-susceptibilities/daptomycin-2",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"sab-workup",subcategoryName:"S. aureus Bacteremia — Workup & Risk Stratification",line:"Empiric — Pending Susceptibilities",regimen:"Daptomycin 6-10 mg/kg IV once daily",notes:"Alternative empiric agent when vancomycin cannot be used (allergy, intolerance, renal toxicity). Use ≥8 mg/kg for suspected endocarditis or complicated infections. Rapidly bactericidal. CONTRAINDICATED in pneumonia (surfactant inactivation). If MSSA returns, still de-escalate to beta-lactam.",drug:"daptomycin",monographId:"daptomycin",evidence:"B-II",evidenceSource:"AHA 2015 IE Guideline",evidenceSourceIds:["aha-2015-ie"]},{id:"bacteremia-endocarditis/sab-workup/empiric-pending-susceptibilities/vancomycin-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"sab-workup",subcategoryName:"S. aureus Bacteremia — Workup & Risk Stratification",line:"Empiric — Pending Susceptibilities",regimen:"Vancomycin IV (AUC/MIC target 400-600)",notes:"Empiric first-line for SAB until MSSA vs MRSA is determined. AUC-guided dosing is now the standard (2020 consensus) — replaces trough-based dosing. Typical loading dose: 25-30 mg/kg (actual body weight), then maintenance guided by AUC. CRITICAL: once susceptibilities return, de-escalate MSSA to cefazolin/nafcillin immediately — vancomycin is INFERIOR to beta-lactams for MSSA (slower bacteremia clearance, higher mortality in some studies).",drug:"vancomycin",monographId:"vancomycin",evidence:"A-I",evidenceSource:"AHA 2015 IE Guideline",evidenceSourceIds:["aha-2015-ie"]},{id:"bacteremia-endocarditis/sab-workup/mrsa-definitive-therapy/daptomycin-2",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"sab-workup",subcategoryName:"S. aureus Bacteremia — Workup & Risk Stratification",line:"MRSA Definitive Therapy",regimen:"Daptomycin 8-10 mg/kg IV once daily",notes:"Preferred alternative to vancomycin for MRSA bacteremia when: vancomycin MIC ≥2, vancomycin intolerance/nephrotoxicity, persistent bacteremia on vancomycin >3-5 days. Dose at ≥8 mg/kg for bacteremia (6 mg/kg is the IE/bacteremia approved dose but many experts go higher). Monitor CPK weekly. If daptomycin MIC ≥2-4, consider ceftaroline or salvage regimens.",drug:"daptomycin",monographId:"daptomycin"},{id:"bacteremia-endocarditis/sab-workup/mrsa-definitive-therapy/vancomycin-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"sab-workup",subcategoryName:"S. aureus Bacteremia — Workup & Risk Stratification",line:"MRSA Definitive Therapy",regimen:"Vancomycin IV (AUC/MIC 400-600)",notes:"Standard of care for MRSA bacteremia. AUC-guided dosing with Bayesian software is preferred. If vancomycin MIC ≥2 by broth microdilution (≥2 by E-test is less reliable), consider switching to daptomycin — treatment failure risk increases with higher MICs (MIC creep). Do NOT add rifampicin routinely (ARREST trial — no benefit, added toxicity). Duration: 14 days minimum for uncomplicated, 4-6 weeks for IE/complicated.",drug:"vancomycin",monographId:"vancomycin"},{id:"bacteremia-endocarditis/sab-workup/mssa-definitive-therapy/cefazolin-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"sab-workup",subcategoryName:"S. aureus Bacteremia — Workup & Risk Stratification",line:"MSSA Definitive Therapy",regimen:"Cefazolin 2g IV q8h",notes:"PREFERRED agent for MSSA bacteremia and MSSA IE (native valve). Multiple observational studies and meta-analyses show non-inferiority or superiority to nafcillin/oxacillin with fewer adverse effects (less nephrotoxicity, less hepatotoxicity, less phlebitis). Q8h dosing is practical for OPAT. Duration: 14 days for uncomplicated SAB, 4-6 weeks for IE or complicated SAB.",drug:"cefazolin",monographId:"cefazolin",evidence:"A-I",evidenceSource:"AHA 2015 IE Guideline",evidenceSourceIds:["aha-2015-ie"]},{id:"bacteremia-endocarditis/sab-workup/mssa-definitive-therapy/nafcillin-oxacillin-2",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"sab-workup",subcategoryName:"S. aureus Bacteremia — Workup & Risk Stratification",line:"MSSA Definitive Therapy",regimen:"Nafcillin or Oxacillin 2g IV q4h",notes:"Historical gold standard for MSSA. Still used by some ID physicians who prefer the rapid bactericidal activity and high-dose continuous infusion data. Disadvantages: q4h dosing (impractical for OPAT), significant phlebitis, oxacillin hepatotoxicity, nafcillin-associated interstitial nephritis. Most centers have transitioned to cefazolin. Reserve for cefazolin allergy (severe cephalosporin allergy — rare) or treatment failure on cefazolin (extremely rare).",drug:"nafcillin-oxacillin",evidence:"A-I",evidenceSource:"AHA 2015 IE Guideline",evidenceSourceIds:["aha-2015-ie"]},{id:"bone-joint/diabetic-foot-osteo/medical-management-no-bone-resection/medical-osteo-1",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"diabetic-foot-osteo",subcategoryName:"Diabetic Foot Osteomyelitis",line:"Medical Management (No Bone Resection)",regimen:"Pathogen-directed therapy × 4-6 weeks (based on BONE culture, not wound swab)",notes:"If treating medically without surgery: 4-6 weeks of antibiotics directed by bone biopsy culture. OVIVA supports oral step-down with appropriate agents. CRP and clinical response guide adequacy. CRITICAL: surface wound swab cultures do NOT guide osteomyelitis therapy — you must have bone culture. If no bone biopsy is obtainable, empiric coverage of the most likely pathogens (S. aureus ± GN based on clinical context).",drug:"medical-osteo"},{id:"bone-joint/diabetic-foot-osteo/post-surgical-resection-complete-bone-removal/post-resection-1",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"diabetic-foot-osteo",subcategoryName:"Diabetic Foot Osteomyelitis",line:"Post-Surgical Resection (Complete Bone Removal)",regimen:"1-2 weeks of antibiotics post-resection if clean margins",notes:"If infected bone is COMPLETELY resected with confirmed clean margins on histology: antibiotics can be shortened dramatically to 1-2 weeks (some experts use 5-7 days post-resection). This is a paradigm shift from 6-week courses — adequate surgery can substitute for prolonged antibiotics. The pathology report confirming clean margins is essential.",drug:"post-resection"},{id:"bone-joint/prosthetic-joint-infection/antibiotic-therapy-for-dair-staphylococcal-pji/cefazolin-rifampin-dair-1",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"prosthetic-joint-infection",subcategoryName:"Prosthetic Joint Infection (PJI)",line:"Antibiotic Therapy for DAIR (Staphylococcal PJI)",regimen:"Cefazolin 2g IV q8h + Rifampin 300-450mg PO q12h × 2-6 weeks IV, then oral companion + rifampin to complete 3 months (hip) or 6 months (knee)",notes:"For MSSA PJI treated with DAIR. Rifampin is ESSENTIAL — it penetrates biofilm and kills sessile organisms on prosthetic material. NEVER use rifampin alone (resistance in 1-2 days). Start rifampin only AFTER initial debridement and once bacteremia has cleared (rifampin resistance can emerge if used during active bacteremia). Oral companion drugs for rifampin: levofloxacin 500mg daily (preferred for MSSA), TMP-SMX DS 1 tab BID, or doxycycline 100mg BID.",drug:"cefazolin-rifampin-dair"},{id:"bone-joint/prosthetic-joint-infection/antibiotic-therapy-for-dair-staphylococcal-pji/vanc-rifampin-dair-2",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"prosthetic-joint-infection",subcategoryName:"Prosthetic Joint Infection (PJI)",line:"Antibiotic Therapy for DAIR (Staphylococcal PJI)",regimen:"Vancomycin IV (AUC-guided) + Rifampin 300-450mg PO q12h × 2-6 weeks IV, then oral companion + rifampin to complete 3-6 months",notes:"For MRSA PJI treated with DAIR. Same rifampin principles. Oral companions for MRSA: TMP-SMX DS 1 tab BID + rifampin (most common), linezolid 600mg BID + rifampin (limit linezolid duration — myelosuppression), or doxycycline 100mg BID + rifampin (if susceptible). Total duration: 3 months (hip) or 6 months (knee).",drug:"vanc-rifampin-dair"},{id:"bone-joint/prosthetic-joint-infection/antibiotic-therapy-for-two-stage-exchange/two-stage-abx-1",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"prosthetic-joint-infection",subcategoryName:"Prosthetic Joint Infection (PJI)",line:"Antibiotic Therapy for Two-Stage Exchange",regimen:"Pathogen-directed IV/oral therapy × 4-6 weeks between stages",notes:"After stage 1 (explant + debridement): pathogen-directed systemic antibiotics for 4-6 weeks. Rifampin is NOT needed during the spacer phase (no retained implant — no biofilm target). After completion of antibiotics: 2-4 week antibiotic-free holiday. Check CRP, aspirate joint if feasible. If markers normalizing and aspirate negative → proceed to stage 2 (reimplant). After stage 2: some protocols use perioperative prophylaxis only; others use 4-6 weeks of pathogen-directed therapy post-reimplantation. Practice varies.",drug:"two-stage-abx"},{id:"bone-joint/prosthetic-joint-infection/surgical-strategy-the-most-important-decision/dair-1",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"prosthetic-joint-infection",subcategoryName:"Prosthetic Joint Infection (PJI)",line:"Surgical Strategy — The Most Important Decision",regimen:"DAIR: Debridement, Antibiotics, and Implant Retention",notes:"Criteria for DAIR: (1) Early PJI (<30 days post-op) OR acute hematogenous PJI with symptoms <3 weeks, (2) Stable, well-fixed implant, (3) Intact soft tissue envelope, (4) Susceptible organism (ideally Staphylococcus amenable to rifampin), (5) NOT a highly virulent or resistant organism. DAIR success: 55-75% (organism-dependent — better for Streptococci, worse for MRSA and resistant GN). If ANY DAIR criterion is not met → exchange arthroplasty.",drug:"dair"},{id:"bone-joint/prosthetic-joint-infection/surgical-strategy-the-most-important-decision/one-stage-3",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"prosthetic-joint-infection",subcategoryName:"Prosthetic Joint Infection (PJI)",line:"Surgical Strategy — The Most Important Decision",regimen:"One-Stage Exchange: Explant + immediate reimplantation in single surgery",notes:"Gaining popularity in selected cases: healthy patient, susceptible organism (especially Streptococci), no sinus tract, healthy soft tissues. Advantage: single surgery, faster functional recovery. The INFORM trial (2022) showed non-inferiority of one-stage vs. two-stage for selected hip and knee PJI. Success: 85-95% in appropriate candidates.",drug:"one-stage"},{id:"bone-joint/prosthetic-joint-infection/surgical-strategy-the-most-important-decision/two-stage-2",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"prosthetic-joint-infection",subcategoryName:"Prosthetic Joint Infection (PJI)",line:"Surgical Strategy — The Most Important Decision",regimen:"Two-Stage Exchange: Explant → antibiotic spacer → 6-8 weeks antibiotics → reimplantation",notes:"Gold standard for chronic PJI, PJI failing DAIR, resistant organisms, compromised soft tissues. Stage 1: remove all prosthetic components and cement, aggressive debridement, place antibiotic-loaded cement spacer. Pathogen-directed systemic antibiotics × 6-8 weeks (some use 4-6 weeks after spacer). Stage 2: reimplant after antibiotic holiday + negative inflammatory markers ± re-aspiration. Success: 85-95%.",drug:"two-stage"},{id:"bone-joint/septic-arthritis/empiric-pending-cultures/ceftriaxone-2",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"septic-arthritis",subcategoryName:"Septic Arthritis (Native Joint)",line:"Empiric — Pending Cultures",regimen:"Ceftriaxone 2g IV daily (add to vancomycin if GN risk)",notes:"For gram-negative coverage in high-risk patients. Also first-line empiric in suspected gonococcal arthritis (sexually active young adult with migratory polyarthralgia → monoarthritis + skin lesions). NAAT for GC/CT on urogenital, rectal, and pharyngeal sites.",drug:"ceftriaxone",monographId:"ceftriaxone"},{id:"bone-joint/septic-arthritis/empiric-pending-cultures/vancomycin-1",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"septic-arthritis",subcategoryName:"Septic Arthritis (Native Joint)",line:"Empiric — Pending Cultures",regimen:"Vancomycin IV (AUC-guided)",notes:"First-line empiric for native joint septic arthritis. Covers MRSA and MSSA (though inferior to beta-lactams for MSSA — will de-escalate once cultures return). Most septic arthritis is gram-positive (S. aureus 40-60%, Streptococci 15-20%). Add gram-negative coverage (ceftriaxone) if: immunocompromised, IDU, healthcare-associated, GI/GU source suspected.",drug:"vancomycin",monographId:"vancomycin"},{id:"bone-joint/septic-arthritis/pathogen-directed-therapy/cefazolin-1",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"septic-arthritis",subcategoryName:"Septic Arthritis (Native Joint)",line:"Pathogen-Directed Therapy",regimen:"Cefazolin 2g IV q8h × 3-4 weeks (MSSA)",notes:"De-escalate from vancomycin upon MSSA confirmation. Duration: 3-4 weeks for native joint septic arthritis (shorter than osteomyelitis if no bone involvement). Oral step-down per OVIVA: consider after 1-2 weeks IV if clinically responding, using bone-penetrating oral agents.",drug:"cefazolin",monographId:"cefazolin"},{id:"bone-joint/septic-arthritis/pathogen-directed-therapy/ceftriaxone-gc-2",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"septic-arthritis",subcategoryName:"Septic Arthritis (Native Joint)",line:"Pathogen-Directed Therapy",regimen:"Ceftriaxone 1g IV/IM daily × 7-14 days (gonococcal)",notes:"Gonococcal arthritis: excellent prognosis. Ceftriaxone 1g IV daily until clinical improvement (usually 24-48h), then oral step-down to cefixime or ciprofloxacin (if susceptible) to complete 7-14 days. Treat concurrent chlamydia empirically (azithromycin 1g or doxycycline 100mg BID × 7d).",drug:"ceftriaxone-gc"},{id:"bone-joint/septic-arthritis/surgical-drainage/drainage-native-1",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"septic-arthritis",subcategoryName:"Septic Arthritis (Native Joint)",line:"Surgical Drainage",regimen:"Serial arthrocentesis or arthroscopic lavage",notes:"Purulent joints must be drained. Options: (1) Serial bedside arthrocentesis (daily or as needed until effusion resolves — works well for knee), (2) Arthroscopic lavage/debridement (preferred for hip, shoulder, and joints difficult to aspirate adequately), (3) Open arthrotomy (reserved for failed arthroscopic drainage, hip joint in some centers, or when debridement of necrotic tissue is needed). HIP SEPTIC ARTHRITIS: usually requires surgical drainage (deep joint, difficult to aspirate adequately at bedside).",drug:"drainage-native"},{id:"bone-joint/vertebral-osteomyelitis/duration-monitoring/duration-osteo-1",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"vertebral-osteomyelitis",subcategoryName:"Vertebral Osteomyelitis (Native Spine)",line:"Duration & Monitoring",regimen:"6 weeks total (parenteral + oral per OVIVA)",notes:"IDSA 2015: 6 weeks of parenteral (or equivalent oral per OVIVA) therapy. Start counting from day 1 of appropriate therapy after surgical debridement (if performed). CRP should be trended q1-2 weeks — a decreasing CRP confirms response. If CRP is not declining by week 2-3: re-evaluate (inadequate source control? wrong pathogen? abscess not drained? wrong antibiotic?). Repeat MRI only if clinical concern for worsening (NOT routine — MRI findings lag behind clinical improvement by weeks to months).",drug:"duration-osteo"},{id:"bone-joint/vertebral-osteomyelitis/empiric-when-antibiotics-cannot-wait/vancomycin-1",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"vertebral-osteomyelitis",subcategoryName:"Vertebral Osteomyelitis (Native Spine)",line:"Empiric — When Antibiotics Cannot Wait",regimen:"Vancomycin IV (AUC-guided) + Ceftriaxone 2g IV daily",notes:"Covers MRSA + MSSA + Streptococci + most Enterobacterales. This is the standard empiric combination when you must start before cultures. Vancomycin for MRSA, ceftriaxone for gram-negatives and Streptococci. If cultures return MSSA, de-escalate to cefazolin immediately. If epidural abscess with concern for Pseudomonas (post-procedural, healthcare-associated): substitute cefepime for ceftriaxone.",drug:"vancomycin",monographId:"vancomycin"},{id:"bone-joint/vertebral-osteomyelitis/pathogen-directed-therapy-after-culture-results/cefazolin-1",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"vertebral-osteomyelitis",subcategoryName:"Vertebral Osteomyelitis (Native Spine)",line:"Pathogen-Directed Therapy (After Culture Results)",regimen:"Cefazolin 2g IV q8h × 6 weeks (MSSA)",notes:"PREFERRED for MSSA vertebral osteomyelitis. Transition to oral step-down after initial IV period per OVIVA data: high-dose oral agents with bone penetration (e.g., levofloxacin 750mg daily + rifampin 300-450mg BID for Staph, or TMP-SMX DS 2 tabs BID for MSSA). CRP trending guides response.",drug:"cefazolin",monographId:"cefazolin"},{id:"bone-joint/vertebral-osteomyelitis/pathogen-directed-therapy-after-culture-results/ceftriaxone-3",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"vertebral-osteomyelitis",subcategoryName:"Vertebral Osteomyelitis (Native Spine)",line:"Pathogen-Directed Therapy (After Culture Results)",regimen:"Ceftriaxone 2g IV daily × 6 weeks (Streptococci, susceptible GN)",notes:"Once-daily dosing makes this ideal for OPAT. Excellent for Streptococcal vertebral osteomyelitis and susceptible gram-negative infections. Oral step-down: levofloxacin 750mg daily (if susceptible) or amoxicillin 1g TID (for Streptococci).",drug:"ceftriaxone",monographId:"ceftriaxone"},{id:"bone-joint/vertebral-osteomyelitis/pathogen-directed-therapy-after-culture-results/vancomycin-2",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"vertebral-osteomyelitis",subcategoryName:"Vertebral Osteomyelitis (Native Spine)",line:"Pathogen-Directed Therapy (After Culture Results)",regimen:"Vancomycin IV (AUC-guided) × 6 weeks (MRSA)",notes:"Standard for MRSA vertebral osteomyelitis. AUC/MIC 400-600. Monitor renal function closely over 6-week course. Oral step-down options for MRSA: TMP-SMX DS 2 tabs BID, linezolid 600mg BID (monitor for myelosuppression — limit to 4-6 weeks if possible), or doxycycline 100mg BID (if susceptible). Some ID physicians use daptomycin as the initial IV agent then step down.",drug:"vancomycin",monographId:"vancomycin"},{id:"bone-joint/vertebral-osteomyelitis/pre-biopsy-hold-antibiotics-if-possible/hold-antibiotics-1",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"vertebral-osteomyelitis",subcategoryName:"Vertebral Osteomyelitis (Native Spine)",line:"Pre-Biopsy — Hold Antibiotics if Possible",regimen:"Defer antibiotics until biopsy cultures obtained (if clinically stable)",notes:"THE MOST IMPORTANT DECISION IN VERTEBRAL OSTEOMYELITIS: If the patient is hemodynamically stable without sepsis or progressive neurologic deficits, HOLD antibiotics until CT-guided biopsy is performed. The 24-48h delay to obtain cultures before starting antibiotics is worth it — it changes the entire course of therapy. A biopsy that identifies MSSA means 6 weeks of cefazolin. Without a pathogen, you're stuck guessing with broad-spectrum empiric therapy. Exception: unstable patient, sepsis, or neurologic emergency — start empiric antibiotics immediately.",drug:"hold-antibiotics"},{id:"c-difficile/special-populations/cdi-in-ibd-patients/ibd-cdi-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"special-populations",subcategoryName:"CDI in Special Populations",line:"CDI in IBD Patients",regimen:"Standard CDI therapy (fidaxomicin preferred) + evaluate immunosuppression",notes:"CDI and IBD have a bidirectional relationship: CDI triggers IBD flares, and IBD treatment (immunosuppression) increases CDI risk. KEY CHALLENGE: Distinguishing CDI from IBD flare — test for CDI in ANY IBD patient with worsening diarrhea, even if the clinical picture looks like a typical flare. Treatment: standard CDI antibiotics. Do NOT escalate immunosuppression (steroids, biologics) for presumed IBD flare until CDI is ruled out. If CDI is confirmed: treat CDI first, then reassess IBD activity. Some guidelines suggest NOT de-escalating immunosuppression during active CDI (to prevent IBD flare), but this is controversial — individualize.",drug:"ibd-cdi"},{id:"c-difficile/special-populations/cdi-in-immunocompromised-patients/immunocompromised-cdi-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"special-populations",subcategoryName:"CDI in Special Populations",line:"CDI in Immunocompromised Patients",regimen:"Fidaxomicin (preferred) + bezlotoxumab (strongly consider) + close monitoring for severity progression",notes:"Immunocompromised patients (solid organ transplant, hematologic malignancy, chemotherapy, chronic steroids) have higher CDI incidence, severity, recurrence, and mortality. Low threshold for bezlotoxumab (MODIFY trials showed significant benefit in this subgroup). Close monitoring — immunosuppressed patients may not mount typical WBC response, so traditional severity markers may be unreliable. FMT: historically cautious in severely immunocompromised (theoretical risk of donor-derived bacteremia through disrupted mucosa), but safety data is accumulating. Consult ID and GI.",drug:"immunocompromised-cdi"},{id:"c-difficile/special-populations/stewardship-cdi-prevention-strategies/prevention-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"special-populations",subcategoryName:"CDI in Special Populations",line:"Stewardship — CDI Prevention Strategies",regimen:"Antibiotic stewardship + contact precautions + environmental cleaning",notes:"ANTIBIOTIC STEWARDSHIP IS THE #1 CDI PREVENTION STRATEGY: Every unnecessary antibiotic day increases CDI risk. High-impact interventions: restrict fluoroquinolones (strongest CDI association), promote narrow-spectrum agents, enforce automatic stop dates, prospective audit and feedback. INFECTION PREVENTION: Contact precautions (gown and gloves) for CDI patients. Soap and water hand hygiene (alcohol-based sanitizer does NOT kill C. diff spores). Terminal room cleaning with sporicidal agents (bleach-based products, UV light). PHARMACIST ROLE: Review all antibiotics on CDI patients for de-escalation opportunities, ensure PPI appropriateness, educate on hand hygiene.",drug:"prevention"},{id:"c-difficile/first-recurrence/adjunctive-recurrence-prevention/bezlotoxumab-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"first-recurrence",subcategoryName:"First Recurrence",line:"Adjunctive — Recurrence Prevention",regimen:"Bezlotoxumab 10 mg/kg IV × 1 dose (during CDI antibiotic treatment)",notes:"Strongly consider for first recurrence — the MODIFY trials enrolled patients with recurrent CDI and showed benefit. Give as single infusion during the CDI treatment course. Particularly indicated if: age ≥65, immunocompromised, severe CDI, CDI while on concurrent antibiotics, NAP1/027 strain. NNT ~8-10. Cost ~$4,500 but may be cost-effective if it prevents hospitalization for subsequent recurrence.",drug:"bezlotoxumab",monographId:"bezlotoxumab"},{id:"c-difficile/first-recurrence/alternative-first-recurrence/vancomycin-oral-2",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"first-recurrence",subcategoryName:"First Recurrence",line:"Alternative — First Recurrence",regimen:"Vancomycin 125mg PO QID × 10 days (if initial episode treated with metronidazole)",notes:"If the initial episode was treated with metronidazole (which it shouldn't have been per 2021 guidelines, but sometimes is), a standard vancomycin course is appropriate for first recurrence. This effectively 'upgrades' therapy.",drug:"vancomycin-oral",monographId:"vancomycin-oral"},{id:"c-difficile/first-recurrence/alternative-first-recurrence/vancomycin-taper-pulse-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"first-recurrence",subcategoryName:"First Recurrence",line:"Alternative — First Recurrence",regimen:"Vancomycin taper-and-pulse: 125mg QID × 10-14d → 125mg BID × 7d → 125mg daily × 7d → 125mg q2-3d × 2-4 weeks",notes:"If fidaxomicin is unavailable or cost-prohibitive. The taper-and-pulse regimen reduces recurrence to ~25-35% (vs ~45-65% with standard 10-day re-treatment). The pulse phase targets C. diff spores that germinate after cessation of continuous therapy. Mechanism: spores are resistant to antibiotics, but newly germinated vegetative cells are susceptible. By pulsing antibiotics, you catch newly germinated bacteria before they can produce toxin.",drug:"vancomycin-taper-pulse"},{id:"c-difficile/first-recurrence/preferred-first-recurrence-idsa-shea-2021/fidaxomicin-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"first-recurrence",subcategoryName:"First Recurrence",line:"Preferred — First Recurrence (IDSA/SHEA 2021)",regimen:"Fidaxomicin 200mg PO BID × 10 days",notes:"STRONGLY preferred for first recurrence (IDSA/SHEA 2021). If the initial episode was treated with vancomycin, switching to fidaxomicin reduces subsequent recurrence by ~50% (EXTEND trial). If the initial episode was treated with fidaxomicin and still recurred, fidaxomicin can be repeated — there is no evidence of diminishing returns. The narrow spectrum preserving protective anaerobes is the key mechanistic advantage.",drug:"fidaxomicin",monographId:"fidaxomicin"},{id:"c-difficile/first-recurrence/preferred-first-recurrence-idsa-shea-2021/fidaxomicin-extended-pulse-2",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"first-recurrence",subcategoryName:"First Recurrence",line:"Preferred — First Recurrence (IDSA/SHEA 2021)",regimen:"Fidaxomicin 200mg PO BID × 5 days, then 200mg PO once daily every other day × 20 days",notes:"Extended-pulsed fidaxomicin (EFP) regimen from the EXTEND-EFP study. Even lower recurrence rates than standard 10-day fidaxomicin (~4% recurrence in some studies). The every-other-day dosing targets newly germinating spores while allowing microbiome recovery on 'off' days. Increasingly used by ID experts for first recurrence. Not yet in formal IDSA guidelines as a first-line recommendation but gaining traction rapidly.",drug:"fidaxomicin-extended-pulse"},{id:"c-difficile/fulminant/fulminant-cdi-standard-medical-therapy/metronidazole-2",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"fulminant",subcategoryName:"Fulminant CDI (Previously 'Severe, Complicated')",line:"Fulminant CDI — Standard Medical Therapy",regimen:"Metronidazole 500mg IV q8h",notes:"ADJUNCTIVE to oral/rectal vancomycin — IV metronidazole reaches colonic tissue via systemic circulation. This is the ONE remaining indication where IV metronidazole adds value in CDI. When the colon is atonic (ileus), oral drugs cannot reliably reach the diseased tissue. IV metronidazole provides a secondary route of drug delivery. Duration: until clinical improvement or colectomy.",drug:"metronidazole",monographId:"metronidazole"},{id:"c-difficile/fulminant/fulminant-cdi-standard-medical-therapy/vancomycin-rectal-3",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"fulminant",subcategoryName:"Fulminant CDI (Previously 'Severe, Complicated')",line:"Fulminant CDI — Standard Medical Therapy",regimen:"Vancomycin 500mg in 100mL NS per rectum q6h (retention enema)",notes:"ADD to oral vancomycin + IV metronidazole when ileus is present. Rectal administration delivers drug directly to the diseased colon, bypassing the ileus-impaired oral route. Technique: 500mg in 100mL NS, administered as a retention enema via rectal tube. Patient in Trendelenburg position to facilitate proximal distribution. LIMITATION: only reaches the distal colon (sigmoid, rectum) — proximal colonic disease may not benefit. This is a temporizing measure while awaiting surgical decision.",drug:"vancomycin-rectal"},{id:"c-difficile/fulminant/fulminant-cdi-standard-medical-therapy/vancomycin-oral-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"fulminant",subcategoryName:"Fulminant CDI (Previously 'Severe, Complicated')",line:"Fulminant CDI — Standard Medical Therapy",regimen:"Vancomycin 500mg PO (or via NG tube) QID",notes:"HIGHER DOSE than standard CDI — 500mg QID (not 125mg). The rationale: in fulminant disease with ileus, drug delivery to the colon may be impaired. Higher oral doses may achieve better colonic concentrations. Administered PO or via nasogastric tube if the patient cannot swallow. Fidaxomicin is NOT well-studied in fulminant CDI — vancomycin is the standard here.",drug:"vancomycin-oral",monographId:"vancomycin-oral"},{id:"c-difficile/fulminant/fulminant-cdi-surgical-options/diverting-ileostomy-2",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"fulminant",subcategoryName:"Fulminant CDI (Previously 'Severe, Complicated')",line:"Fulminant CDI — Surgical Options",regimen:"Diverting loop ileostomy with colonic vancomycin lavage (Neal procedure)",notes:"COLON-SPARING alternative to subtotal colectomy. Technique: laparoscopic loop ileostomy + antegrade vancomycin flushes (500mg in 500mL NS q8h through the ileostomy, draining from a rectal tube). Preserves the colon for potential reversal. Small case series show improved survival compared to historical colectomy data. Increasingly used at centers with surgical expertise. Advantage: avoids permanent ostomy in survivors. Limitation: not all surgical teams have experience with this approach.",drug:"diverting-ileostomy"},{id:"c-difficile/fulminant/fulminant-cdi-surgical-options/colectomy-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"fulminant",subcategoryName:"Fulminant CDI (Previously 'Severe, Complicated')",line:"Fulminant CDI — Surgical Options",regimen:"Subtotal colectomy with end ileostomy",notes:"DEFINITIVE surgical treatment for fulminant CDI. Indications: perforation, megacolon not responding to medical therapy, multi-organ failure despite medical management, WBC >50,000 with clinical deterioration, lactate >5 with rising trend. TIMING IS EVERYTHING — colectomy before vasopressor requirement and organ failure has dramatically better survival (50-60%) than colectomy after shock/MOF (20-30%). This is why surgical consultation must happen EARLY in severe CDI.",drug:"colectomy"},{id:"c-difficile/initial-non-severe/alternative-first-line/vancomycin-oral-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"initial-non-severe",subcategoryName:"Initial Episode — Non-Severe CDI",line:"Alternative — First-Line",regimen:"Vancomycin 125mg PO QID × 10 days",notes:"Standard of care before 2021 guideline update. Still highly effective for initial cure (clinical cure rate ~90%). IDSA/SHEA 2021 made this 'alternative' rather than 'preferred' because of higher recurrence rate compared to fidaxomicin. If fidaxomicin is unavailable or cost-prohibitive, oral vancomycin remains an excellent option. Do NOT increase the dose to 250mg or 500mg for non-severe CDI — no added benefit, only added cost. IV vancomycin does NOT work for CDI (does not reach the colon).",drug:"vancomycin-oral",monographId:"vancomycin-oral"},{id:"c-difficile/initial-non-severe/not-recommended-metronidazole-for-cdi-idsa-shea-/metronidazole-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"initial-non-severe",subcategoryName:"Initial Episode — Non-Severe CDI",line:"Not Recommended — Metronidazole for CDI (IDSA/SHEA 2021)",regimen:"Metronidazole 500mg PO TID × 10 days",notes:"DOWNGRADED in 2017 guidelines, further de-emphasized in 2021. Inferior to vancomycin for clinical cure (especially for severe CDI) and has higher recurrence rates. IDSA/SHEA 2021: metronidazole should ONLY be used when vancomycin and fidaxomicin are unavailable. Some guidelines allow metronidazole for non-severe INITIAL episode only, but this is increasingly seen as suboptimal. The only remaining role for metronidazole in CDI: IV metronidazole as ADJUNCTIVE therapy in fulminant CDI (reaches colonic tissue via systemic circulation when oral drugs cannot reach the colon due to ileus).",drug:"metronidazole",monographId:"metronidazole"},{id:"c-difficile/initial-non-severe/preferred-first-line-idsa-shea-2021/fidaxomicin-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"initial-non-severe",subcategoryName:"Initial Episode — Non-Severe CDI",line:"Preferred — First-Line (IDSA/SHEA 2021)",regimen:"Fidaxomicin 200mg PO BID × 10 days",notes:"IDSA/SHEA 2021 PREFERRED over vancomycin for initial CDI (conditional recommendation based on EXTEND trial data). Advantage: 50% lower recurrence rate compared to vancomycin for non-NAP1 strains. Mechanism of benefit: narrow-spectrum macrolide that kills C. diff while sparing protective anaerobes (Bacteroides). Allows microbiome recovery. LIMITATION: cost (~$3,000-5,000/course vs ~$50-100 for vancomycin). For non-severe initial CDI, both are effective — the fidaxomicin advantage is primarily in reducing RECURRENCE.",drug:"fidaxomicin",monographId:"fidaxomicin",evidence:"A-I",evidenceSource:"IDSA/SHEA 2021",evidenceSourceIds:["idsa-shea-2021-cdi"]},{id:"c-difficile/initial-non-severe/stewardship-antibiotic-optimization/stewardship-cdi-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"initial-non-severe",subcategoryName:"Initial Episode — Non-Severe CDI",line:"Stewardship — Antibiotic Optimization",regimen:"Discontinue or narrow the inciting antibiotic if possible",notes:"THE MOST IMPORTANT INTERVENTION. CDI is a disease of dysbiosis — the inciting antibiotic disrupted the protective microbiome, allowing C. diff to flourish. If the patient is on antibiotics for another infection, narrow the spectrum as much as possible. Discontinue antibiotics entirely if they are no longer needed. If antibiotics must continue: choose lower C. diff risk agents when possible (e.g., doxycycline, TMP-SMX over fluoroquinolones or clindamycin). Continue CDI-directed therapy for the full course even after other antibiotics are stopped.",drug:"stewardship-cdi"},{id:"c-difficile/initial-severe/adjunctive-recurrence-prevention-in-severe-cdi/bezlotoxumab-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"initial-severe",subcategoryName:"Initial Episode — Severe CDI",line:"Adjunctive — Recurrence Prevention in Severe CDI",regimen:"Bezlotoxumab 10 mg/kg IV × 1 dose (during CDI antibiotic treatment)",notes:"Consider bezlotoxumab for severe CDI patients at high recurrence risk: age ≥65, immunocompromised, prior CDI episode, severe CDI (this category), NAP1/027 strain. The MODIFY trials showed ~10% absolute reduction in recurrence. NNT ~8-10. Given as a single infusion during the CDI treatment course. Does NOT treat active CDI — it prevents recurrence by neutralizing toxin B. Cost: ~$4,500 per infusion. CAUTION: heart failure exacerbation reported in patients with underlying CHF — use with caution in decompensated HF.",drug:"bezlotoxumab",monographId:"bezlotoxumab"},{id:"c-difficile/initial-severe/monitoring-severe-cdi/monitoring-severe-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"initial-severe",subcategoryName:"Initial Episode — Severe CDI",line:"Monitoring — Severe CDI",regimen:"Daily labs (CBC, CMP), surgical consult early, CT if clinical deterioration",notes:"Track WBC and creatinine daily. Rising WBC (>25,000 or leukemoid reaction), worsening creatinine, increasing lactate, new ileus, or hemodynamic instability = progression to fulminant CDI → escalate to fulminant protocol immediately. Surgical consultation should be obtained EARLY — colectomy has the best outcomes when performed before vasopressor requirement and organ failure develop.",drug:"monitoring-severe"},{id:"c-difficile/initial-severe/preferred-severe-cdi-idsa-shea-2021/fidaxomicin-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"initial-severe",subcategoryName:"Initial Episode — Severe CDI",line:"Preferred — Severe CDI (IDSA/SHEA 2021)",regimen:"Fidaxomicin 200mg PO BID × 10 days",notes:"IDSA/SHEA 2021 lists fidaxomicin as preferred for severe CDI as well (conditional recommendation). The EXTEND trial included severe CDI patients and fidaxomicin maintained its recurrence advantage. Same dosing as non-severe. If the patient progresses to fulminant despite fidaxomicin, transition to the fulminant CDI protocol.",drug:"fidaxomicin",monographId:"fidaxomicin"},{id:"c-difficile/initial-severe/preferred-severe-cdi-idsa-shea-2021/vancomycin-oral-2",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"initial-severe",subcategoryName:"Initial Episode — Severe CDI",line:"Preferred — Severe CDI (IDSA/SHEA 2021)",regimen:"Vancomycin 125mg PO QID × 10 days",notes:"Alternative first-line for severe CDI. Same dose as non-severe — 125mg QID is sufficient. Clinical cure rates are high (~85-90%). The distinction between 'preferred' (fidaxomicin) and 'alternative' (vancomycin) is driven by recurrence data, not acute cure rates. If fidaxomicin is unavailable, vancomycin is the standard.",drug:"vancomycin-oral",monographId:"vancomycin-oral"},{id:"c-difficile/multiple-recurrences/adjunctive-for-multiple-recurrences/bezlotoxumab-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"multiple-recurrences",subcategoryName:"Multiple Recurrences (≥2nd Recurrence)",line:"Adjunctive for Multiple Recurrences",regimen:"Bezlotoxumab 10 mg/kg IV × 1 (during CDI antibiotic treatment, before FMT)",notes:"Can be used in combination with FMT for multiply recurrent CDI. Give during the antibiotic treatment phase (before FMT). Neutralizes toxin B to reduce recurrence risk while microbiome restoration occurs. Cost-effective in multiply recurrent patients given the high per-episode hospitalization cost.",drug:"bezlotoxumab",monographId:"bezlotoxumab"},{id:"c-difficile/multiple-recurrences/antibiotic-treatment-second-recurrence/fidaxomicin-extended-pulse-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"multiple-recurrences",subcategoryName:"Multiple Recurrences (≥2nd Recurrence)",line:"Antibiotic Treatment — Second Recurrence",regimen:"Fidaxomicin extended-pulsed: 200mg BID × 5d, then 200mg once every other day × 20d",notes:"Preferred antibiotic for second and subsequent recurrences. The extended-pulsed regimen targets spore germination. This is the antibiotic phase before microbiome restoration therapy.",drug:"fidaxomicin-extended-pulse"},{id:"c-difficile/multiple-recurrences/antibiotic-treatment-second-recurrence/vancomycin-taper-pulse-2",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"multiple-recurrences",subcategoryName:"Multiple Recurrences (≥2nd Recurrence)",line:"Antibiotic Treatment — Second Recurrence",regimen:"Vancomycin taper-and-pulse (6-8 week regimen)",notes:"Alternative if fidaxomicin is unavailable. Extended taper may be necessary: 125mg QID × 14d → 125mg BID × 7d → 125mg daily × 7d → 125mg q2d × 14d → 125mg q3d × 14d. The longer the pulse phase, the more germinating spores are eliminated.",drug:"vancomycin-taper-pulse"},{id:"c-difficile/multiple-recurrences/microbiome-restoration-fda-approved-products/rebyota-2",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"multiple-recurrences",subcategoryName:"Multiple Recurrences (≥2nd Recurrence)",line:"Microbiome Restoration — FDA-Approved Products",regimen:"Rebyota (fecal microbiota, live-jslm / RBL): single rectal administration",notes:"FIRST FDA-approved fecal microbiota product (November 2022). Delivered rectally by healthcare provider. PUNCH CD3 trial: 70.6% success vs 57.5% placebo. Given 24-72 hours after completing CDI antibiotics. Patient retains rectal administration for 15 minutes. Single administration — no repeat dosing needed. Advantage over traditional FMT: standardized manufacturing, screened donors, quality control.",drug:"rebyota"},{id:"c-difficile/multiple-recurrences/microbiome-restoration-fda-approved-products/vowst-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"multiple-recurrences",subcategoryName:"Multiple Recurrences (≥2nd Recurrence)",line:"Microbiome Restoration — FDA-Approved Products",regimen:"Vowst (fecal microbiota spores, live-brpk / SER-109): 4 capsules PO daily × 3 days",notes:"FIRST oral fecal microbiota product (FDA-approved April 2023). Purified Firmicutes spores in capsule form. Given 2-6 days after completing CDI antibiotics. ECOSPOR III trial: 88% success vs 60% placebo. GAME-CHANGER: eliminates need for colonoscopic or rectal FMT delivery. Capsules must be swallowed whole (do not crush/chew). Refrigerated storage. Patients must take with water on an empty stomach.",drug:"vowst"},{id:"c-difficile/multiple-recurrences/traditional-fmt-if-fda-approved-products-unavail/fmt-capsules-2",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"multiple-recurrences",subcategoryName:"Multiple Recurrences (≥2nd Recurrence)",line:"Traditional FMT (If FDA-Approved Products Unavailable)",regimen:"FMT capsules (investigational at some centers)",notes:"Non-FDA-approved FMT delivered via oral capsules. Available at some academic centers under IND. Less studied than colonoscopic FMT but shows similar efficacy in case series. Patient preference may favor oral over colonoscopic delivery.",drug:"fmt-capsules"},{id:"c-difficile/multiple-recurrences/traditional-fmt-if-fda-approved-products-unavail/fmt-colonoscopy-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"multiple-recurrences",subcategoryName:"Multiple Recurrences (≥2nd Recurrence)",line:"Traditional FMT (If FDA-Approved Products Unavailable)",regimen:"FMT via colonoscopy — fresh or frozen donor stool",notes:"Traditional fecal microbiota transplantation performed at specialized centers. Highest single-procedure success rate (~85-90% for recurrent CDI). Delivered via colonoscopy into the cecum/right colon. Requires pre-procedure CDI antibiotic treatment (stop antibiotics 24-48h before FMT). Donor screening is rigorous (FDA requires IND for FMT using non-FDA-approved products). The AGA 2024 guideline supports microbiota-based therapy for patients with recurrent CDI after appropriate antibiotic treatment.",drug:"fmt-colonoscopy"},{id:"cns-infections/brain-abscess/duration-monitoring/duration-abscess-1",diseaseId:"cns-infections",diseaseName:"CNS Infections",diseaseIcon:"🧠",subcategoryId:"brain-abscess",subcategoryName:"Brain Abscess",line:"Duration & Monitoring",regimen:"4-8 weeks of IV/oral antibiotics with serial imaging",notes:"Total duration depends on: size (larger = longer), drainage adequacy, organism, and clinical/radiographic response. Oral step-down is reasonable after 2-4 weeks of IV if clinical improvement and abscess shrinking on imaging. OVIVA principles apply — high-dose oral agents with good CNS penetration (metronidazole, fluoroquinolones, TMP-SMX, linezolid). Serial MRI q2-4 weeks to monitor response. Abscess capsule may persist for months on imaging even after cure — follow size trend, not complete resolution.",drug:"duration-abscess"},{id:"cns-infections/brain-abscess/empiric-post-neurosurgical-post-traumatic/vanc-cefepime-metro-1",diseaseId:"cns-infections",diseaseName:"CNS Infections",diseaseIcon:"🧠",subcategoryId:"brain-abscess",subcategoryName:"Brain Abscess",line:"Empiric — Post-Neurosurgical/Post-Traumatic",regimen:"Vancomycin IV + Cefepime 2g IV q8h + Metronidazole 500mg IV q8h",notes:"Covers MRSA + Pseudomonas + anaerobes + Enterobacterales. Post-surgical and post-traumatic abscesses have a different microbiologic profile (Staphylococci, gram-negatives) than community-acquired (Streptococci, anaerobes). Meropenem 2g IV q8h can substitute for cefepime + metronidazole (covers both gram-negatives and anaerobes) — but standard infusion for CNS penetration.",drug:"vanc-cefepime-metro"},{id:"cns-infections/brain-abscess/empiric-unknown-source-or-dental-sinus-origin/ceftriaxone-metro-abscess-1",diseaseId:"cns-infections",diseaseName:"CNS Infections",diseaseIcon:"🧠",subcategoryId:"brain-abscess",subcategoryName:"Brain Abscess",line:"Empiric — Unknown Source or Dental/Sinus Origin",regimen:"Ceftriaxone 2g IV q12h + Metronidazole 500mg IV q8h ± Vancomycin",notes:"Covers Streptococci (especially S. anginosus/milleri group — THE classic abscess-forming organism) + anaerobes + gram-negatives. Add vancomycin if: post-surgical, post-traumatic, IDU, or MRSA risk. Metronidazole provides excellent CNS penetration (40-100% of serum levels) and covers anaerobes that ceftriaxone misses. Duration: 4-8 weeks total (longer for larger abscesses or incomplete drainage).",drug:"ceftriaxone-metro-abscess",evidence:"A-I",evidenceSource:"IDSA 2004",evidenceSourceIds:["idsa-2004-bacterial-meningitis"]},{id:"cns-infections/brain-abscess/surgical-management/surgical-abscess-1",diseaseId:"cns-infections",diseaseName:"CNS Infections",diseaseIcon:"🧠",subcategoryId:"brain-abscess",subcategoryName:"Brain Abscess",line:"Surgical Management",regimen:"Stereotactic aspiration (preferred) or craniotomy with excision",notes:"ASPIRATION indications: abscess >2.5cm, accessible location, diagnostic uncertainty, mass effect. Most abscesses are managed with aspiration + antibiotics. May need repeat aspiration if abscess re-accumulates. EXCISION: reserved for multiloculated abscesses, posterior fossa (risk of brainstem compression), failed aspiration, traumatic abscess with foreign material. MEDICAL MANAGEMENT ALONE (no surgery): considered for small abscesses (<2.5cm), multiple small abscesses, early cerebritis stage, deep/eloquent location, and when patient is a poor surgical candidate.",drug:"surgical-abscess"},{id:"cns-infections/community-bacterial-meningitis/empiric-adults-50-years-or-immunocompromised-add/ceftriaxone-vanco-ampicillin-1",diseaseId:"cns-infections",diseaseName:"CNS Infections",diseaseIcon:"🧠",subcategoryId:"community-bacterial-meningitis",subcategoryName:"Community-Acquired Bacterial Meningitis",line:"Empiric — Adults >50 years or Immunocompromised (ADD Listeria coverage)",regimen:"Vancomycin IV + Ceftriaxone 2g IV q12h + Ampicillin 2g IV q4h + Dexamethasone",notes:"ADD AMPICILLIN for Listeria coverage in patients >50 years, immunocompromised (HIV, transplant, chronic steroids, pregnancy, alcoholism, malignancy). Ceftriaxone does NOT cover Listeria (inherent resistance to cephalosporins). Ampicillin is the drug of choice for Listeria meningitis. If the patient has no Listeria risk factors AND is <50 years, ampicillin can be omitted.",drug:"ceftriaxone-vanco-ampicillin",evidence:"A-I",evidenceSource:"IDSA 2004",evidenceSourceIds:["idsa-2004-bacterial-meningitis"]},{id:"cns-infections/community-bacterial-meningitis/empiric-adults-18-50-years-immediate-within-minu/ceftriaxone-vanco-meningitis-1",diseaseId:"cns-infections",diseaseName:"CNS Infections",diseaseIcon:"🧠",subcategoryId:"community-bacterial-meningitis",subcategoryName:"Community-Acquired Bacterial Meningitis",line:"Empiric — Adults 18-50 years (IMMEDIATE — within minutes)",regimen:"Vancomycin 15-20 mg/kg IV + Ceftriaxone 2g IV q12h + Dexamethasone 0.15 mg/kg IV q6h × 4 days",notes:"STANDARD empiric regimen for community-acquired bacterial meningitis in adults 18-50. Vancomycin covers ceftriaxone-resistant S. pneumoniae (ceftriaxone MIC ≥2). Ceftriaxone covers susceptible S. pneumoniae and N. meningitidis. Dexamethasone MUST be given BEFORE or SIMULTANEOUSLY with the first antibiotic dose — reduces mortality and neurologic sequelae (de Gans trial). If given hours later, it provides no benefit. TIMING IS EVERYTHING: do not delay antibiotics for LP, imaging, or any other test.",drug:"ceftriaxone-vanco-meningitis",evidence:"A-I",evidenceSource:"IDSA 2004",evidenceSourceIds:["idsa-2004-bacterial-meningitis"]},{id:"cns-infections/community-bacterial-meningitis/empiric-neonates-1-month/neonatal-meningitis-1",diseaseId:"cns-infections",diseaseName:"CNS Infections",diseaseIcon:"🧠",subcategoryId:"community-bacterial-meningitis",subcategoryName:"Community-Acquired Bacterial Meningitis",line:"Empiric — Neonates (<1 month)",regimen:"Ampicillin 75 mg/kg IV q6h + Cefotaxime 50 mg/kg IV q6h (or Gentamicin)",notes:"Covers GBS (S. agalactiae), E. coli (including K1 capsule), and Listeria. Cefotaxime preferred over ceftriaxone in neonates (ceftriaxone causes biliary sludging and displaces bilirubin from albumin → kernicterus risk). Cefotaxime is the only cephalosporin approved for neonatal meningitis in many guidelines. Gentamicin alternative for E. coli synergy if cefotaxime unavailable.",drug:"neonatal-meningitis"},{id:"cns-infections/community-bacterial-meningitis/pathogen-directed-therapy-after-csf-culture-gram/listeria-meningitis-3",diseaseId:"cns-infections",diseaseName:"CNS Infections",diseaseIcon:"🧠",subcategoryId:"community-bacterial-meningitis",subcategoryName:"Community-Acquired Bacterial Meningitis",line:"Pathogen-Directed Therapy (After CSF Culture/Gram Stain)",regimen:"Ampicillin 2g IV q4h × 21 days ± Gentamicin (first 7 days for synergy)",notes:"Listeria monocytogenes (gram-positive rods): CEPHALOSPORINS DO NOT COVER LISTERIA. This is why ampicillin is added empirically in patients >50 or immunocompromised. TMP-SMX is the alternative for penicillin-allergic patients (the ONLY reliable alternative). Meropenem has some activity but is not well-studied. Duration: ≥21 days (longer than other meningitis — Listeria has high relapse rate with shorter courses). STOP dexamethasone if Listeria confirmed — dexamethasone may worsen Listeria outcomes (impairs cell-mediated immunity needed for intracellular pathogen clearance).",drug:"listeria-meningitis"},{id:"cns-infections/community-bacterial-meningitis/pathogen-directed-therapy-after-csf-culture-gram/pneumococcal-meningitis-1",diseaseId:"cns-infections",diseaseName:"CNS Infections",diseaseIcon:"🧠",subcategoryId:"community-bacterial-meningitis",subcategoryName:"Community-Acquired Bacterial Meningitis",line:"Pathogen-Directed Therapy (After CSF Culture/Gram Stain)",regimen:"Ceftriaxone 2g IV q12h × 10-14 days (if MIC <1) ± vancomycin if MIC ≥1",notes:"S. pneumoniae (gram-positive diplococci): most common adult meningitis. CONTINUE dexamethasone for full 4 days. If ceftriaxone MIC <0.06: can use penicillin G 4 million units IV q4h. If MIC 0.1-1.0: ceftriaxone alone. If MIC ≥2: ceftriaxone + vancomycin (maintain both). Duration: 10-14 days.",drug:"pneumococcal-meningitis"},{id:"cns-infections/community-bacterial-meningitis/pathogen-directed-therapy-after-csf-culture-gram/meningococcal-meningitis-2",diseaseId:"cns-infections",diseaseName:"CNS Infections",diseaseIcon:"🧠",subcategoryId:"community-bacterial-meningitis",subcategoryName:"Community-Acquired Bacterial Meningitis",line:"Pathogen-Directed Therapy (After CSF Culture/Gram Stain)",regimen:"Ceftriaxone 2g IV q12h × 7 days (or Penicillin G if susceptible)",notes:"N. meningitidis (gram-negative diplococci): PUBLIC HEALTH EMERGENCY — requires immediate health department notification and close contact chemoprophylaxis (rifampin, ciprofloxacin, or ceftriaxone). Dexamethasone: uncertain benefit for meningococcal meningitis — continue if started empirically but the evidence is less clear than for pneumococcal. Duration: 7 days.",drug:"meningococcal-meningitis"},{id:"cns-infections/healthcare-cns/device-management/device-removal-1",diseaseId:"cns-infections",diseaseName:"CNS Infections",diseaseIcon:"🧠",subcategoryId:"healthcare-cns",subcategoryName:"Healthcare-Associated Meningitis/Ventriculitis",line:"Device Management",regimen:"Remove or externalize infected device whenever possible",notes:"VP shunt infection: removal + external drainage + antibiotics is the gold standard (cure rate >90% vs. 30-40% with antibiotics alone and shunt retention). EVD infection: replace the drain (exchange to contralateral side) + systemic ± intraventricular antibiotics. Treat until CSF is sterile for 48-72h and clinical improvement, then consider re-internalization.",drug:"device-removal"},{id:"cns-infections/healthcare-cns/empiric-post-neurosurgical-post-trauma/vancomycin-cefepime-meningitis-1",diseaseId:"cns-infections",diseaseName:"CNS Infections",diseaseIcon:"🧠",subcategoryId:"healthcare-cns",subcategoryName:"Healthcare-Associated Meningitis/Ventriculitis",line:"Empiric — Post-Neurosurgical/Post-Trauma",regimen:"Vancomycin 15-20 mg/kg IV q8-12h + Cefepime 2g IV q8h (or Meropenem 2g IV q8h)",notes:"Covers MRSA + Pseudomonas + Enterobacterales + Staphylococci. Vancomycin for MRSA/CoNS. Cefepime or meropenem for gram-negatives including Pseudomonas. MENINGITIS DOSING: higher than standard — vancomycin target trough 15-20 (or AUC equivalent for CNS penetration), cefepime 2g q8h, meropenem 2g q8h. Note for meropenem: use STANDARD infusion (not extended) for meningitis — need high peak levels for CSF penetration.",drug:"vancomycin-cefepime-meningitis"},{id:"cns-infections/healthcare-cns/intraventricular-antibiotics-adjunctive-for-refr/intrathecal-gent-2",diseaseId:"cns-infections",diseaseName:"CNS Infections",diseaseIcon:"🧠",subcategoryId:"healthcare-cns",subcategoryName:"Healthcare-Associated Meningitis/Ventriculitis",line:"Intraventricular Antibiotics (Adjunctive for Refractory Cases)",regimen:"Intraventricular gentamicin 4-8mg/day (via EVD or Ommaya reservoir)",notes:"For gram-negative ventriculitis — aminoglycosides achieve poor CSF penetration systemically but excellent concentrations intraventricularly. Alternative: polymyxin B or colistin intraventricularly for MDR gram-negatives (Acinetobacter, CRE). Coordinate dosing with EVD drainage — clamp drain for 15-60 min after instillation.",drug:"intrathecal-gent"},{id:"cns-infections/healthcare-cns/intraventricular-antibiotics-adjunctive-for-refr/intrathecal-vanc-1",diseaseId:"cns-infections",diseaseName:"CNS Infections",diseaseIcon:"🧠",subcategoryId:"healthcare-cns",subcategoryName:"Healthcare-Associated Meningitis/Ventriculitis",line:"Intraventricular Antibiotics (Adjunctive for Refractory Cases)",regimen:"Intraventricular vancomycin 10-20mg/day (via EVD or Ommaya reservoir)",notes:"For healthcare-associated ventriculitis/meningitis not responding to systemic antibiotics alone. Intraventricular route achieves CSF concentrations far exceeding what systemic dosing can achieve. IDSA 2017 recommends considering intraventricular antibiotics for gram-positive infections not responding to systemic therapy within 48-72h.",drug:"intrathecal-vanc"},{id:"cap/aspiration-pneumonia/alternatives/ceftriaxone-metro-1",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"aspiration-pneumonia",subcategoryName:"Aspiration Pneumonia",line:"Alternatives",regimen:"Ceftriaxone 1-2g IV daily + Metronidazole 500mg IV q8h",notes:"If amp-sulbactam unavailable. Ceftriaxone handles gram-negatives and streptococci; metronidazole adds anaerobic coverage. Note: the role of anaerobic coverage is debated — some experts argue it's unnecessary for most community-acquired aspiration.",drug:"ceftriaxone-metro"},{id:"cap/aspiration-pneumonia/alternatives/clindamycin-2",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"aspiration-pneumonia",subcategoryName:"Aspiration Pneumonia",line:"Alternatives",regimen:"Clindamycin 600mg IV q8h (or 300-450mg PO QID)",notes:"Traditional aspiration pneumonia drug — excellent anaerobic and streptococcal coverage. Fallen somewhat out of favor due to high C. diff risk. Still useful for penicillin-allergic patients or lung abscess.",drug:"clindamycin",monographId:"clindamycin"},{id:"cap/aspiration-pneumonia/alternatives/moxifloxacin-asp-3",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"aspiration-pneumonia",subcategoryName:"Aspiration Pneumonia",line:"Alternatives",regimen:"Moxifloxacin 400mg IV/PO daily",notes:"Covers typicals, atypicals, AND has moderate anaerobic activity (unique among FQs). Can be used as monotherapy for mild-moderate aspiration pneumonia. No Pseudomonas coverage.",drug:"moxifloxacin-asp"},{id:"cap/aspiration-pneumonia/first-line-community-acquired-aspiration/amox-clav-asp-2",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"aspiration-pneumonia",subcategoryName:"Aspiration Pneumonia",line:"First-Line (Community-Acquired Aspiration)",regimen:"Amoxicillin-clavulanate 875/125mg PO BID (if outpatient/mild)",notes:"Oral equivalent for mild aspiration pneumonia that can be treated outpatient. Same spectrum as IV amp-sulbactam. Duration: 5-7 days.",drug:"amox-clav-asp",evidence:"B-II",evidenceSource:"IDSA/ATS 2019",evidenceSourceIds:["ats-idsa-2019-cap"]},{id:"cap/aspiration-pneumonia/first-line-community-acquired-aspiration/amp-sulbactam-asp-1",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"aspiration-pneumonia",subcategoryName:"Aspiration Pneumonia",line:"First-Line (Community-Acquired Aspiration)",regimen:"Ampicillin-sulbactam 3g IV q6h",notes:"Excellent choice — covers streptococci, oral anaerobes, H. influenzae, and gram-negatives. The gold standard for aspiration pneumonia. Good anaerobic coverage without being overly broad.",drug:"amp-sulbactam-asp",evidence:"A-I",evidenceSource:"IDSA/ATS 2019",evidenceSourceIds:["ats-idsa-2019-cap"]},{id:"cap/aspiration-pneumonia/lung-abscess-empyema/prolonged-course-1",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"aspiration-pneumonia",subcategoryName:"Aspiration Pneumonia",line:"Lung Abscess / Empyema",regimen:"Amp-sulbactam or clindamycin × 4-6 weeks minimum for lung abscess",notes:"Lung abscess requires prolonged therapy — typically until radiographic resolution or significant improvement. Some abscesses >6cm may require percutaneous drainage or surgical intervention. Empyema requires chest tube drainage ± fibrinolytics (tPA + DNase per MIST2 trial) + antibiotics.",drug:"prolonged-course"},{id:"cap/cap-inpatient/first-line-combination-preferred-by-ats-idsa/ampicillin-sulbactam-2",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-inpatient",subcategoryName:"Inpatient CAP (Non-ICU)",line:"First-Line (Combination — Preferred by ATS/IDSA)",regimen:"Ampicillin-Sulbactam 3g IV q6h + Azithromycin 500mg IV/PO daily",notes:"Alternative beta-lactam backbone. Better anaerobic coverage than ceftriaxone (relevant if aspiration component suspected). Covers H. influenzae and M. catarrhalis beta-lactamase producers.",drug:"ampicillin-sulbactam",monographId:"ampicillin-sulbactam",evidence:"A-I",evidenceSource:"IDSA/ATS 2019",evidenceSourceIds:["ats-idsa-2019-cap"]},{id:"cap/cap-inpatient/first-line-combination-preferred-by-ats-idsa/ceftriaxone-1",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-inpatient",subcategoryName:"Inpatient CAP (Non-ICU)",line:"First-Line (Combination — Preferred by ATS/IDSA)",regimen:"Ceftriaxone 1-2g IV daily + Azithromycin 500mg IV/PO daily",notes:"The classic inpatient CAP regimen. Beta-lactam covers typicals; macrolide adds atypical coverage + immunomodulatory effects. ATS/IDSA 2019 preferred combination. Note: CAP-START suggests beta-lactam monotherapy may suffice — but most US institutions still use combination.",drug:"ceftriaxone",monographId:"ceftriaxone",evidence:"A-I",evidenceSource:"IDSA/ATS 2019",evidenceSourceIds:["ats-idsa-2019-cap"]},{id:"cap/cap-inpatient/first-line-combination-preferred-by-ats-idsa/ceftriaxone-doxy-3",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-inpatient",subcategoryName:"Inpatient CAP (Non-ICU)",line:"First-Line (Combination — Preferred by ATS/IDSA)",regimen:"Ceftriaxone 1-2g IV daily + Doxycycline 100mg PO/IV BID",notes:"Doxycycline substitution for macrolide-intolerant patients (QT concern, azithromycin allergy). Equally effective for atypical coverage.",drug:"ceftriaxone-doxy",evidence:"B-II",evidenceSource:"IDSA/ATS 2019",evidenceSourceIds:["ats-idsa-2019-cap"]},{id:"cap/cap-inpatient/second-line-monotherapy-respiratory-fq/levofloxacin-1",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-inpatient",subcategoryName:"Inpatient CAP (Non-ICU)",line:"Second-Line (Monotherapy — Respiratory FQ)",regimen:"Levofloxacin 750mg IV/PO daily",notes:"Monotherapy alternative. Covers typicals + atypicals in one drug. 100% oral bioavailability — switch to PO as soon as patient can swallow. Reserve for beta-lactam allergy or when combination therapy not feasible.",drug:"levofloxacin",monographId:"levofloxacin"},{id:"cap/cap-inpatient/second-line-monotherapy-respiratory-fq/moxifloxacin-2",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-inpatient",subcategoryName:"Inpatient CAP (Non-ICU)",line:"Second-Line (Monotherapy — Respiratory FQ)",regimen:"Moxifloxacin 400mg IV/PO daily",notes:"Superior pneumococcal activity vs. levo. NO Pseudomonal coverage. Higher QT prolongation risk. No IV-to-PO dose change needed. No renal adjustment.",drug:"moxifloxacin",monographId:"moxifloxacin"},{id:"cap/cap-outpatient-healthy/first-line-pick-one-monotherapy/amoxicillin-1",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-outpatient-healthy",subcategoryName:"Outpatient CAP — No Comorbidities",line:"First-Line (Pick ONE — Monotherapy)",regimen:"Amoxicillin 1g PO TID × 5 days",notes:"ATS/IDSA 2019 first-line. HIGH-DOSE (1g, not 500mg) targets intermediate-resistant S. pneumoniae. Excellent safety profile. STEP trial supports even 3-day courses if rapid clinical improvement.",drug:"amoxicillin",monographId:"amoxicillin",evidence:"A-I",evidenceSource:"IDSA/ATS 2019",evidenceSourceIds:["ats-idsa-2019-cap"]},{id:"cap/cap-outpatient-healthy/first-line-pick-one-monotherapy/azithromycin-3",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-outpatient-healthy",subcategoryName:"Outpatient CAP — No Comorbidities",line:"First-Line (Pick ONE — Monotherapy)",regimen:"Azithromycin 500mg PO day 1, then 250mg daily × 4 days (Z-pack)",notes:"Covers atypicals well. HOWEVER: Rising S. pneumoniae macrolide resistance (~30-40% in US) is a concern. ATS/IDSA 2019 only recommends as monotherapy where local pneumococcal macrolide resistance <25%. QT risk. Many ID physicians now prefer doxycycline over azithromycin.",drug:"azithromycin",monographId:"azithromycin",evidence:"A-I",evidenceSource:"IDSA/ATS 2019",evidenceSourceIds:["ats-idsa-2019-cap"]},{id:"cap/cap-outpatient-healthy/first-line-pick-one-monotherapy/doxycycline-2",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-outpatient-healthy",subcategoryName:"Outpatient CAP — No Comorbidities",line:"First-Line (Pick ONE — Monotherapy)",regimen:"Doxycycline 100mg PO BID × 5 days",notes:"Covers typicals AND atypicals (Mycoplasma, Chlamydophila). Good alternative for penicillin-allergic patients. Avoids azithromycin resistance selection. Well-tolerated.",drug:"doxycycline",monographId:"doxycycline",evidence:"A-I",evidenceSource:"IDSA/ATS 2019",evidenceSourceIds:["ats-idsa-2019-cap"]},{id:"cap/cap-outpatient-comorbid/first-line-combination-therapy/amox-clav-combo-1",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-outpatient-comorbid",subcategoryName:"Outpatient CAP — With Comorbidities",line:"First-Line (Combination Therapy)",regimen:"Amoxicillin-Clavulanate 875/125mg PO BID + Azithromycin 500mg day 1 then 250mg × 4 days",notes:"OR Amox-clav + Doxycycline 100mg BID. The beta-lactam covers S. pneumoniae, H. influenzae (beta-lactamase producers), M. catarrhalis. Macrolide/doxy adds atypical coverage. Duration: 5 days.",drug:"amox-clav-combo",evidence:"A-I",evidenceSource:"IDSA/ATS 2019",evidenceSourceIds:["ats-idsa-2019-cap"]},{id:"cap/cap-outpatient-comorbid/first-line-combination-therapy/cephalexin-combo-2",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-outpatient-comorbid",subcategoryName:"Outpatient CAP — With Comorbidities",line:"First-Line (Combination Therapy)",regimen:"Cephalexin 500mg PO TID (or Cefpodoxime 200mg BID) + Azithromycin or Doxycycline",notes:"Alternative beta-lactam backbone. Cefpodoxime preferred over cephalexin for broader gram-negative coverage.",drug:"cephalexin-combo",evidence:"B-II",evidenceSource:"IDSA/ATS 2019",evidenceSourceIds:["ats-idsa-2019-cap"]},{id:"cap/cap-outpatient-comorbid/second-line-monotherapy-respiratory-fluoroquinol/levofloxacin-1",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-outpatient-comorbid",subcategoryName:"Outpatient CAP — With Comorbidities",line:"Second-Line (Monotherapy — Respiratory Fluoroquinolone)",regimen:"Levofloxacin 750mg PO daily × 5 days",notes:"Respiratory FQ covers typicals + atypicals in one agent. Reserve as second-line per ATS/IDSA due to FDA boxed warnings and collateral damage. Appropriate when beta-lactam allergy is severe or combination therapy not feasible.",drug:"levofloxacin",monographId:"levofloxacin"},{id:"cap/cap-outpatient-comorbid/second-line-monotherapy-respiratory-fluoroquinol/moxifloxacin-2",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-outpatient-comorbid",subcategoryName:"Outpatient CAP — With Comorbidities",line:"Second-Line (Monotherapy — Respiratory Fluoroquinolone)",regimen:"Moxifloxacin 400mg PO daily × 5 days",notes:"Best anti-pneumococcal FQ. Excellent bioavailability. NO Pseudomonas activity (unlike levo). Higher QT risk than levofloxacin. No renal adjustment needed. AVOID if any QT concern.",drug:"moxifloxacin",monographId:"moxifloxacin"},{id:"cap/cap-icu/add-on-for-mrsa-risk-factors/linezolid-2",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-icu",subcategoryName:"Severe CAP / ICU Admission",line:"Add-On for MRSA Risk Factors",regimen:"Linezolid 600mg IV/PO BID",notes:"Alternative to vancomycin for MRSA pneumonia. Some data suggests better lung penetration. 100% oral bioavailability. Myelosuppression risk with courses >14 days. Monitor CBC weekly. Serotonin syndrome risk with SSRIs/MAOIs.",drug:"linezolid",monographId:"linezolid"},{id:"cap/cap-icu/add-on-for-mrsa-risk-factors/vancomycin-1",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-icu",subcategoryName:"Severe CAP / ICU Admission",line:"Add-On for MRSA Risk Factors",regimen:"Vancomycin IV (AUC/MIC-guided dosing, target AUC 400-600)",notes:"Add if: prior MRSA infection/colonization, IVDU, post-influenza necrotizing pneumonia, cavitation/empyema. Check nasal MRSA swab — if negative, de-escalate within 48h. AUC-guided dosing is now preferred over trough-based (2020 vancomycin consensus guidelines).",drug:"vancomycin",monographId:"vancomycin"},{id:"cap/cap-icu/add-on-for-pseudomonas-risk-factors/cefepime-2",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-icu",subcategoryName:"Severe CAP / ICU Admission",line:"Add-On for Pseudomonas Risk Factors",regimen:"Cefepime 2g IV q8h (extended infusion)",notes:"Alternative anti-pseudomonal beta-lactam. Also covers SPACE organisms (AmpC producers) — better than ceftriaxone for Enterobacter, Citrobacter, Serratia.",drug:"cefepime",monographId:"cefepime"},{id:"cap/cap-icu/add-on-for-pseudomonas-risk-factors/meropenem-3",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-icu",subcategoryName:"Severe CAP / ICU Admission",line:"Add-On for Pseudomonas Risk Factors",regimen:"Meropenem 1-2g IV q8h (extended infusion over 3h)",notes:"Reserve for severe septic shock, ESBL/MDR risk, or failure of other agents. Always de-escalate aggressively once cultures return. Extended infusion is standard of care in the ICU.",drug:"meropenem",monographId:"meropenem"},{id:"cap/cap-icu/add-on-for-pseudomonas-risk-factors/pip-tazo-1",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-icu",subcategoryName:"Severe CAP / ICU Admission",line:"Add-On for Pseudomonas Risk Factors",regimen:"Piperacillin-tazobactam 4.5g IV q6h (extended infusion over 4h)",notes:"Replace ceftriaxone with pip-tazo + azithromycin or FQ. Extended infusion critical for optimizing time above MIC. Consider adding an aminoglycoside or anti-pseudomonal FQ for double coverage in critically ill.",drug:"pip-tazo",monographId:"pip-tazo"},{id:"cap/cap-icu/adjunctive-therapy/corticosteroids-1",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-icu",subcategoryName:"Severe CAP / ICU Admission",line:"Adjunctive Therapy",regimen:"Hydrocortisone 200mg IV daily (50mg q6h) × 4-7 days, then taper",notes:"CAPE COD Trial (2023): Hydrocortisone reduced 28-day mortality in severe CAP (6.2% vs 11.9%, NNT=18). Practice-changing. ATS/IDSA 2019 conditionally recommends for refractory septic shock. Now extending to all severe CAP based on CAPE COD. Avoid in influenza pneumonia (worsens outcomes) and suspected fungal infection.",drug:"corticosteroids"},{id:"cap/cap-icu/adjunctive-therapy/oseltamivir-2",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-icu",subcategoryName:"Severe CAP / ICU Admission",line:"Adjunctive Therapy",regimen:"Oseltamivir 75mg PO BID × 5 days (or longer if immunocompromised)",notes:"Add empirically during influenza season for all ICU CAP until influenza is ruled out. Even if >48h from symptom onset, treat in severe/hospitalized cases.",drug:"oseltamivir"},{id:"cap/cap-icu/first-line-always-combination-for-severe-cap/amp-sulbactam-combo-3",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-icu",subcategoryName:"Severe CAP / ICU Admission",line:"First-Line (ALWAYS Combination for Severe CAP)",regimen:"Ampicillin-sulbactam 3g IV q6h + Azithromycin 500mg IV daily",notes:"Alternative beta-lactam backbone with better anaerobic coverage. Useful if aspiration component suspected in ICU CAP.",drug:"amp-sulbactam-combo",evidence:"B-II",evidenceSource:"IDSA/ATS 2019",evidenceSourceIds:["ats-idsa-2019-cap"]},{id:"cap/cap-icu/first-line-always-combination-for-severe-cap/ceftriaxone-1",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-icu",subcategoryName:"Severe CAP / ICU Admission",line:"First-Line (ALWAYS Combination for Severe CAP)",regimen:"Ceftriaxone 2g IV daily + Azithromycin 500mg IV daily",notes:"ATS/IDSA standard for severe CAP. The macrolide is STRONGLY recommended here (not optional like non-ICU). Macrolide immunomodulatory effect is most impactful in severe/bacteremic disease. Duration: minimum 5 days, typically 7 days.",drug:"ceftriaxone",monographId:"ceftriaxone",evidence:"A-I",evidenceSource:"IDSA/ATS 2019",evidenceSourceIds:["ats-idsa-2019-cap"]},{id:"cap/cap-icu/first-line-always-combination-for-severe-cap/ceftriaxone-fq-2",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-icu",subcategoryName:"Severe CAP / ICU Admission",line:"First-Line (ALWAYS Combination for Severe CAP)",regimen:"Ceftriaxone 2g IV daily + Levofloxacin 750mg IV daily",notes:"Alternative combination if macrolide cannot be used (QT prolongation, allergy). Note: combining ceftriaxone + FQ gives broader coverage but loses the macrolide immunomodulatory benefit.",drug:"ceftriaxone-fq",evidence:"A-I",evidenceSource:"IDSA/ATS 2019",evidenceSourceIds:["ats-idsa-2019-cap"]},{id:"diabetic-foot/dfi-osteomyelitis/medical-management-empiric-pending-bone-culture/vanc-erta-osteo-empiric-1",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"dfi-osteomyelitis",subcategoryName:"Diabetic Foot Osteomyelitis",line:"Medical Management — Empiric, Pending Bone Culture",regimen:"Vancomycin IV (AUC 400-600) + Ertapenem 1g IV q24h (empiric, pending bone biopsy results)",notes:"Broad empiric coverage pending bone culture: vancomycin for MRSA/gram-positives, ertapenem for Enterobacterales/anaerobes/MSSA. HOLD antibiotics for 48-72 hours (if clinically stable) to allow bone biopsy — culture yield plummets after antibiotics started. If bone biopsy cannot be obtained or must be delayed, start empiric therapy and accept empiric limitations. Narrow aggressively within 48-72h of culture results. Do NOT continue broad empiric coverage for 6 weeks without organism identification — this drives resistance and increases toxicity.",drug:"vanc-erta-osteo-empiric",evidence:"B-III",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/dfi-osteomyelitis/medical-management-pathogen-directed-gram-negati/cipro-gn-osteo-1",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"dfi-osteomyelitis",subcategoryName:"Diabetic Foot Osteomyelitis",line:"Medical Management — Pathogen-Directed, Gram-Negative Osteomyelitis",regimen:"Ciprofloxacin 750mg PO BID × 6 weeks (gram-negative osteomyelitis, susceptible organism)",notes:"Fluoroquinolones are the BEST oral agents for gram-negative osteomyelitis — highest oral bioavailability (~80%) and highest bone penetration ratio of any oral class. Ciprofloxacin 750mg BID achieves bone concentrations at 30-50% of peak serum concentration. OVIVA strongly supports oral fluoroquinolones for gram-negative bone infections. Check susceptibility before using — resistance in E. coli is 15-25%, Pseudomonas 20-40% in many US centers. Levofloxacin 750mg once daily is an alternative with better gram-positive coverage and simpler dosing.",drug:"cipro-gn-osteo",evidence:"A-I",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/dfi-osteomyelitis/medical-management-pathogen-directed-gram-negati/ertapenem-esbl-osteo-2",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"dfi-osteomyelitis",subcategoryName:"Diabetic Foot Osteomyelitis",line:"Medical Management — Pathogen-Directed, Gram-Negative Osteomyelitis",regimen:"Ertapenem 1g IV q24h × 6 weeks (ESBL-producing Enterobacterales osteomyelitis, OPAT setting)",notes:"For ESBL-producing gram-negative DFI osteomyelitis: ertapenem 1g IV once daily is the preferred OPAT agent. Does NOT cover Pseudomonas — ensure Pseudomonas is not a co-pathogen. Once-daily dosing compatible with home infusion nurse visits every other day. Renally eliminated — adjust for CrCl <30 mL/min. Oral step-down for ESBL osteomyelitis is challenging — fluoroquinolone only if confirmed susceptible.",drug:"ertapenem-esbl-osteo",evidence:"A-II",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/dfi-osteomyelitis/medical-management-pathogen-directed-mrsa-osteom/dapto-mrsa-osteo-opat-2",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"dfi-osteomyelitis",subcategoryName:"Diabetic Foot Osteomyelitis",line:"Medical Management — Pathogen-Directed, MRSA Osteomyelitis",regimen:"Daptomycin 8-10 mg/kg IV q24h × 6 weeks (MRSA osteomyelitis, OPAT-preferred regimen)",notes:"Daptomycin at 8-10 mg/kg is preferred over vancomycin by many ID specialists for MRSA DFI osteomyelitis in the OPAT setting: (1) Once-daily dosing (easier for home infusion), (2) No AUC monitoring required (CPK monitoring suffices), (3) Higher tissue concentrations at 8-10 mg/kg (superior bone penetration), (4) Activity against biofilm-embedded MRSA. Clinical evidence for high-dose daptomycin in osteomyelitis is observational. CPK monitoring weekly — myopathy risk increases above 6 mg/kg. Suspend concurrent statins.",drug:"dapto-mrsa-osteo-opat",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/dfi-osteomyelitis/medical-management-pathogen-directed-mrsa-osteom/vanc-mrsa-osteo-1",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"dfi-osteomyelitis",subcategoryName:"Diabetic Foot Osteomyelitis",line:"Medical Management — Pathogen-Directed, MRSA Osteomyelitis",regimen:"Vancomycin IV (AUC/MIC 400-600) × 2-6 weeks → oral TMP-SMX DS 2 tabs PO BID to complete 6 weeks total",notes:"Standard IV therapy for MRSA DFI osteomyelitis. AUC-guided Bayesian dosing is mandatory — trough-only monitoring is no longer standard (2020 consensus). Target AUC/MIC 400-600 mg·h/L. Oral step-down: TMP-SMX DS 2 tabs BID (workhorse for MRSA osteomyelitis — excellent bone penetration, generally tolerated long-term). Monitor: creatinine (false rise from tubular creatinine secretion block — educate team this is not true AKI), potassium (hyperkalemia risk — check weekly), CBC. Linezolid 600mg BID is alternative oral step-down if TMP-SMX not tolerated.",drug:"vanc-mrsa-osteo",evidence:"A-I",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/dfi-osteomyelitis/medical-management-pathogen-directed-mssa-osteom/cefazolin-mssa-osteo-1",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"dfi-osteomyelitis",subcategoryName:"Diabetic Foot Osteomyelitis",line:"Medical Management — Pathogen-Directed, MSSA Osteomyelitis",regimen:"Cefazolin 2g IV q8h × 2-6 weeks → oral step-down (levofloxacin 750mg PO q24h + rifampin 300mg PO q12h, OR TMP-SMX DS 2 tabs PO BID) to complete 6 weeks total",notes:"Gold standard for MSSA osteomyelitis. Initial IV cefazolin for 1-2 weeks achieves rapid bactericidal activity in bone. OVIVA-supported oral step-down after initial IV period: levofloxacin 750mg daily (excellent bone penetration ~30-50% of serum concentrations) ± rifampin 300mg BID (biofilm penetration — see pearl below). Rifampin combination for osteomyelitis: data is strongest for Staphylococcal PJI (Zimmerli trial), but extrapolated to DFI osteomyelitis by many ID specialists — use with companion drug only (resistance develops rapidly with rifampin monotherapy). CRP trending every 2 weeks confirms treatment response.",drug:"cefazolin-mssa-osteo",evidence:"A-I",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/dfi-osteomyelitis/medical-management-pathogen-directed-mssa-osteom/diclox-mssa-osteo-oral-2",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"dfi-osteomyelitis",subcategoryName:"Diabetic Foot Osteomyelitis",line:"Medical Management — Pathogen-Directed, MSSA Osteomyelitis",regimen:"Dicloxacillin 500mg PO QID × 6 weeks (mild-moderate MSSA osteomyelitis, OVIVA-eligible patients)",notes:"For selected MSSA DFI osteomyelitis in OVIVA-eligible patients: oral from the start or after ≤7 days IV. Dicloxacillin achieves adequate serum concentrations for MSSA osteomyelitis but bone penetration is lower than fluoroquinolones. Must be taken on empty stomach. Most ID experts prefer fluoroquinolone or TMP-SMX oral step-down over dicloxacillin for bone infections — better bone concentration data. Discuss with ID.",drug:"diclox-mssa-osteo-oral",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/dfi-osteomyelitis/surgical-resection-post-operative-antibiotic-dur/post-resection-dirty-margins-2",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"dfi-osteomyelitis",subcategoryName:"Diabetic Foot Osteomyelitis",line:"Surgical Resection — Post-Operative Antibiotic Duration",regimen:"Antibiotics for 2-4 weeks post-operatively (incomplete resection or positive margins on histology)",notes:"When intraoperative cultures are positive and/or histology shows residual osteomyelitis at the resection margin: treat as ongoing osteomyelitis. Duration: 2-4 weeks from the date of resection (not from initial diagnosis). The goal is pathogen-directed therapy guided by intraoperative bone culture. Surface wound cultures from the amputation stump do NOT guide this therapy — intraoperative bone cultures are the essential data point.",drug:"post-resection-dirty-margins",evidence:"B-III",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/dfi-osteomyelitis/surgical-resection-post-operative-antibiotic-dur/post-resection-clean-margins-1",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"dfi-osteomyelitis",subcategoryName:"Diabetic Foot Osteomyelitis",line:"Surgical Resection — Post-Operative Antibiotic Duration",regimen:"Antibiotics for 5-7 days post-operatively (complete bone resection with histologically confirmed clean margins)",notes:"PARADIGM SHIFT (IDSA/IWGDF 2023; Ha Van 2003): If ALL infected bone is resected with pathologically confirmed clean margins, only 5-7 days of post-operative antibiotics are needed — to treat residual soft tissue infection, not residual bone infection. The surgery has eliminated the bone infection. Antibiotics post-resection address any surrounding soft tissue component. This dramatically reduces treatment burden vs. historical 6-week post-op courses. CRITICAL: 'clean margins' must be confirmed by pathology (absence of osteomyelitis on histology at resection edge) — not just clinical or surgical judgment.",drug:"post-resection-clean-margins",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/mild-dfi/first-line-mild-dfi-with-mrsa-risk-factors-outpa/doxycycline-mild-dfi-2",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"mild-dfi",subcategoryName:"Mild Diabetic Foot Infection",line:"First-Line — Mild DFI WITH MRSA Risk Factors, Outpatient Oral",regimen:"Doxycycline 100mg PO BID × 5-7 days",notes:"Alternative for MRSA-risk mild DFI, especially when TMP-SMX is not tolerated or contraindicated. CA-MRSA susceptibility >95%. BID dosing. Same Streptococcal gap as TMP-SMX — pair with amoxicillin if significant surrounding cellulitis. Photosensitivity risk (counsel patient to use sunscreen). Take with full glass of water upright to prevent esophageal ulceration. No renal dose adjustment required (unlike TMP-SMX).",drug:"doxycycline-mild-dfi",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/mild-dfi/first-line-mild-dfi-with-mrsa-risk-factors-outpa/tmp-smx-mild-dfi-1",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"mild-dfi",subcategoryName:"Mild Diabetic Foot Infection",line:"First-Line — Mild DFI WITH MRSA Risk Factors, Outpatient Oral",regimen:"TMP-SMX DS (160/800mg) 1-2 tablets PO BID × 5-7 days",notes:"Add to mild DFI regimen when MRSA risk factors present (prior MRSA, nursing home resident, prior hospitalization, known MRSA contact, local MRSA prevalence >30%). Excellent CA-MRSA activity (>95% susceptible). IMPORTANT LIMITATION: TMP-SMX has poor Streptococcal coverage — for mild DFI with surrounding cellulitis, consider adding amoxicillin or cephalexin to address the Streptococcal gap. Renally adjust for CrCl <30 mL/min (avoid or reduce dose). Monitor potassium (amiloride-like potassium-sparing effect — risk of hyperkalemia with ACE/ARB, common in diabetics).",drug:"tmp-smx-mild-dfi",evidence:"A-II",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/mild-dfi/first-line-mild-dfi-no-mrsa-risk-outpatient-oral/amox-clav-mild-dfi-1",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"mild-dfi",subcategoryName:"Mild Diabetic Foot Infection",line:"First-Line — Mild DFI, No MRSA Risk, Outpatient Oral",regimen:"Amoxicillin-clavulanate 875/125mg PO BID × 5-7 days",notes:"IDSA/IWGDF 2023 first-line for mild DFI. Covers gram-positive cocci (Streptococci, MSSA), some gram-negatives (E. coli, Klebsiella — less relevant in mild DFI), and anaerobes. The beta-lactamase inhibitor component (clavulanate) extends coverage to MSSA and anaerobes. BID dosing improves adherence over TID regimens. Avoid if penicillin allergy. GI tolerability: take with food to reduce nausea/diarrhea from clavulanate. Do NOT use if MRSA risk factors present.",drug:"amox-clav-mild-dfi",evidence:"A-I",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/mild-dfi/first-line-mild-dfi-no-mrsa-risk-outpatient-oral/cephalexin-mild-dfi-2",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"mild-dfi",subcategoryName:"Mild Diabetic Foot Infection",line:"First-Line — Mild DFI, No MRSA Risk, Outpatient Oral",regimen:"Cephalexin 500mg PO QID (or 1000mg PO BID) × 5-7 days",notes:"Reasonable first-line alternative for mild, acute DFI in antibiotic-naive patients. Covers Streptococci and MSSA. No anaerobic or MRSA coverage. BID high-dose regimen (1g BID) achieves comparable T>MIC to QID dosing and dramatically improves adherence — many ID pharmacists now prefer 1g BID. Use when the wound is acute, superficial, and likely monomicrobial gram-positive etiology. De-escalation target if cultures confirm MSSA.",drug:"cephalexin-mild-dfi",evidence:"A-II",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/mild-dfi/first-line-mild-dfi-no-mrsa-risk-outpatient-oral/clindamycin-mild-dfi-3",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"mild-dfi",subcategoryName:"Mild Diabetic Foot Infection",line:"First-Line — Mild DFI, No MRSA Risk, Outpatient Oral",regimen:"Clindamycin 300-450mg PO TID × 5-7 days",notes:"Alternative for penicillin-allergic patients. Covers Streptococci, MSSA, and most CA-MRSA (check local susceptibility — clindamycin resistance rising to 15-25% in some areas). D-test required if erythromycin-resistant isolate is clindamycin-susceptible (inducible resistance via erm gene — will fail clinically despite in vitro susceptibility). Also covers anaerobes — useful for wounds with any necrotic component. Higher C. diff risk than beta-lactams.",drug:"clindamycin-mild-dfi",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/mild-dfi/penicillin-allergy-alternatives-non-anaphylactic/clindamycin-pen-allergy-mild-1",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"mild-dfi",subcategoryName:"Mild Diabetic Foot Infection",line:"Penicillin Allergy Alternatives (Non-Anaphylactic History)",regimen:"Clindamycin 300mg PO TID × 5-7 days",notes:"For mild DFI with non-severe penicillin allergy. Covers gram-positives + anaerobes. Check D-test. For confirmed anaphylactic penicillin allergy, cross-reactivity with cephalosporins is <2% for dissimilar side chains — many ID pharmacists advocate for cephalosporins even in documented penicillin allergy (discuss with prescriber/patient). Azithromycin is NOT recommended for DFI — poor Staphylococcal activity.",drug:"clindamycin-pen-allergy-mild",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/moderate-dfi/first-line-moderate-dfi-iv-required-hospitalized/cefazolin-moderate-iv-3",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"moderate-dfi",subcategoryName:"Moderate Diabetic Foot Infection",line:"First-Line — Moderate DFI, IV Required (Hospitalized or OPAT)",regimen:"Cefazolin 2g IV q8h (soft tissue, low-risk, no deep involvement) ± add anaerobic coverage (metronidazole 500mg IV q8h) if necrotic wound",notes:"Acceptable for moderate DFI with primarily gram-positive etiology (early infection, no chronic wound features, no gram-negative risk). Cefazolin covers MSSA and Streptococci. No MRSA, no Pseudomonas, limited anaerobic coverage. Add metronidazole 500mg IV/PO q8h if necrotic wound or fetid discharge. Add vancomycin if MRSA risk. This narrow regimen is appropriate only for selected moderate DFI — do NOT use for chronic deep wounds without culture data.",drug:"cefazolin-moderate-iv",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/moderate-dfi/first-line-moderate-dfi-iv-required-hospitalized/ertapenem-moderate-iv-1",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"moderate-dfi",subcategoryName:"Moderate Diabetic Foot Infection",line:"First-Line — Moderate DFI, IV Required (Hospitalized or OPAT)",regimen:"Ertapenem 1g IV q24h ± Vancomycin IV (AUC/MIC 400-600) if MRSA risk",notes:"IDSA/IWGDF preferred IV regimen for moderate DFI requiring hospitalization. Ertapenem provides: MSSA, Streptococci, Enterobacterales (including most ESBL producers), and anaerobic coverage. Once-daily dosing is ideal for OPAT. CRITICAL GAPS: NO Pseudomonas aeruginosa coverage, NO MRSA coverage. Add vancomycin if MRSA risk factors present. Substitute pip-tazo or meropenem if Pseudomonas risk exists (macerated wound, hydrotherapy, prior Pseudomonas, tropical exposure). Ertapenem is renally eliminated — dose-adjust for CrCl <30 mL/min (500mg q24h).",drug:"ertapenem-moderate-iv",evidence:"A-I",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/moderate-dfi/first-line-moderate-dfi-iv-required-hospitalized/pip-tazo-moderate-iv-2",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"moderate-dfi",subcategoryName:"Moderate Diabetic Foot Infection",line:"First-Line — Moderate DFI, IV Required (Hospitalized or OPAT)",regimen:"Piperacillin-tazobactam 4.5g IV q6h (extended infusion over 4h) ± Vancomycin IV",notes:"Alternative to ertapenem for moderate DFI when Pseudomonas coverage is needed (macerated wound, water exposure, prior Pseudomonas cultures). Pip-tazo covers MSSA, Streptococci, Enterobacterales, Pseudomonas aeruginosa, and anaerobes. Extended infusion (4-hour infusion q6h) optimizes T>MIC PK/PD target and is strongly preferred by ID pharmacists. Add vancomycin for MRSA coverage. De-escalate based on cultures — if Pseudomonas not recovered, step down to ertapenem or oral agents.",drug:"pip-tazo-moderate-iv",evidence:"A-II",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/moderate-dfi/first-line-moderate-dfi-oral-candidate-no-iv-req/amox-clav-moderate-oral-1",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"moderate-dfi",subcategoryName:"Moderate Diabetic Foot Infection",line:"First-Line — Moderate DFI, Oral Candidate (No IV Required)",regimen:"Amoxicillin-clavulanate 875/125mg PO BID × 2-3 weeks",notes:"Appropriate for moderate DFI with erythema >2cm but no deep tissue involvement, ambulatory patient, reliable GI absorption, no MRSA risk, no Pseudomonas risk. Covers MSSA, Streptococci, most Enterobacterales, and anaerobes. Add TMP-SMX or doxycycline if MRSA risk present. Duration: 2 weeks for soft tissue only; extend to 3 weeks if slow response. Reassess clinically at 72 hours.",drug:"amox-clav-moderate-oral",evidence:"A-II",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/moderate-dfi/first-line-moderate-dfi-oral-candidate-no-iv-req/clinda-cipro-moderate-oral-2",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"moderate-dfi",subcategoryName:"Moderate Diabetic Foot Infection",line:"First-Line — Moderate DFI, Oral Candidate (No IV Required)",regimen:"Clindamycin 300-450mg PO TID + Ciprofloxacin 500mg PO BID × 2-3 weeks",notes:"Alternative oral combination for moderate DFI with MRSA risk or deeper wound features. Clindamycin: covers MSSA, most CA-MRSA, Streptococci, and anaerobes. Ciprofloxacin: covers gram-negatives including moderate Pseudomonas activity. Together: comprehensive polymicrobial coverage without IV therapy. Check D-test for clindamycin if erythromycin-resistant isolate. This combination is especially useful for chronic wounds where gram-negatives are likely co-pathogens.",drug:"clinda-cipro-moderate-oral",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/moderate-dfi/mrsa-coverage-add-when-risk-factors-present/daptomycin-moderate-mrsa-2",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"moderate-dfi",subcategoryName:"Moderate Diabetic Foot Infection",line:"MRSA Coverage — Add When Risk Factors Present",regimen:"Daptomycin 6 mg/kg IV q24h — alternative to vancomycin for MRSA, particularly in renal impairment or vancomycin intolerance",notes:"Alternative MRSA coverage agent. Once-daily dosing (OPAT-friendly). Rapidly bactericidal. Do NOT use for pulmonary infections (inactivated by surfactant). Monitor CPK weekly — myopathy risk, especially with concurrent statin use. Daptomycin may be preferred over vancomycin for DFI when: vancomycin AUC-guided dosing not available, prior vancomycin-associated nephrotoxicity, vancomycin MIC creep (vancomycin MIC ≥2 µg/mL), or in patients with baseline renal impairment where vancomycin toxicity risk is elevated.",drug:"daptomycin-moderate-mrsa",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/moderate-dfi/mrsa-coverage-add-when-risk-factors-present/vancomycin-moderate-mrsa-1",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"moderate-dfi",subcategoryName:"Moderate Diabetic Foot Infection",line:"MRSA Coverage — Add When Risk Factors Present",regimen:"Vancomycin IV (AUC/MIC-guided, target AUC/MIC 400-600) — add to gram-negative backbone",notes:"Add vancomycin to ertapenem or pip-tazo backbone when MRSA risk factors are present: prior MRSA, recent hospitalization/nursing home, local MRSA prevalence >30%, prior wound culture showing MRSA, IV drug use. AUC-guided dosing is the 2020 ASHP/IDSA/SIDP consensus standard — Bayesian dosing software strongly preferred over trough-only monitoring. De-escalate to targeted oral agent (TMP-SMX, doxycycline, linezolid) as soon as patient is clinically stable and GI absorption reliable.",drug:"vancomycin-moderate-mrsa",evidence:"A-I",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/moderate-dfi/oral-step-down-iv-to-po-after-clinical-stabiliza/cipro-moderate-step-down-1",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"moderate-dfi",subcategoryName:"Moderate Diabetic Foot Infection",line:"Oral Step-Down (IV to PO) — After Clinical Stabilization",regimen:"Ciprofloxacin 500-750mg PO BID (gram-negative coverage, Pseudomonas if susceptible)",notes:"Excellent PO bioavailability (~80%). Best oral option for gram-negative osteomyelitis step-down (OVIVA data). Does NOT cover MRSA or anaerobes. Pair with TMP-SMX or doxycycline if MRSA step-down needed. Fluoroquinolone cautions: FDA boxed warning (tendinopathy, peripheral neuropathy, CNS effects — particularly relevant in diabetics who already have peripheral neuropathy). Avoid if prior fluoroquinolone exposure within 90 days (resistance risk). Check fluoroquinolone susceptibility on culture before using for step-down.",drug:"cipro-moderate-step-down",evidence:"A-II",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/moderate-dfi/oral-step-down-iv-to-po-after-clinical-stabiliza/linezolid-moderate-step-down-3",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"moderate-dfi",subcategoryName:"Moderate Diabetic Foot Infection",line:"Oral Step-Down (IV to PO) — After Clinical Stabilization",regimen:"Linezolid 600mg PO/IV BID (MRSA, gram-positive, excellent bone penetration)",notes:"100% oral bioavailability — oral equals IV in bone/tissue concentrations. Excellent for MRSA step-down with bone penetration superior to most alternatives. Limitations: cost (expensive, especially without PA approval), myelosuppression (CBC weekly — thrombocytopenia and anemia risk if >14 days, more common in renal impairment), serotonin syndrome risk (avoid with serotonergic drugs: SSRIs, SNRIs, MAOIs, tramadol), lactic acidosis with prolonged use (mitochondrial toxicity). Reserve for confirmed MRSA soft tissue/bone infection when TMP-SMX not tolerated or contraindicated. Limit duration <6 weeks when possible.",drug:"linezolid-moderate-step-down",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/moderate-dfi/oral-step-down-iv-to-po-after-clinical-stabiliza/tmp-smx-moderate-step-down-2",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"moderate-dfi",subcategoryName:"Moderate Diabetic Foot Infection",line:"Oral Step-Down (IV to PO) — After Clinical Stabilization",regimen:"TMP-SMX DS 1-2 tablets PO BID (MRSA, gram-positive step-down)",notes:"Excellent oral MRSA agent with good soft tissue and bone penetration. Renally eliminated — adjust for CrCl <30 mL/min (avoid or reduce dose to 1 DS tab BID). Hyperkalemia risk — monitor K at day 3-5, especially in patients on ACE/ARBs (nearly universal in diabetic patients with nephropathy). False creatinine rise: TMP blocks tubular creatinine secretion — creatinine will rise without true GFR decline; monitor cystatin C or clinical assessment rather than stopping TMP-SMX for this reason.",drug:"tmp-smx-moderate-step-down",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/severe-dfi/esbl-or-mdr-gram-negative-suspected-confirmed/caz-avi-cre-severe-2",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"severe-dfi",subcategoryName:"Severe Diabetic Foot Infection",line:"ESBL or MDR Gram-Negative Suspected/Confirmed",regimen:"Ceftazidime-avibactam 2.5g IV q8h (extended infusion) — for KPC-producing Klebsiella or MDR Pseudomonas",notes:"Reserve for carbapenem-resistant Enterobacterales (CRE) — specifically KPC producers. Ceftazidime-avibactam covers KPC, OXA-48, and extended-spectrum beta-lactamases but NOT metallo-beta-lactamases (NDM, VIM, IMP — which require aztreonam-avibactam or colistin-based regimens). Always confirm mechanism of carbapenem resistance before choosing therapy. Consult ID and antimicrobial stewardship. This is a high-cost, restricted antibiotic — appropriate use critical.",drug:"caz-avi-cre-severe",evidence:"B-III",evidenceSource:"IDSA AMR Guidance 2023",evidenceSourceIds:["idsa-2023-amr"]},{id:"diabetic-foot/severe-dfi/esbl-or-mdr-gram-negative-suspected-confirmed/meropenem-esbl-severe-1",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"severe-dfi",subcategoryName:"Severe Diabetic Foot Infection",line:"ESBL or MDR Gram-Negative Suspected/Confirmed",regimen:"Meropenem 1g IV q8h (ESBL confirmed or high-risk severe DFI)",notes:"When deep tissue or blood culture grows ESBL-producing E. coli or Klebsiella in severe DFI: meropenem is the definitive therapy. Ertapenem is also acceptable for ESBL if not critically ill (lacks Pseudomonas coverage — avoid if Pseudomonas co-pathogen suspected). Cefepime is NOT reliable for ESBL (inoculum effect causes in vivo failure despite in vitro susceptibility in some patients). Do NOT use extended-spectrum cephalosporins for ESBL-confirmed infections.",drug:"meropenem-esbl-severe",evidence:"A-I",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/severe-dfi/first-line-severe-dfi-empiric-broad-spectrum-iv/meropenem-vanc-severe-2",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"severe-dfi",subcategoryName:"Severe Diabetic Foot Infection",line:"First-Line — Severe DFI, Empiric Broad-Spectrum, IV",regimen:"Meropenem 1g IV q8h + Vancomycin IV (AUC/MIC 400-600)",notes:"Reserve for severe DFI with: prior MDR gram-negative cultures, recent hospitalization, prior broad-spectrum antibiotic exposure within 90 days, or failed pip-tazo therapy. Meropenem covers Enterobacterales (including ESBL), Pseudomonas, and anaerobes — broader than pip-tazo for resistant gram-negatives. Add vancomycin for MRSA. This is not first-line empiric — reserve to prevent unnecessary carbapenem use and emergence of carbapenem-resistant organisms (CRO). Consult antimicrobial stewardship.",drug:"meropenem-vanc-severe",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/severe-dfi/first-line-severe-dfi-empiric-broad-spectrum-iv/pip-tazo-vanc-severe-1",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"severe-dfi",subcategoryName:"Severe Diabetic Foot Infection",line:"First-Line — Severe DFI, Empiric Broad-Spectrum, IV",regimen:"Piperacillin-tazobactam 4.5g IV q6h (extended infusion over 4h) + Vancomycin IV (AUC/MIC 400-600)",notes:"Standard empiric regimen for severe DFI. Pip-tazo covers: MSSA, Streptococci, Enterobacterales, Pseudomonas aeruginosa, and anaerobes. Vancomycin adds MRSA coverage. Extended infusion pip-tazo (4h over 30 min q6h) significantly improves T>MIC target attainment for susceptible and intermediate Pseudomonas — pharmacist-driven intervention with high impact. AUC-guided vancomycin dosing (Bayesian software) reduces nephrotoxicity while ensuring efficacy. De-escalate based on blood cultures and deep wound cultures within 48-72h.",drug:"pip-tazo-vanc-severe",evidence:"A-I",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/severe-dfi/mrsa-coverage-options-iv/daptomycin-severe-mrsa-2",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"severe-dfi",subcategoryName:"Severe Diabetic Foot Infection",line:"MRSA Coverage Options — IV",regimen:"Daptomycin 6-8 mg/kg IV q24h — alternative or adjunct to vancomycin for MRSA",notes:"Daptomycin 6 mg/kg for serious MRSA soft tissue infection; consider 8-10 mg/kg for DFI osteomyelitis (higher doses improve bone penetration and maintain activity against biofilm-embedded organisms per pharmacodynamic data). Once-daily dosing. Monitor CPK weekly — suspend statins during daptomycin therapy (myopathy risk). Preferred over vancomycin when: vancomycin MIC ≥2 µg/mL, prior vancomycin nephrotoxicity, or OPAT (once-daily vs. intermittent vancomycin infusions). Do NOT use for pneumonia.",drug:"daptomycin-severe-mrsa",evidence:"B-II",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/severe-dfi/mrsa-coverage-options-iv/vancomycin-severe-mrsa-1",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"severe-dfi",subcategoryName:"Severe Diabetic Foot Infection",line:"MRSA Coverage Options — IV",regimen:"Vancomycin IV — AUC/MIC target 400-600 mg·h/L (Bayesian dosing strongly preferred)",notes:"Standard MRSA coverage for severe DFI. Initiate with loading dose (25-35 mg/kg IV once for severe infection) followed by maintenance dosing guided by Bayesian pharmacokinetic software. Monitor AUC daily for first 2-3 days, then every 2-3 days when stable. Nephrotoxicity risk is real, particularly with concurrent nephrotoxins (NSAIDs — common in diabetics), contrast agents, or baseline CKD. Transition to oral MRSA agent (TMP-SMX, linezolid) when clinically stable and GI function adequate.",drug:"vancomycin-severe-mrsa",evidence:"A-I",evidenceSource:"IDSA/IWGDF 2023",evidenceSourceIds:["iwgdf-idsa-dfi"]},{id:"diabetic-foot/severe-dfi/necrotizing-fasciitis-emergent-regimen-if-nsti-s/nsti-dfi-regimen-1",diseaseId:"diabetic-foot",diseaseName:"Diabetic Foot Infections",diseaseIcon:"🦶",subcategoryId:"severe-dfi",subcategoryName:"Severe Diabetic Foot Infection",line:"Necrotizing Fasciitis — Emergent Regimen (If NSTI Suspected)",regimen:"Vancomycin IV + Piperacillin-tazobactam 4.5g IV q6h + Clindamycin 900mg IV q8h (toxin suppression)",notes:"If necrotizing fasciitis is suspected in addition to DFI (pain out of proportion, crepitus, rapidly spreading necrosis, skin blistering, hemodynamic instability): EMERGENT surgery consultation + triple therapy. Add clindamycin 900mg IV q8h for toxin suppression (Eagle effect — at high bacterial inocula, cell-wall agents are less effective; clindamycin inhibits toxin synthesis regardless of growth phase). TIME TO SURGERY IS THE DOMINANT PROGNOSTIC VARIABLE — do not delay OR for further imaging if clinical picture strongly suggests necrotizing fasciitis.",drug:"nsti-dfi-regimen",evidence:"A-I",evidenceSource:"IDSA 2014 SSTI Guidelines (NF component)",evidenceSourceIds:["idsa-2014-ssti"]},{id:"febrile-neutropenia/fn-with-fungal-risk/antibacterial-prophylaxis-high-risk-prolonged-ne/ciprofloxacin-ppx-1",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"fn-with-fungal-risk",subcategoryName:"Febrile Neutropenia — Persistent / Fungal Risk",line:"Antibacterial Prophylaxis — High-Risk Prolonged Neutropenia",regimen:"Ciprofloxacin 500 mg PO BID — for expected neutropenia >7 days (AML induction, HSCT)",notes:"IDSA 2010 (A-I): Fluoroquinolone prophylaxis reduces FN incidence by 50% and infection-related mortality in patients expected to have prolonged profound neutropenia. NCCN 2024 recommends fluoroquinolone prophylaxis for: neutropenia expected >7 days (AML induction, intensive lymphoma regimens, HSCT). CRITICAL CAVEATS: (1) Increased FQ resistance — widespread prophylaxis selects for FQ-resistant gram-negatives (especially ESBL-producing E. coli). If FN develops while on FQ prophylaxis, use IV antipseudomonal beta-lactam (NOT a fluoroquinolone). (2) C. difficile risk — FQ prophylaxis increases CDI risk; concomitant proton pump inhibitors further increase risk. Monitor for diarrhea. (3) QTc effects if combined with azole antifungals. Levofloxacin 500 mg PO daily is an alternative — CALGB 10403 and other trials show similar efficacy to ciprofloxacin.",drug:"ciprofloxacin-ppx",evidence:"A-I",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"febrile-neutropenia/fn-with-fungal-risk/antifungal-prophylaxis-aml-mds-prevention-before/fluconazole-prophylaxis-2",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"fn-with-fungal-risk",subcategoryName:"Febrile Neutropenia — Persistent / Fungal Risk",line:"Antifungal Prophylaxis — AML/MDS (Prevention Before FN Episode)",regimen:"Fluconazole 400 mg PO/IV daily (for allogeneic HSCT — engraftment through day +75; for patients with lower IPA risk)",notes:"Fluconazole prophylaxis is recommended for allogeneic HSCT recipients during the engraftment phase (conditioning through day +75 or longer if prolonged neutropenia). Evidence: multiple RCTs demonstrating reduction in candidiasis and candidemia mortality. LIMITATION: NO ASPERGILLUS ACTIVITY — fluconazole does not prevent invasive mold infections. In centers with high Aspergillus prevalence or for patients receiving intensive conditioning (matched unrelated donor, cord blood, haploidentical), posaconazole or voriconazole is preferred. Fluconazole is appropriate for standard myeloablative HSCT in centers with low Aspergillus incidence.",drug:"fluconazole-prophylaxis",evidence:"A-I (for HSCT engraftment phase)",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"febrile-neutropenia/fn-with-fungal-risk/antifungal-prophylaxis-aml-mds-prevention-before/posaconazole-prophylaxis-1",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"fn-with-fungal-risk",subcategoryName:"Febrile Neutropenia — Persistent / Fungal Risk",line:"Antifungal Prophylaxis — AML/MDS (Prevention Before FN Episode)",regimen:"Posaconazole Delayed-Release Tablet (DRT) 300 mg PO daily (load 300 mg BID × 1 day) — PREFERRED over suspension",notes:"IDSA 2010 + NCCN 2024 (Category 1): Posaconazole is the PREFERRED antifungal prophylaxis for AML/MDS patients receiving induction or salvage chemotherapy expected to result in prolonged neutropenia (>7 days). Evidence: Cornely et al. NEJM 2007 — posaconazole reduced IFI (2% vs 8%, p<0.001) and invasive aspergillosis (1% vs 7%, p<0.001) vs fluconazole/itraconazole. DRUG FORMULATION MATTERS: Delayed-release tablet achieves more reliable PK than the suspension (suspension requires high-fat meal and acidic pH for absorption — unreliable in mucositis). Check TDM: target trough ≥0.5–0.7 mcg/mL for prophylaxis (obtain within first week). MAJOR DRUG INTERACTIONS: posaconazole is a strong CYP3A4 inhibitor — increases tacrolimus, cyclosporine, sirolimus, midazolam, statins, vincristine (vincristine neurotoxicity!). Avoid coadministration with rifampin, carbamazepine, phenytoin (reduce posaconazole levels by 80%). CHECK QTCF: posaconazole prolongs QTc — avoid with other QT-prolonging agents if possible.",drug:"posaconazole-prophylaxis",evidence:"A-I",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"febrile-neutropenia/fn-with-fungal-risk/antifungal-prophylaxis-aml-mds-prevention-before/voriconazole-prophylaxis-3",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"fn-with-fungal-risk",subcategoryName:"Febrile Neutropenia — Persistent / Fungal Risk",line:"Antifungal Prophylaxis — AML/MDS (Prevention Before FN Episode)",regimen:"Voriconazole 200 mg PO q12h (avoid high-fat meals; TDM trough target 1.0–5.5 mcg/mL)",notes:"Voriconazole prophylaxis for allogeneic HSCT recipients with high Aspergillus risk (unrelated donor, cord blood, significant GVHD, prolonged steroid use). Evidence: Wingard et al. Blood 2010 — reduced invasive aspergillosis vs fluconazole (1.5% vs 3%, p=0.02) in allogeneic HSCT. Comparable aspergillosis prevention to posaconazole with less favorable tolerability (visual disturbances, hepatotoxicity, phototoxicity, QTc effects). TDM mandatory. IMPORTANT: voriconazole has NO Mucorales activity — if mucormycosis is a concern, choose posaconazole or liposomal amphotericin B. Breakthrough mucormycosis on voriconazole prophylaxis has been reported.",drug:"voriconazole-prophylaxis",evidence:"B-I",evidenceSource:"NCCN 2024",evidenceSourceIds:["nccn-fever-neutropenia"]},{id:"febrile-neutropenia/fn-with-fungal-risk/empiric-antifungal-persistent-fever-day-4-7-if-c/caspofungin-empiric-2",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"fn-with-fungal-risk",subcategoryName:"Febrile Neutropenia — Persistent / Fungal Risk",line:"Empiric Antifungal — Persistent Fever Day 4–7 (If Candida Pattern Suspected)",regimen:"Caspofungin 70 mg IV × 1 load, then 50 mg IV daily",notes:"Alternative echinocandin for empiric antifungal in persistent FN. FDA-approved indication for empiric antifungal in FN (the only echinocandin with this labeled indication, though all are used). Evidence: Walsh 2004 NEJM trial compared caspofungin vs liposomal AmB — caspofungin was non-inferior with better tolerability. More drug interactions than micafungin or anidulafungin (cyclosporine — hepatotoxicity; rifampin — reduces caspofungin levels requiring 70 mg daily maintenance dose). Hepatic dose adjustment: Child-Pugh B → 35 mg daily after load.",drug:"caspofungin-empiric",evidence:"A-I",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"febrile-neutropenia/fn-with-fungal-risk/empiric-antifungal-persistent-fever-day-4-7-if-c/micafungin-empiric-1",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"fn-with-fungal-risk",subcategoryName:"Febrile Neutropenia — Persistent / Fungal Risk",line:"Empiric Antifungal — Persistent Fever Day 4–7 (If Candida Pattern Suspected)",regimen:"Micafungin 100–150 mg IV daily",notes:"PREFERRED empiric antifungal at 4–7 days of persistent FN when: Candida is more likely than Aspergillus (shorter neutropenia duration, solid tumor, prior candidiasis, no new CT chest findings), prior azole prophylaxis use, hemodynamically unstable patient (avoid azoles until stable). Evidence: Walsh et al. NEJM 2004 (caspofungin non-inferior to liposomal AmB). Broad Candida spectrum; NO activity against Aspergillus or Mucorales. Once Candida species identified and susceptibility confirmed: de-escalate to fluconazole 400 mg PO daily if fluconazole-susceptible and patient stable.",drug:"micafungin-empiric",evidence:"A-I",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"febrile-neutropenia/fn-with-fungal-risk/empiric-pre-emptive-antifungal-persistent-fever-/liposomal-amphotericin-empiric-fn-3",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"fn-with-fungal-risk",subcategoryName:"Febrile Neutropenia — Persistent / Fungal Risk",line:"Empiric/Pre-emptive Antifungal — Persistent Fever + Mold Risk (CT Chest Abnormality or Galactomannan Positive)",regimen:"Amphotericin B liposomal (AmBisome) 3 mg/kg IV daily (increase to 5 mg/kg for CNS or severe disease; 5–10 mg/kg for mucormycosis)",notes:"FOR EMPIRIC ANTIFUNGAL: When azoles cannot be used (severe drug interactions, hepatotoxicity, azole-resistant organism suspected) or when Mucorales is the primary concern (CT showing reverse halo sign, sinus/palatal involvement, rhinocerebral extension). WALSH 1999 TRIAL: liposomal AmB equivalent to conventional AmB for empiric FN antifungal with less nephrotoxicity (19% vs 34% creatinine doubling) and fewer infusion reactions. NEPHROTOXICITY MANAGEMENT: Pre-hydrate with 1L NS before each infusion. Aggressive electrolyte replacement (hypokalemia and hypomagnesemia are near-universal). Monitor daily BMP. Avoid concurrent nephrotoxins. Target K+ ≥3.5, Mg2+ ≥1.8 with IV replacement as needed.",drug:"liposomal-amphotericin-empiric-fn",evidence:"A-I",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"febrile-neutropenia/fn-with-fungal-risk/empiric-pre-emptive-antifungal-persistent-fever-/isavuconazole-empiric-fn-2",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"fn-with-fungal-risk",subcategoryName:"Febrile Neutropenia — Persistent / Fungal Risk",line:"Empiric/Pre-emptive Antifungal — Persistent Fever + Mold Risk (CT Chest Abnormality or Galactomannan Positive)",regimen:"Isavuconazonium sulfate (CRESEMBA) 372 mg (= 200 mg isavuconazole) IV/PO q8h × 6 doses over 48 hours (loading phase), then 372 mg IV/PO daily",notes:"ALTERNATIVE to voriconazole for suspected IPA with advantages: (1) No QTc prolongation (shortens QTc — avoid in short QT syndrome), (2) IV without cyclodextrin — safe in all levels of renal impairment, (3) Less visual disturbances, (4) Covers Mucorales (unlike voriconazole) — preferred when diagnosis uncertain between aspergillosis and mucormycosis, (5) Once-daily dosing after load, (6) More predictable pharmacokinetics (TDM less critical but still recommended). Evidence: SECURE trial (Maertens 2016) — non-inferior to voriconazole for primary IPA therapy. NCCN 2024: isavuconazole is preferred by many hematology centers as first-line for IPA due to better tolerability profile.",drug:"isavuconazole-empiric-fn",evidence:"A-I (non-inferior to voriconazole)",evidenceSource:"NCCN 2024",evidenceSourceIds:["nccn-fever-neutropenia"]},{id:"febrile-neutropenia/fn-with-fungal-risk/empiric-pre-emptive-antifungal-persistent-fever-/voriconazole-empiric-fn-1",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"fn-with-fungal-risk",subcategoryName:"Febrile Neutropenia — Persistent / Fungal Risk",line:"Empiric/Pre-emptive Antifungal — Persistent Fever + Mold Risk (CT Chest Abnormality or Galactomannan Positive)",regimen:"Voriconazole 6 mg/kg IV q12h × 2 loading doses, then 4 mg/kg IV q12h; transition to 200 mg PO q12h when stable. TDM trough target 1.0–5.5 mcg/mL.",notes:"PREFERRED for suspected invasive aspergillosis (halo sign on CT, positive galactomannan, prolonged neutropenia >10 days, HSCT recipient, high-dose corticosteroids). Evidence: IDSA 2016 aspergillosis guidelines — voriconazole first-line for IPA. MONITORING: obtain first trough on day 5; check LFTs, visual symptoms, and QTc weekly. MAJOR INTERACTIONS: inhibits CYP2C19/2C9/3A4 — reduce tacrolimus by 66%, cyclosporine by 50%; CONTRAINDICATED with sirolimus, rifampin, carbamazepine. IV formulation contains cyclodextrin vehicle — accumulates in CrCl <50; switch to oral PO if renal impairment develops.",drug:"voriconazole-empiric-fn",evidence:"A-I (for suspected IPA)",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"febrile-neutropenia/fn-with-fungal-risk/mucormycosis-surgical-emergency-antifungal/liposomal-amphotericin-mucor-1",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"fn-with-fungal-risk",subcategoryName:"Febrile Neutropenia — Persistent / Fungal Risk",line:"Mucormycosis — Surgical Emergency + Antifungal",regimen:"Amphotericin B liposomal 5–10 mg/kg IV daily + Urgent surgical debridement + Reverse immunosuppression (reduce steroids, manage hyperglycemia, correct acidosis)",notes:"MUCORMYCOSIS IS A SURGICAL AND MEDICAL EMERGENCY. Any delay in surgical debridement (including rhinosinusitis, orbital involvement, cutaneous necrotizing infection) worsens prognosis dramatically. ANTIFUNGAL: High-dose liposomal AmB (5 mg/kg minimum; some centers use 7.5–10 mg/kg for CNS or disseminated disease). Posaconazole (300 mg PO/IV daily) or isavuconazole (372 mg daily after loading) are step-down options after clinical improvement and surgery. VORICONAZOLE IS INEFFECTIVE AGAINST MUCORALES — do not use. CT imaging of sinuses, orbits, and brain is mandatory. PET/CT may define extent of disease. Correct all predisposing factors: hyperglycemia, acidosis (DKA predisposes), iron overload (deferasirox has in vitro anti-Mucorales activity; clinical benefit uncertain), reduce steroids as much as oncologically acceptable. Adjunctive hyperbaric oxygen — limited data, center-specific.",drug:"liposomal-amphotericin-mucor",evidence:"A-II (AmB) + surgical (mandatory)",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"febrile-neutropenia/fn-with-fungal-risk/pcp-pneumocystis-jirovecii-pneumonia-prophylaxis/tmp-smx-pcp-1",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"fn-with-fungal-risk",subcategoryName:"Febrile Neutropenia — Persistent / Fungal Risk",line:"PCP (Pneumocystis jirovecii Pneumonia) — Prophylaxis and Treatment",regimen:"TMP-SMX (Bactrim DS) 1 DS tablet (160/800 mg) PO daily OR 1 SS tablet daily OR 1 DS tablet PO TIW — PROPHYLAXIS. TMP-SMX 15–20 mg/kg/day IV (of TMP component) divided q6–8h — TREATMENT",notes:"PCP PROPHYLAXIS: Required for patients on ≥20 mg/day of prednisone equivalent for ≥1 month, patients with CD4 <200 (HIV+), HSCT recipients (through day +180 or longer with ongoing immunosuppression), patients receiving temozolomide, fludarabine, or other T-cell depleting agents. TMP-SMX is first-line prophylaxis — also provides prophylaxis against Toxoplasma and bacterial infections. ALTERNATIVES for TMP-SMX intolerance: Dapsone 100 mg PO daily (check G6PD first), atovaquone 1500 mg PO daily with fatty food, inhaled pentamidine 300 mg monthly via Respigard nebulizer. TREATMENT of confirmed PCP: TMP-SMX 15–20 mg/kg/day IV × 21 days + prednisone 40 mg BID × 5 days then taper (if PaO2 <70 mmHg or A-a gradient >35). TOXICITY: Myelosuppression, renal impairment, hypersensitivity (rash, fever, SJS — rare). Monitoring: CBC weekly, CMP.",drug:"tmp-smx-pcp",evidence:"A-I (prophylaxis)",evidenceSource:"NCCN 2024",evidenceSourceIds:["nccn-fever-neutropenia"]},{id:"febrile-neutropenia/high-risk-fn/add-antifungal-persistent-fever-4-7-days-despite/liposomal-amphotericin-fn-3",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"high-risk-fn",subcategoryName:"High-Risk Febrile Neutropenia",line:"ADD Antifungal — Persistent Fever >4–7 Days Despite Antibiotics",regimen:"Amphotericin B liposomal (AmBisome) 3 mg/kg IV daily",notes:"FOR EMPIRIC ANTIFUNGAL when echinocandin and azole are both contraindicated, or when Mucorales (mucormycosis) is suspected (CT chest showing reverse halo sign, rhinocerebral extension). Voriconazole has NO Mucorales activity — use amphotericin B or isavuconazole for suspected mucormycosis. NEPHROTOXICITY MONITORING: daily BMP (creatinine, potassium, magnesium, sodium). Pre-hydration with 1L NS reduces nephrotoxicity. Hypokalemia and hypomagnesemia are nearly universal — supplement aggressively. Avoid concurrent nephrotoxins (vancomycin, aminoglycosides, calcineurin inhibitors) when possible.",drug:"liposomal-amphotericin-fn",evidence:"A-I (Walsh 1999 trial)",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"febrile-neutropenia/high-risk-fn/add-antifungal-persistent-fever-4-7-days-despite/micafungin-fn-1",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"high-risk-fn",subcategoryName:"High-Risk Febrile Neutropenia",line:"ADD Antifungal — Persistent Fever >4–7 Days Despite Antibiotics",regimen:"Micafungin 100–150 mg IV daily (echinocandin preferred if Candida suspected)",notes:"EMPIRIC ANTIFUNGAL: Add after 4–7 days of persistent fever despite adequate antibacterial therapy, in the setting of prolonged neutropenia. Echinocandin (micafungin, caspofungin, anidulafungin) preferred when: (1) Prior azole exposure or prophylaxis, (2) Hemodynamic instability, (3) Candida species unknown. Micafungin 100 mg daily (standard); 150 mg daily for higher-risk patients (obese, hematologic malignancy, critically ill). PRE-EMPTIVE STRATEGY: Many centers now use BDG and serum galactomannan at day 4–5 of persistent fever to guide antifungal initiation rather than fever duration alone — this reduces unnecessary antifungal therapy by 20–30% without compromising outcomes. BDG >80 pg/mL or serum GM >0.5 ODI supports antifungal initiation. Duration: minimum 14 days for candidemia from first negative blood culture; 6–12 weeks for invasive aspergillosis.",drug:"micafungin-fn",evidence:"A-I (Walsh 2004 trial)",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"febrile-neutropenia/high-risk-fn/add-antifungal-persistent-fever-4-7-days-despite/voriconazole-fn-2",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"high-risk-fn",subcategoryName:"High-Risk Febrile Neutropenia",line:"ADD Antifungal — Persistent Fever >4–7 Days Despite Antibiotics",regimen:"Voriconazole 6 mg/kg IV q12h × 2 loading doses, then 4 mg/kg IV q12h; OR 200 mg PO q12h (if able to take orally)",notes:"PREFERRED when Aspergillus (or other mold) is suspected: CT chest showing halo sign, nodules, or cavitary lesions; prolonged neutropenia >10 days; HSCT recipient. Voriconazole covers Aspergillus fumigatus, A. flavus, A. niger (but NOT Mucorales). THERAPEUTIC DRUG MONITORING mandatory: target trough 1.0–5.5 mcg/mL. Supratherapeutic levels → hepatotoxicity, visual disturbances, encephalopathy. Subtherapeutic → treatment failure. SIGNIFICANT DRUG INTERACTIONS: inhibits CYP2C19, CYP2C9, CYP3A4 — major interactions with tacrolimus (reduce dose 66%), cyclosporine (reduce dose 50%), sirolimus (CONTRAINDICATED), carbamazepine, rifampin, phenytoin. Avoid in patients with CrCl <50 if using IV formulation (cyclodextrin vehicle accumulates; switch to PO).",drug:"voriconazole-fn",evidence:"A-I (for suspected aspergillosis)",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"febrile-neutropenia/high-risk-fn/add-metronidazole-for-suspected-anaerobic-intra-/metronidazole-fn-1",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"high-risk-fn",subcategoryName:"High-Risk Febrile Neutropenia",line:"ADD Metronidazole — For Suspected Anaerobic/Intra-Abdominal Source",regimen:"Metronidazole 500mg IV q8h (or 1g IV q12h for extended infusion)",notes:"Add anaerobic coverage when: (1) Typhlitis (neutropenic enterocolitis) — RLQ pain + fever in neutropenic patient; CT-confirmed bowel wall thickening. (2) Perirectal abscess (do NOT perform digital rectal exam — can introduce bacteremia; use imaging). (3) Intra-abdominal source (diverticulitis, appendicitis). (4) Oral/dental source with suspected anaerobic involvement. NOTE: Piperacillin-tazobactam already has anaerobic coverage — metronidazole is redundant and should NOT be added if pip-tazo is the backbone agent. Add metronidazole only when cefepime or meropenem is used as the primary antipseudomonal agent in suspected anaerobic infection.",drug:"metronidazole-fn",evidence:"B-III",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"febrile-neutropenia/high-risk-fn/add-mrsa-coverage-specific-high-risk-scenarios/daptomycin-fn-2",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"high-risk-fn",subcategoryName:"High-Risk Febrile Neutropenia",line:"ADD MRSA Coverage — Specific High-Risk Scenarios",regimen:"Daptomycin 6–10 mg/kg IV daily (higher doses for bacteremia/endocarditis)",notes:"ALTERNATIVE to vancomycin for gram-positive/MRSA coverage when: vancomycin MIC ≥2 (vancomycin heteroresistance), vancomycin nephrotoxicity, prior vancomycin failure, or concurrent nephrotoxic drug combinations. CONTRAINDICATED for pneumonia — daptomycin is inactivated by pulmonary surfactant. Monitor CPK weekly (myopathy risk, especially at higher doses). No need for TDM, but CPK monitoring essential.",drug:"daptomycin-fn",evidence:"B-II",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"febrile-neutropenia/high-risk-fn/add-mrsa-coverage-specific-high-risk-scenarios/vancomycin-mrsa-fn-1",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"high-risk-fn",subcategoryName:"High-Risk Febrile Neutropenia",line:"ADD MRSA Coverage — Specific High-Risk Scenarios",regimen:"Vancomycin IV (AUC/MIC 400–600) — see dosing above",notes:"ADD vancomycin for MRSA-specific coverage in: (1) Hemodynamic instability (septic shock) — until source clarified. (2) Skin or soft tissue infection (SSTI) with MRSA risk factors. (3) Central catheter infection with purulence/tunnel tract involvement. (4) Prior MRSA colonization or infection. (5) Chest CT showing necrotizing pneumonia or cavitary lesion consistent with MRSA. Discontinue at 48–72h if no MRSA/gram-positive pathogen confirmed. AUC-guided dosing is the standard — do not use trough-only monitoring.",drug:"vancomycin-mrsa-fn",evidence:"A-I",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"febrile-neutropenia/high-risk-fn/add-vancomycin-only-if-specific-indications-pres/vancomycin-fn-1",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"high-risk-fn",subcategoryName:"High-Risk Febrile Neutropenia",line:"ADD Vancomycin — Only If Specific Indications Present (IDSA 2010, A-I)",regimen:"Vancomycin 25–30 mg/kg IV loading dose (actual body weight, max 3g), then 15–20 mg/kg IV q8–12h (AUC/MIC target 400–600 mcg·h/mL using Bayesian software)",notes:"IDSA 2010 (A-I): Vancomycin should NOT be routinely added to empiric FN therapy. Evidence shows routine addition of vancomycin does NOT improve outcomes, increases nephrotoxicity risk, and prolongs therapy duration unnecessarily. ADD VANCOMYCIN ONLY FOR THE FOLLOWING INDICATIONS: (1) Clinically apparent catheter-related infection (exit site erythema/discharge, tunneled catheter tenderness, positive blood cultures flagging from catheter before peripheral). (2) Skin or soft tissue infection (cellulitis, wound infection). (3) Hemodynamic instability or suspected septic shock (broader empiric coverage until source identified). (4) Blood cultures positive for gram-positive organisms (add while awaiting species ID and susceptibilities). (5) Suspected mucositis-associated viridans streptococcal sepsis (NCI grade 3–4 mucositis + severe sepsis picture). (6) Known MRSA colonization with new pulmonary infiltrates or bacteremia. REASSESSMENT AT 48–72H: Discontinue vancomycin if no gram-positive pathogen isolated and patient improving (A-II). AUC-GUIDED DOSING: 2020 ASHP/IDSA/SIDP consensus guidelines mandate AUC/MIC 400–600 monitoring over trough-based dosing — use Bayesian software (e.g., InsightRx, Vanderbilt AUC calculator).",drug:"vancomycin-fn",evidence:"A-I",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"febrile-neutropenia/high-risk-fn/aminoglycoside-do-not-use-as-routine-combination/amikacin-fn-1",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"high-risk-fn",subcategoryName:"High-Risk Febrile Neutropenia",line:"Aminoglycoside — Do NOT Use as Routine Combination (A-I, Not Recommended)",regimen:"Amikacin 15–20 mg/kg IV once daily (extended-interval dosing) — ONLY if specific documented resistance scenario",notes:"IDSA 2010 (A-I): Aminoglycoside combination therapy with antipseudomonal beta-lactams is NOT recommended for routine FN empiric therapy. No mortality benefit from combination in RCTs; significantly higher nephrotoxicity and ototoxicity with combination therapy. SPECIFIC INDICATIONS (narrow): (1) Documented gram-negative bacteremia with resistant organism susceptible only to aminoglycoside + another agent (e.g., CRE with limited options), (2) Suspected Pseudomonas with carbapenem resistance and aminoglycoside susceptibility confirmed. Extended-interval dosing (15–20 mg/kg once daily) is standard; goal peak 56–64 mcg/mL and trough <1 mcg/mL (gentamicin/tobramycin: 5–7 mg/kg daily, peak 20–30, trough <1). Avoid in patients with CrCl <60 — dose adjustment required and toxicity risk high.",drug:"amikacin-fn",evidence:"A-I (not recommended routinely)",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"febrile-neutropenia/high-risk-fn/g-csf-adjunctive-therapy-for-selected-high-risk-/filgrastim-fn-1",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"high-risk-fn",subcategoryName:"High-Risk Febrile Neutropenia",line:"G-CSF — Adjunctive Therapy for Selected High-Risk FN",regimen:"Filgrastim (G-CSF) 5 mcg/kg/day SC (round to nearest vial: 300 mcg or 480 mcg) until ANC ≥1000–2000 cells/μL post-nadir; OR Pegfilgrastim 6 mg SC × 1 dose (NOT for acute FN treatment — prophylaxis only)",notes:"IDSA/ASCO G-CSF GUIDANCE: Therapeutic G-CSF (during FN episode) is recommended for patients with HIGH-RISK features: (1) Expected prolonged neutropenia >10 days, (2) Age >65, (3) Uncontrolled/progressive malignancy, (4) Documented pneumonia, septic shock, or invasive fungal infection, (5) Prior FN episode. G-CSF shortens duration of neutropenia by 1–3 days and reduces infectious complications. NOT universally recommended for all FN — low-risk patients with expected rapid ANC recovery do not clearly benefit. PEGFILGRASTIM TIMING: If patient received pegfilgrastim ≤14 days before current FN episode, the depot effect may still be active — check timing before re-administering. PRIMARY PROPHYLAXIS: Filgrastim or pegfilgrastim recommended when FN risk from chemotherapy regimen is ≥20%. SECONDARY PROPHYLAXIS: After a prior FN episode, G-CSF in subsequent cycles maintains dose intensity.",drug:"filgrastim-fn",evidence:"A-I (high-risk features)",evidenceSource:"NCCN 2024",evidenceSourceIds:["nccn-fever-neutropenia"]},{id:"febrile-neutropenia/high-risk-fn/monotherapy-antipseudomonal-beta-lactam-idsa-201/cefepime-1",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"high-risk-fn",subcategoryName:"High-Risk Febrile Neutropenia",line:"Monotherapy — Antipseudomonal Beta-Lactam (IDSA 2010 First-Line, A-I)",regimen:"Cefepime 2g IV q8h",notes:"IDSA 2010 preferred first-line monotherapy (A-I). Fourth-generation cephalosporin with excellent antipseudomonal activity and broad gram-negative + gram-positive spectrum. Does NOT cover MRSA, Enterococcus, or anaerobes. DOSING NOTE: 2g q8h is the standard for FN; continuous infusion (6g over 24h by elastomeric pump) has pharmacodynamic advantages for organisms with higher MICs. RENAL DOSING: CrCl 30–60 → 1–2g q12h; CrCl 11–29 → 1–2g q24h; HD → 0.5–1g after each HD session. CNS TOXICITY RISK: neurotoxicity (encephalopathy, myoclonus, seizures) at higher exposures — especially in renal failure. Monitor closely in elderly and renally impaired patients. Consider EEG if altered mental status develops on cefepime.",drug:"cefepime",monographId:"cefepime",evidence:"A-I",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"febrile-neutropenia/high-risk-fn/monotherapy-antipseudomonal-beta-lactam-idsa-201/meropenem-3",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"high-risk-fn",subcategoryName:"High-Risk Febrile Neutropenia",line:"Monotherapy — Antipseudomonal Beta-Lactam (IDSA 2010 First-Line, A-I)",regimen:"Meropenem 1g IV q8h (2g IV q8h for Pseudomonas or suspected resistant organisms)",notes:"IDSA 2010 alternative first-line monotherapy (A-I). Reserve as the broadest coverage option — covers Pseudomonas, ESBL producers, AmpC producers, anaerobes, streptococci. Preferred as empiric first-line in: (1) Patients with prior gram-negative bacteremia due to ESBL-producing organisms, (2) Recent hospitalization in regions with high ESBL prevalence, (3) Clinically unstable or septic shock presentations where broadest coverage is critical, (4) Suspected typhlitis or abdominal source. STEWARDSHIP NOTE: Carbapenems should not be used routinely as first-line when cefepime or pip-tazo are appropriate — carbapenem overuse drives carbapenem-resistant Enterobacterales (CRE) emergence. RENAL DOSING: CrCl 26–50 → 1g q12h; CrCl 10–25 → 500mg q12h; CrCl <10/HD → 500mg q24h.",drug:"meropenem",monographId:"meropenem",evidence:"A-I",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"febrile-neutropenia/high-risk-fn/monotherapy-antipseudomonal-beta-lactam-idsa-201/piperacillin-tazobactam-2",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"high-risk-fn",subcategoryName:"High-Risk Febrile Neutropenia",line:"Monotherapy — Antipseudomonal Beta-Lactam (IDSA 2010 First-Line, A-I)",regimen:"Piperacillin-Tazobactam 4.5g IV q6h (or 3.375g IV q6h for less severe)",notes:"IDSA 2010 alternative first-line monotherapy (A-I). Broad-spectrum: antipseudomonal + anaerobic coverage + good gram-positive activity. Particularly advantageous when typhlitis, perirectal infection, or intra-abdominal source is suspected (anaerobic coverage included). Standard dosing: 4.5g IV q6h; extended infusion (3-hour infusion of 3.375g q8h or 4.5g q8h) pharmacodynamically superior for organisms with higher MICs — consider for critically ill patients or when Pseudomonas susceptibility is borderline. RENAL DOSING: CrCl 20–40 → 3.375g q8h; CrCl <20/HD → 2.25g q8h (additional 0.75g after HD). GALACTOMANNAN FALSE POSITIVES: pip-tazo can cause false-positive serum galactomannan — interpret serum GM cautiously in patients on pip-tazo; BAL GM preferred if pulmonary aspergillosis suspected.",drug:"piperacillin-tazobactam",evidence:"A-I",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"febrile-neutropenia/low-risk-fn/beta-lactam-allergy-low-risk/aztreonam-fn-1",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"low-risk-fn",subcategoryName:"Low-Risk Febrile Neutropenia",line:"Beta-Lactam Allergy — Low Risk",regimen:"Aztreonam 2g IV q8h + Vancomycin 15–20 mg/kg IV q8–12h (for severe penicillin allergy precluding all beta-lactams)",notes:"For patients with documented severe IgE-mediated penicillin allergy where cross-reactivity with cephalosporins is a concern. Aztreonam provides gram-negative (including Pseudomonas) coverage. Add vancomycin for gram-positive coverage. Note: cross-reactivity between penicillin and cephalosporins is <1–2% in patients with confirmed penicillin allergy (sIgE to penicillin determinants). Most 'penicillin-allergic' patients can safely receive cefepime — consider allergy reconciliation before defaulting to aztreonam-based regimens.",drug:"aztreonam-fn",evidence:"B-III",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"febrile-neutropenia/low-risk-fn/first-line-oral-outpatient-idsa-2010-a-i-for-low/cipro-amox-clav-1",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"low-risk-fn",subcategoryName:"Low-Risk Febrile Neutropenia",line:"First-Line — Oral Outpatient (IDSA 2010, A-I for low-risk)",regimen:"Ciprofloxacin 500–750 mg PO q12h + Amoxicillin-Clavulanate 875/125 mg PO q12h",notes:"IDSA 2010 (Evidence: A-I). The STANDARD oral regimen for low-risk FN. Evidence basis: Freifeld et al. NEJM 1999 RCT. Ciprofloxacin provides antipseudomonal and gram-negative coverage; amoxicillin-clavulanate adds streptococcal coverage (viridans streptococcal risk from mucositis) and broadens spectrum. CRITICAL: This combination is essential — ciprofloxacin monotherapy is INADEQUATE (poor streptococcal coverage; viridans streptococcal bacteremia from mucositis can be rapidly fatal). Duration: continue until ANC ≥500 and afebrile ≥48h. IMPORTANT CAVEAT: If patient received fluoroquinolone prophylaxis, do NOT use ciprofloxacin as empiric therapy — consider IV antipseudomonal beta-lactam instead (risk of breakthrough infection with resistant organisms).",drug:"cipro-amox-clav",evidence:"A-I",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"febrile-neutropenia/low-risk-fn/first-line-oral-outpatient-idsa-2010-a-i-for-low/levofloxacin-oral-2",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"low-risk-fn",subcategoryName:"Low-Risk Febrile Neutropenia",line:"First-Line — Oral Outpatient (IDSA 2010, A-I for low-risk)",regimen:"Levofloxacin 750 mg PO daily (if ciprofloxacin + amox-clav not tolerated)",notes:"Alternative for patients who cannot tolerate the combination regimen. Levofloxacin 750 mg daily provides broader spectrum than ciprofloxacin alone, including better streptococcal coverage. However, FDA fluoroquinolone safety label (2016): boxed warnings for tendinopathy, peripheral neuropathy, CNS effects, and aortic aneurysm — use with appropriate clinical judgment. SAME CAVEAT: do not use if patient was on fluoroquinolone prophylaxis. Evidence: B-II (IDSA 2010).",drug:"levofloxacin-oral",evidence:"B-II",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"febrile-neutropenia/low-risk-fn/initial-iv-if-cannot-immediately-discharge-obser/cefepime-initial-1",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"low-risk-fn",subcategoryName:"Low-Risk Febrile Neutropenia",line:"Initial IV (If Cannot Immediately Discharge — Observe and Step Down)",regimen:"Cefepime 2g IV q8h × first 2–4 hours during ED/clinic evaluation, then step down to oral if criteria met",notes:"For low-risk patients presenting to ED who are started on IV empirically: initiate cefepime or pip-tazo IV while cultures are collected and risk stratification is completed. If MASCC ≥21 and all outpatient criteria met after 2–4h of observation → transition to oral ciprofloxacin + amoxicillin-clavulanate. Do not delay oral step-down for low-risk patients who meet criteria. IV continuation not required and increases healthcare costs and risks (line infections, hospital-acquired complications).",drug:"cefepime-initial",evidence:"B-II",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"fungal-infections/antifungal-stewardship/stewardship-echinocandin-to-fluconazole-de-escal/fluconazole-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"antifungal-stewardship",subcategoryName:"Antifungal Stewardship & De-escalation",line:"Stewardship — Echinocandin-to-Fluconazole De-escalation",regimen:"Switch echinocandin → fluconazole 400 mg PO daily",notes:"CRITERIA FOR SAFE DE-ESCALATION: (1) Candida species confirmed susceptible to fluconazole (C. albicans, C. tropicalis, C. parapsilosis with MIC ≤2), (2) patient clinically improving (afebrile, hemodynamically stable, off vasopressors), (3) blood cultures clearing, (4) no metastatic complications (endophthalmitis, endocarditis, osteomyelitis), (5) able to tolerate oral medications. Average time to de-escalation: 5–7 days. This is the single highest-impact antifungal stewardship intervention.",drug:"fluconazole",monographId:"fluconazole"},{id:"fungal-infections/antifungal-stewardship/stewardship-iv-to-po-azole-conversion/fluconazole-2",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"antifungal-stewardship",subcategoryName:"Antifungal Stewardship & De-escalation",line:"Stewardship — IV-to-PO Azole Conversion",regimen:"Switch fluconazole IV → same dose PO",notes:"Fluconazole oral bioavailability ~90%. Same dose IV and PO. One of the easiest IV-to-PO conversions in all of infectious disease. No food restrictions. Pharmacy should proactively recommend this conversion.",drug:"fluconazole",monographId:"fluconazole"},{id:"fungal-infections/antifungal-stewardship/stewardship-iv-to-po-azole-conversion/voriconazole-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"antifungal-stewardship",subcategoryName:"Antifungal Stewardship & De-escalation",line:"Stewardship — IV-to-PO Azole Conversion",regimen:"Switch voriconazole IV → voriconazole 200 mg PO q12h",notes:"Voriconazole oral bioavailability >96% — IV offers no pharmacokinetic advantage over PO. Switch as soon as patient can tolerate oral medications. IMPORTANT: Avoid taking with high-fat meals (reduces absorption by 34%). Also: PO tablets may actually give MORE predictable levels than IV in patients with renal impairment (avoids cyclodextrin accumulation).",drug:"voriconazole",monographId:"voriconazole"},{id:"fungal-infections/antifungal-stewardship/stewardship-prophylaxis-review/fluconazole-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"antifungal-stewardship",subcategoryName:"Antifungal Stewardship & De-escalation",line:"Stewardship — Prophylaxis Review",regimen:"Review appropriateness of antifungal prophylaxis",notes:"Appropriate prophylaxis: (1) Fluconazole 400 mg daily for allogeneic HSCT (engraftment through day +75), (2) Posaconazole 300 mg daily for AML/MDS induction chemotherapy with expected neutropenia >7 days, (3) Fluconazole 400 mg daily for high-risk liver transplant recipients. INAPPROPRIATE (common): continuing prophylaxis beyond risk period, prophylaxis in ICU patients without neutropenia (routine fluconazole in surgical ICU not recommended by guidelines), prophylaxis based solely on positive BDG without clinical correlation.",drug:"fluconazole",monographId:"fluconazole"},{id:"fungal-infections/antifungal-stewardship/stewardship-tdm-optimization/voriconazole-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"antifungal-stewardship",subcategoryName:"Antifungal Stewardship & De-escalation",line:"Stewardship — TDM Optimization",regimen:"Voriconazole trough target: 1.0–5.5 mcg/mL",notes:"TDM schedule: Day 5 (steady state), then weekly until therapeutic and stable, then with dose changes, interacting drug changes, or clinical failure. Subtherapeutic (<1.0): Increase dose by 50%. Supratherapeutic (>5.5): Hold 1 dose, reduce by 50%, recheck in 3–5 days. CYP2C19 genotyping: Consider in patients with extreme levels despite standard dosing (PM vs UM phenotype). Posaconazole: Trough >1.0 mcg/mL for prophylaxis, >1.0–1.5 for treatment. Itraconazole: Trough >0.5 for prophylaxis, >1.0 for treatment.",drug:"voriconazole",monographId:"voriconazole"},{id:"fungal-infections/candidemia/alternative-de-escalation-fluconazole-susceptibl/fluconazole-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"candidemia",subcategoryName:"Candidemia & Invasive Candidiasis",line:"Alternative — De-escalation / Fluconazole-Susceptible",regimen:"Fluconazole 800 mg (12 mg/kg) IV/PO load × 1, then 400 mg (6 mg/kg) IV/PO daily",notes:"STEP-DOWN therapy once: (1) patient is clinically stable, (2) Candida species confirmed susceptible (MIC ≤2 mcg/mL), (3) blood cultures are clearing, (4) no metastatic complications. Loading dose is critical and frequently omitted. IV-to-PO switch: bioavailability is ~90%, so same dose PO. NOT appropriate for C. glabrata (dose-dependent susceptibility), C. krusei (intrinsically resistant), or critically ill patients on vasopressors.",drug:"fluconazole",monographId:"fluconazole"},{id:"fungal-infections/candidemia/duration-source-control/option-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"candidemia",subcategoryName:"Candidemia & Invasive Candidiasis",line:"Duration & Source Control",regimen:"Duration: 14 days from FIRST NEGATIVE blood culture + resolution of symptoms/signs",notes:"CVC removal: Strongly recommended within 24–48 hours when feasible. CVC retention is associated with higher mortality and prolonged candidemia. If CVC cannot be removed (e.g., limited access), ensure echinocandin therapy and consider locking solutions for biofilm. Ophthalmologic exam: Within 1 week of diagnosis in non-neutropenic patients, within 1 week of neutrophil recovery in neutropenic patients. If endophthalmitis present: extend treatment to ≥4–6 weeks and consider intravitreal amphotericin B."},{id:"fungal-infections/candidemia/preferred-first-line-empiric/anidulafungin-3",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"candidemia",subcategoryName:"Candidemia & Invasive Candidiasis",line:"Preferred — First-Line Empiric",regimen:"Anidulafungin 200 mg IV load × 1, then 100 mg IV daily",notes:"Third echinocandin option. Best evidence from the Reboli NEJM 2007 trial. No hepatic or renal dose adjustment needed. Non-enzymatic degradation (no CYP metabolism) means fewest drug interactions of the echinocandins. Preferred when drug interactions are a concern.",drug:"anidulafungin"},{id:"fungal-infections/candidemia/preferred-first-line-empiric/caspofungin-2",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"candidemia",subcategoryName:"Candidemia & Invasive Candidiasis",line:"Preferred — First-Line Empiric",regimen:"Caspofungin 70 mg IV load × 1, then 50 mg IV daily",notes:"Alternative echinocandin. Equivalent efficacy to micafungin. Loading dose required on day 1. More drug interactions (cyclosporine — hepatotoxicity risk, rifampin — reduces caspofungin levels). Dose adjust for hepatic impairment (Child-Pugh B: 35 mg daily after load).",drug:"caspofungin"},{id:"fungal-infections/candidemia/preferred-first-line-empiric/micafungin-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"candidemia",subcategoryName:"Candidemia & Invasive Candidiasis",line:"Preferred — First-Line Empiric",regimen:"Micafungin 100 mg IV once daily",notes:"IDSA 2016 first-line for candidemia regardless of severity or species. Echinocandins preferred over fluconazole because: (1) broader spectrum covering C. glabrata and C. krusei, (2) fungicidal vs. fungistatic, (3) better outcomes in RCTs (Reboli 2007). Continue until species identification and susceptibility allow de-escalation.",drug:"micafungin",monographId:"micafungin"},{id:"fungal-infections/candidemia/reserve-amphotericin-b/amphotericin-b-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"candidemia",subcategoryName:"Candidemia & Invasive Candidiasis",line:"Reserve — Amphotericin B",regimen:"Amphotericin B liposomal (AmBisome) 3–5 mg/kg IV daily",notes:"Reserve for: (1) echinocandin-resistant Candida (rare but increasing), (2) CNS candidiasis (echinocandins do not penetrate CNS), (3) endocarditis (in combination), (4) C. auris with pan-echinocandin resistance. Always use LIPID formulation — conventional amphotericin B deoxycholate has unacceptable nephrotoxicity. Monitor: daily BMP (creatinine, potassium, magnesium), CBC.",drug:"amphotericin-b",monographId:"amphotericin-b"},{id:"fungal-infections/cryptococcal-meningitis/adjunctive-icp-management/option-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"cryptococcal-meningitis",subcategoryName:"Cryptococcal Meningitis",line:"Adjunctive — ICP Management",regimen:"Therapeutic lumbar punctures: daily or as needed to maintain opening pressure <20 cmH2O",notes:"ELEVATED ICP IS THE PRIMARY KILLER in cryptococcal meningitis. Aggressive pressure management with serial LPs is essential. Remove enough CSF to achieve OP <20 or 50% reduction. VP shunt or lumbar drain for refractory elevated ICP. DO NOT use corticosteroids for ICP management in cryptococcal meningitis — the Day et al. NEJM 2014 trial showed dexamethasone INCREASED mortality."},{id:"fungal-infections/cryptococcal-meningitis/alternative-induction-resource-limited/fluconazole-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"cryptococcal-meningitis",subcategoryName:"Cryptococcal Meningitis",line:"Alternative — Induction (Resource-Limited)",regimen:"Fluconazole 1200 mg PO daily + Flucytosine 25 mg/kg PO q6h × 2 weeks",notes:"ACTHUNG trial: High-dose fluconazole + flucytosine is the best oral-only induction option. Faster CSF sterilization than fluconazole monotherapy. Important in resource-limited settings without amphotericin B access. Also validated: single high-dose amphotericin B liposomal (10 mg/kg × 1) + flucytosine + fluconazole (AMBITION trial) as simplified induction.",drug:"fluconazole",monographId:"fluconazole"},{id:"fungal-infections/cryptococcal-meningitis/consolidation-week-2-10/fluconazole-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"cryptococcal-meningitis",subcategoryName:"Cryptococcal Meningitis",line:"Consolidation (Week 2–10)",regimen:"Fluconazole 400–800 mg PO daily × 8 weeks",notes:"Begin after successful 2-week induction (clinical improvement, CSF sterilizing). Higher dose (800 mg) preferred in HIV patients. Continue with ART optimization — but timing of ART initiation is critical (see pearls).",drug:"fluconazole",monographId:"fluconazole"},{id:"fungal-infections/cryptococcal-meningitis/maintenance-week-10/fluconazole-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"cryptococcal-meningitis",subcategoryName:"Cryptococcal Meningitis",line:"Maintenance (Week 10+)",regimen:"Fluconazole 200 mg PO daily — continue until CD4 >100 × 1 year + undetectable viral load",notes:"Secondary prophylaxis. Can discontinue once immune reconstitution achieved: CD4 >100 for ≥1 year on ART with suppressed viral load. If CD4 drops below 100 again, restart maintenance fluconazole.",drug:"fluconazole",monographId:"fluconazole"},{id:"fungal-infections/cryptococcal-meningitis/preferred-induction-hiv-associated/amphotericin-b-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"cryptococcal-meningitis",subcategoryName:"Cryptococcal Meningitis",line:"Preferred — Induction (HIV-associated)",regimen:"Amphotericin B liposomal 3–4 mg/kg IV daily + Flucytosine 25 mg/kg PO q6h × 2 weeks",notes:"ACTHUNG trial + AMBITION trial evidence. Amphotericin B + flucytosine is the MOST EFFECTIVE induction regimen, achieving the fastest CSF sterilization (~1 week). Flucytosine is critical — do NOT omit. If flucytosine unavailable, amphotericin B + fluconazole 800 mg daily is an alternative but inferior induction. Monitor flucytosine levels (target peak 30–80 mcg/mL), CBC (myelosuppression), and renal function daily.",drug:"amphotericin-b",monographId:"amphotericin-b"},{id:"fungal-infections/invasive-aspergillosis/alternative-echinocandin-combination/micafungin-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"invasive-aspergillosis",subcategoryName:"Invasive Pulmonary Aspergillosis",line:"Alternative — Echinocandin Combination",regimen:"Voriconazole (standard dosing) + Micafungin 150 mg IV daily OR Caspofungin 70/50 mg IV daily",notes:"Combination therapy based on Marr 2015 trial: trend toward mortality benefit (19.3% vs 27.5%) that was not statistically significant overall, but subgroup with galactomannan-positive IA showed significant benefit. Consider combination in: (1) proven/probable IA with high fungal burden, (2) breakthrough on azole prophylaxis, (3) hematologic malignancy with prolonged neutropenia. NOT universally recommended — discuss with ID.",drug:"micafungin",monographId:"micafungin"},{id:"fungal-infections/invasive-aspergillosis/alternative-first-line/isavuconazole-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"invasive-aspergillosis",subcategoryName:"Invasive Pulmonary Aspergillosis",line:"Alternative — First-Line",regimen:"Isavuconazonium sulfate 372 mg (= 200 mg isavuconazole) IV/PO q8h × 6 doses (48 hr loading), then 372 mg IV/PO daily",notes:"Non-inferior to voriconazole per SECURE trial (Maertens 2016). KEY ADVANTAGES: (1) no QTc prolongation (SHORTENS QT — avoid if baseline short QT syndrome), (2) IV formulation WITHOUT cyclodextrin (safe in renal impairment), (3) fewer visual disturbances, (4) less hepatotoxicity, (5) more predictable PKs (TDM less critical but still recommended in some populations). ALSO active against Mucorales (unlike voriconazole) — useful when diagnosis uncertain between aspergillosis and mucormycosis. Becoming many centers' preferred first-line over voriconazole.",drug:"isavuconazole"},{id:"fungal-infections/invasive-aspergillosis/duration-monitoring/option-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"invasive-aspergillosis",subcategoryName:"Invasive Pulmonary Aspergillosis",line:"Duration & Monitoring",regimen:"Minimum 6–12 weeks; continue until resolution of immunosuppression + radiographic improvement",notes:"Duration highly individualized. Minimum 6 weeks even with good response. In HSCT patients or those with ongoing immunosuppression, treatment often continues for months. Serial GM and CT chest q2–4 weeks to monitor response. IMMUNE RECONSTITUTION: neutrophil recovery is the most important prognostic factor. G-CSF and reduction of immunosuppression should be aggressively pursued. Secondary prophylaxis: after completing treatment, consider maintenance voriconazole/isavuconazole during subsequent immunosuppressive cycles."},{id:"fungal-infections/invasive-aspergillosis/preferred-first-line/voriconazole-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"invasive-aspergillosis",subcategoryName:"Invasive Pulmonary Aspergillosis",line:"Preferred — First-Line",regimen:"Voriconazole 6 mg/kg IV q12h × 2 doses (load), then 4 mg/kg IV q12h; PO: 200 mg q12h (≥40 kg)",notes:"IDSA 2016 first-line based on Herbrecht 2002 NEJM trial. THERAPEUTIC DRUG MONITORING IS MANDATORY — target trough 1.0–5.5 mcg/mL. Subtherapeutic levels (<1.0) associated with treatment failure, supratherapeutic (>5.5) associated with hepatotoxicity and neurotoxicity. Highly variable pharmacokinetics (CYP2C19 polymorphisms). Obtain first trough on day 5 of therapy. IV formulation contains sulfobutyl ether β-cyclodextrin (SBECD) — accumulates in CrCl <50, switch to PO if possible (PO bioavailability >96%).",drug:"voriconazole",monographId:"voriconazole"},{id:"fungal-infections/invasive-aspergillosis/salvage-therapy/amphotericin-b-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"invasive-aspergillosis",subcategoryName:"Invasive Pulmonary Aspergillosis",line:"Salvage Therapy",regimen:"Amphotericin B liposomal (AmBisome) 3–5 mg/kg IV daily",notes:"Salvage for voriconazole/isavuconazole failure or intolerance. Higher doses (5 mg/kg) used in severe disease or CNS involvement. Also first-line if mucormycosis suspected (voriconazole has NO Mucorales activity). Monitor nephrotoxicity, electrolytes daily.",drug:"amphotericin-b",monographId:"amphotericin-b"},{id:"fungal-infections/invasive-aspergillosis/salvage-therapy/caspofungin-2",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"invasive-aspergillosis",subcategoryName:"Invasive Pulmonary Aspergillosis",line:"Salvage Therapy",regimen:"Caspofungin 70 mg IV load, then 50 mg IV daily",notes:"Echinocandin monotherapy is salvage only — NOT adequate as primary therapy for aspergillosis (fungistatic, not fungicidal against Aspergillus). May be used in combination (see above) or when azoles and amphotericin B are not tolerable.",drug:"caspofungin"},{id:"hap-vap/hap-mdr-risk/add-mrsa-coverage-if-risk-factors-present/linezolid-2",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"hap-mdr-risk",subcategoryName:"HAP — MDR Risk Factors OR High Mortality Risk",line:"ADD MRSA Coverage (if risk factors present)",regimen:"Linezolid 600mg IV/PO BID",notes:"Alternative to vancomycin. Potential advantages in pneumonia: better lung penetration, 100% oral bioavailability, no renal dosing. ZEPHyR trial showed linezolid non-inferior to vancomycin for MRSA nosocomial pneumonia with some secondary outcome advantages. Risk: myelosuppression (>14 days), serotonin syndrome with SSRIs.",drug:"linezolid",monographId:"linezolid",evidence:"A-I",evidenceSource:"IDSA/ATS 2016",evidenceSourceIds:["ats-idsa-2016-hap-vap"]},{id:"hap-vap/hap-mdr-risk/add-mrsa-coverage-if-risk-factors-present/vancomycin-1",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"hap-mdr-risk",subcategoryName:"HAP — MDR Risk Factors OR High Mortality Risk",line:"ADD MRSA Coverage (if risk factors present)",regimen:"Vancomycin IV — AUC/MIC-guided dosing (target AUC 400-600 mg·h/L)",notes:"ATS/IDSA 2016: add MRSA coverage if: IV antibiotics in prior 90 days, unit with >20% MRSA prevalence (or unknown), or prior MRSA colonization/infection. AUC-guided dosing is now standard (2020 vancomycin consensus). Check nasal MRSA swab — if negative, de-escalate within 48-72h.",drug:"vancomycin",monographId:"vancomycin",evidence:"A-I",evidenceSource:"IDSA/ATS 2016",evidenceSourceIds:["ats-idsa-2016-hap-vap"]},{id:"hap-vap/hap-mdr-risk/add-second-anti-pseudomonal-agent-if-mdr-pseudom/amikacin-3",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"hap-mdr-risk",subcategoryName:"HAP — MDR Risk Factors OR High Mortality Risk",line:"ADD Second Anti-Pseudomonal Agent (if MDR Pseudomonas risk)",regimen:"Amikacin 15-20 mg/kg IV daily (extended-interval dosing)",notes:"Most resistant to aminoglycoside-modifying enzymes — use when tobramycin-resistant. Higher doses needed for pneumonia due to poor lung penetration. Monitor levels closely.",drug:"amikacin"},{id:"hap-vap/hap-mdr-risk/add-second-anti-pseudomonal-agent-if-mdr-pseudom/aztreonam-4",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"hap-mdr-risk",subcategoryName:"HAP — MDR Risk Factors OR High Mortality Risk",line:"ADD Second Anti-Pseudomonal Agent (if MDR Pseudomonas risk)",regimen:"Aztreonam 2g IV q8h",notes:"Monobactam — NO cross-allergenicity with penicillins (safe in true penicillin allergy). Anti-pseudomonal. Covers gram-negatives only — no gram-positive or anaerobic activity. Useful in penicillin/cephalosporin allergy with Pseudomonas risk.",drug:"aztreonam",monographId:"aztreonam"},{id:"hap-vap/hap-mdr-risk/add-second-anti-pseudomonal-agent-if-mdr-pseudom/ciprofloxacin-hap-1",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"hap-mdr-risk",subcategoryName:"HAP — MDR Risk Factors OR High Mortality Risk",line:"ADD Second Anti-Pseudomonal Agent (if MDR Pseudomonas risk)",regimen:"Ciprofloxacin 400mg IV q8h",notes:"ATS/IDSA 2016: add a second anti-pseudomonal agent from a DIFFERENT class if: prior IV antibiotics in 90 days AND unit with >10% gram-negative resistance to monotherapy agent. FQ provides the different class from the beta-lactam backbone. Check local Pseudomonal FQ susceptibility.",drug:"ciprofloxacin-hap"},{id:"hap-vap/hap-mdr-risk/add-second-anti-pseudomonal-agent-if-mdr-pseudom/tobramycin-2",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"hap-mdr-risk",subcategoryName:"HAP — MDR Risk Factors OR High Mortality Risk",line:"ADD Second Anti-Pseudomonal Agent (if MDR Pseudomonas risk)",regimen:"Tobramycin 5-7 mg/kg IV daily (extended-interval dosing)",notes:"Alternative second anti-pseudomonal agent. Best gram-negative aminoglycoside for Pseudomonas. Extended-interval (once-daily) dosing maximizes peak:MIC ratio (concentration-dependent killing). Monitor levels: target peak >20× MIC, trough <1. Nephrotoxicity and ototoxicity with prolonged courses.",drug:"tobramycin"},{id:"hap-vap/hap-mdr-risk/empiric-anti-pseudomonal-beta-lactam-choose-one/cefepime-mdr-2",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"hap-mdr-risk",subcategoryName:"HAP — MDR Risk Factors OR High Mortality Risk",line:"Empiric — Anti-Pseudomonal Beta-Lactam (choose one)",regimen:"Cefepime 2g IV q8h (extended infusion)",notes:"Preferred if AmpC producers suspected (Enterobacter, Serratia, Citrobacter). NO anaerobic or MRSA coverage — add metronidazole if aspiration component, add vancomycin if MRSA risk.",drug:"cefepime-mdr",evidence:"A-I",evidenceSource:"IDSA/ATS 2016",evidenceSourceIds:["ats-idsa-2016-hap-vap"]},{id:"hap-vap/hap-mdr-risk/empiric-anti-pseudomonal-beta-lactam-choose-one/imipenem-4",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"hap-mdr-risk",subcategoryName:"HAP — MDR Risk Factors OR High Mortality Risk",line:"Empiric — Anti-Pseudomonal Beta-Lactam (choose one)",regimen:"Imipenem-cilastatin 500mg IV q6h",notes:"Alternative carbapenem. Slightly better gram-positive coverage than meropenem. Seizure risk higher than meropenem (especially renal impairment, CNS disease). Requires cilastatin to prevent renal metabolism.",drug:"imipenem"},{id:"hap-vap/hap-mdr-risk/empiric-anti-pseudomonal-beta-lactam-choose-one/meropenem-mdr-3",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"hap-mdr-risk",subcategoryName:"HAP — MDR Risk Factors OR High Mortality Risk",line:"Empiric — Anti-Pseudomonal Beta-Lactam (choose one)",regimen:"Meropenem 2g IV q8h (extended infusion over 3h)",notes:"Use for ESBL risk, prior MDR gram-negatives, or septic shock with high local resistance. Higher dose (2g) for pneumonia — lung penetration requires higher serum levels. De-escalate aggressively.",drug:"meropenem-mdr",evidence:"A-I",evidenceSource:"IDSA/ATS 2016",evidenceSourceIds:["ats-idsa-2016-hap-vap"]},{id:"hap-vap/hap-mdr-risk/empiric-anti-pseudomonal-beta-lactam-choose-one/pip-tazo-mdr-1",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"hap-mdr-risk",subcategoryName:"HAP — MDR Risk Factors OR High Mortality Risk",line:"Empiric — Anti-Pseudomonal Beta-Lactam (choose one)",regimen:"Piperacillin-tazobactam 4.5g IV q6h (extended infusion over 4h)",notes:"Preferred anti-pseudomonal backbone. Extended infusion is mandatory at this severity level. Covers gram-negatives, MSSA, anaerobes.",drug:"pip-tazo-mdr",evidence:"A-I",evidenceSource:"IDSA/ATS 2016",evidenceSourceIds:["ats-idsa-2016-hap-vap"]},{id:"hap-vap/hap-no-mdr/first-line-monotherapy-standard-risk/cefepime-2",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"hap-no-mdr",subcategoryName:"HAP — No MDR Risk Factors, Not High Mortality Risk",line:"First-Line (Monotherapy — Standard Risk)",regimen:"Cefepime 2g IV q8h (extended infusion over 3-4h)",notes:"Alternative first-line. Covers gram-negatives including most Pseudomonas and AmpC producers (SPACE organisms). NO anaerobic coverage. NO MRSA coverage.",drug:"cefepime",monographId:"cefepime",evidence:"A-I",evidenceSource:"IDSA/ATS 2016",evidenceSourceIds:["ats-idsa-2016-hap-vap"]},{id:"hap-vap/hap-no-mdr/first-line-monotherapy-standard-risk/levofloxacin-3",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"hap-no-mdr",subcategoryName:"HAP — No MDR Risk Factors, Not High Mortality Risk",line:"First-Line (Monotherapy — Standard Risk)",regimen:"Levofloxacin 750mg IV daily",notes:"ATS/IDSA lists as an option. Covers typicals + atypicals. BUT: high rates of FQ resistance in hospital-acquired gram-negatives limit utility. Check local antibiogram before selecting. 100% bioavailability — PO = IV.",drug:"levofloxacin",monographId:"levofloxacin",evidence:"B-II",evidenceSource:"IDSA/ATS 2016",evidenceSourceIds:["ats-idsa-2016-hap-vap"]},{id:"hap-vap/hap-no-mdr/first-line-monotherapy-standard-risk/meropenem-hap-4",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"hap-no-mdr",subcategoryName:"HAP — No MDR Risk Factors, Not High Mortality Risk",line:"First-Line (Monotherapy — Standard Risk)",regimen:"Meropenem 1g IV q8h (extended infusion)",notes:"Listed by ATS/IDSA as an option even without MDR risk, but stewardship principles favor reserving carbapenems. Use if high local ESBL prevalence or patient has multiple beta-lactam allergies limiting options.",drug:"meropenem-hap",evidence:"B-II",evidenceSource:"IDSA/ATS 2016",evidenceSourceIds:["ats-idsa-2016-hap-vap"]},{id:"hap-vap/hap-no-mdr/first-line-monotherapy-standard-risk/pip-tazo-hap-1",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"hap-no-mdr",subcategoryName:"HAP — No MDR Risk Factors, Not High Mortality Risk",line:"First-Line (Monotherapy — Standard Risk)",regimen:"Piperacillin-tazobactam 4.5g IV q6h (extended infusion over 4h)",notes:"ATS/IDSA 2016 preferred for HAP without MDR risk. Extended infusion standard of care. Covers Enterobacterales, Pseudomonas (empiric), MSSA, and anaerobes.",drug:"pip-tazo-hap",evidence:"A-I",evidenceSource:"IDSA/ATS 2016",evidenceSourceIds:["ats-idsa-2016-hap-vap"]},{id:"hap-vap/vap-prevention/antibiotic-stewardship-in-hap-vap/antibiotic-timeout-2",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"vap-prevention",subcategoryName:"VAP Prevention Bundle & Stewardship",line:"Antibiotic Stewardship in HAP/VAP",regimen:"Antibiotic time-out at 48-72h and at day 7",notes:"Structured reassessment: Is there still evidence of infection? Are cultures positive? Can therapy be narrowed? Should therapy be stopped (7-day mark)? Pharmacist-driven antibiotic time-outs reduce unnecessary antibiotic days by 1-3 days per patient.",drug:"antibiotic-timeout"},{id:"hap-vap/vap-prevention/antibiotic-stewardship-in-hap-vap/de-escalation-1",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"vap-prevention",subcategoryName:"VAP Prevention Bundle & Stewardship",line:"Antibiotic Stewardship in HAP/VAP",regimen:"Mandatory culture review at 48-72h with de-escalation plan",notes:"ATS/IDSA 2016 strongly recommends de-escalation based on culture results. Stop MRSA coverage if MRSA swab/cultures negative. Stop double Pseudomonal coverage if Pseudomonas not isolated. Switch from carbapenem to narrower agent if non-ESBL organism. Document rationale.",drug:"de-escalation"},{id:"hap-vap/vap-prevention/antibiotic-stewardship-in-hap-vap/pct-guided-3",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"vap-prevention",subcategoryName:"VAP Prevention Bundle & Stewardship",line:"Antibiotic Stewardship in HAP/VAP",regimen:"Procalcitonin-guided discontinuation (PCT <0.25 or >80% decline)",notes:"PTC trial (Bouadma 2010): PCT-guided strategy reduced antibiotic days by ~3 without affecting mortality. ATS/IDSA 2016 does not strongly endorse PCT for VAP diagnosis but supports its use for guiding DURATION. If PCT is trending down and patient is improving, consider stopping antibiotics even before day 7.",drug:"pct-guided"},{id:"hap-vap/vap-prevention/vap-prevention-bundle-components/subglottic-drainage-4",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"vap-prevention",subcategoryName:"VAP Prevention Bundle & Stewardship",line:"VAP Prevention Bundle Components",regimen:"Continuous or intermittent subglottic secretion drainage (via specialized ETT)",notes:"Reduces early-onset VAP by draining secretions pooled above the ETT cuff. Requires specialized endotracheal tube with a subglottic suction port. Meta-analyses show 45% reduction in VAP. Cost-effective. Should be standard for patients expected to be ventilated >48h.",drug:"subglottic-drainage"},{id:"hap-vap/vap-prevention/vap-prevention-bundle-components/sedation-vacation-2",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"vap-prevention",subcategoryName:"VAP Prevention Bundle & Stewardship",line:"VAP Prevention Bundle Components",regimen:"Daily sedation interruption + spontaneous breathing trial (SBT)",notes:"Reduces duration of mechanical ventilation (the single strongest risk factor for VAP). The ABC trial (Awakening and Breathing Controlled) showed this combination reduced ICU LOS and mortality. Pharmacist role: optimize sedation protocols, advocate for daily sedation vacation, manage analgo-sedation.",drug:"sedation-vacation"},{id:"hap-vap/vap-prevention/vap-prevention-bundle-components/dvt-prophylaxis-5",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"vap-prevention",subcategoryName:"VAP Prevention Bundle & Stewardship",line:"VAP Prevention Bundle Components",regimen:"Enoxaparin 40mg SQ daily (or heparin 5000 units SQ q8-12h)",notes:"DVT prophylaxis is a bundle component for VAP prevention bundles — not directly preventing VAP but part of the comprehensive ICU quality bundle. Pharmacist role: ensure appropriate dosing, renal adjustment, anti-Xa monitoring for enoxaparin in obesity/renal impairment.",drug:"dvt-prophylaxis"},{id:"hap-vap/vap-prevention/vap-prevention-bundle-components/hob-elevation-1",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"vap-prevention",subcategoryName:"VAP Prevention Bundle & Stewardship",line:"VAP Prevention Bundle Components",regimen:"Head-of-bed elevation 30-45 degrees",notes:"Reduces aspiration of colonized oropharyngeal secretions. One of the simplest and most effective interventions. Should be maintained at all times unless contraindicated (spinal injury, hemodynamic instability).",drug:"hob-elevation"},{id:"hap-vap/vap-prevention/vap-prevention-bundle-components/oral-care-3",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"vap-prevention",subcategoryName:"VAP Prevention Bundle & Stewardship",line:"VAP Prevention Bundle Components",regimen:"Oral care protocol (chlorhexidine 0.12% oral rinse BID — note controversy)",notes:"Chlorhexidine oral care reduces oropharyngeal colonization and has been associated with reduced VAP in many studies. HOWEVER: Deschepper et al. (2018) meta-analysis found a possible mortality INCREASE with CHG oral care in non-cardiac surgery ICU patients. Some institutions have removed CHG oral care. Know your institution's stance. Regardless, tooth brushing and oral hygiene are beneficial.",drug:"oral-care"},{id:"hap-vap/vap-prevention/vap-prevention-bundle-components/stress-ulcer-6",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"vap-prevention",subcategoryName:"VAP Prevention Bundle & Stewardship",line:"VAP Prevention Bundle Components",regimen:"PPI or H2RA for stress ulcer prophylaxis in at-risk patients",notes:"Controversial component: PPIs may increase risk of C. diff and HAP/VAP (gastric pH elevation → bacterial overgrowth → aspiration). SUP-ICU trial (2018): pantoprazole vs. placebo in ICU patients at risk of GI bleeding — pantoprazole reduced GI bleeding but no mortality difference. Balance GI bleed prevention vs. infection risk. Pharmacist role: ensure appropriate indication and discontinue at ICU discharge.",drug:"stress-ulcer"},{id:"hap-vap/vap/adjunctive-therapies/inhaled-abx-1",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"vap",subcategoryName:"Ventilator-Associated Pneumonia (VAP)",line:"Adjunctive Therapies",regimen:"Inhaled aminoglycosides or colistin — NOT routinely recommended",notes:"ATS/IDSA 2016: recommends AGAINST adjunctive inhaled antibiotics for HAP/VAP. VAPORIZE trial (2024) confirmed no benefit of inhaled amikacin. Exception: may consider for MDR/XDR gram-negatives susceptible only to aminoglycosides or polymyxins, where systemic therapy alone is failing — last-resort measure, consult ID.",drug:"inhaled-abx"},{id:"hap-vap/vap/duration-ats-idsa-2016-7-days-standard/duration-vap-1",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"vap",subcategoryName:"Ventilator-Associated Pneumonia (VAP)",line:"Duration (ATS/IDSA 2016 — 7 Days Standard)",regimen:"7 days for most VAP (strong recommendation, moderate quality evidence)",notes:"Chastre 2003 trial established 8 vs 15 days — 8 days non-inferior for most pathogens. ATS/IDSA 2016 recommends 7 days for ALL HAP/VAP (not 8, not 14). EXCEPTION: non-fermenting GNRs (Pseudomonas, Acinetobacter, Stenotrophomonas) — some experts extend to 10-14 days due to higher relapse rates at 8 days, though ATS/IDSA still recommends 7 days even for these. Clinical judgment applies.",drug:"duration-vap"},{id:"hap-vap/vap/vap-mdr-risk-factors-high-risk/vap-mdr-backbone-1",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"vap",subcategoryName:"Ventilator-Associated Pneumonia (VAP)",line:"VAP — MDR Risk Factors (High-Risk)",regimen:"Anti-pseudomonal beta-lactam (pip-tazo, cefepime, or meropenem) + second anti-gram-negative agent (FQ or aminoglycoside) + MRSA coverage (vancomycin or linezolid)",notes:"Triple therapy for high-risk VAP. ATS/IDSA 2016: two anti-pseudomonal agents from different classes + MRSA coverage when risk factors present. The goal is to maximize probability of at least one active agent against the causative pathogen. De-escalate aggressively at 48-72h.",drug:"vap-mdr-backbone"},{id:"hap-vap/vap/vap-no-mdr-risk-factors-low-risk/cefepime-vap-2",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"vap",subcategoryName:"Ventilator-Associated Pneumonia (VAP)",line:"VAP — No MDR Risk Factors (Low-Risk)",regimen:"Cefepime 2g IV q8h (extended infusion)",notes:"Good choice for AmpC producers. Extended infusion essential. Neurotoxicity risk in renal impairment — monitor for confusion, myoclonus, seizures (cefepime encephalopathy).",drug:"cefepime-vap",evidence:"A-I",evidenceSource:"IDSA/ATS 2016",evidenceSourceIds:["ats-idsa-2016-hap-vap"]},{id:"hap-vap/vap/vap-no-mdr-risk-factors-low-risk/levofloxacin-vap-3",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"vap",subcategoryName:"Ventilator-Associated Pneumonia (VAP)",line:"VAP — No MDR Risk Factors (Low-Risk)",regimen:"Levofloxacin 750mg IV daily",notes:"Alternative monotherapy. Check local FQ susceptibility — hospital-acquired gram-negatives often have high FQ resistance. May not be reliable in many ICUs.",drug:"levofloxacin-vap",evidence:"B-II",evidenceSource:"IDSA/ATS 2016",evidenceSourceIds:["ats-idsa-2016-hap-vap"]},{id:"hap-vap/vap/vap-no-mdr-risk-factors-low-risk/pip-tazo-vap-1",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"vap",subcategoryName:"Ventilator-Associated Pneumonia (VAP)",line:"VAP — No MDR Risk Factors (Low-Risk)",regimen:"Piperacillin-tazobactam 4.5g IV q6h (extended infusion)",notes:"Monotherapy is appropriate if no MDR risk factors AND unit gram-negative resistance <10% to the chosen agent. Same first-line agents as HAP without MDR risk.",drug:"pip-tazo-vap",evidence:"A-I",evidenceSource:"IDSA/ATS 2016",evidenceSourceIds:["ats-idsa-2016-hap-vap"]},{id:"iai/biliary-iai/duration-biliary-infections/duration-biliary-1",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"biliary-iai",subcategoryName:"Biliary Infections (Cholangitis & Complicated Cholecystitis)",line:"Duration — Biliary Infections",regimen:"4-7 days after adequate biliary drainage; shorter if uncomplicated with good source control",notes:"TG18 + STOP-IT principles: once biliary obstruction is relieved (ERCP with sphincterotomy/stent, cholecystectomy, percutaneous drainage), 4-7 days is sufficient. Bacteremia: treat for minimum 7-14 days per bloodstream infection standards. Without adequate drainage: antibiotics alone are usually insufficient — biliary decompression is the source control equivalent for cholangitis.",drug:"duration-biliary"},{id:"iai/biliary-iai/first-line-acute-cholangitis-grade-i-ii/amp-sulb-bil-3",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"biliary-iai",subcategoryName:"Biliary Infections (Cholangitis & Complicated Cholecystitis)",line:"First-Line — Acute Cholangitis (Grade I-II)",regimen:"Ampicillin-sulbactam 3g IV q6h",notes:"TG18 recommended. Covers Enterobacterales, anaerobes, and Enterococcus. The Enterococcal coverage is particularly relevant for biliary infections. Limitation: E. coli resistance (check local rates). Excellent option when local susceptibility supports it.",drug:"amp-sulb-bil"},{id:"iai/biliary-iai/first-line-acute-cholangitis-grade-i-ii/ctx-metro-bil-1",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"biliary-iai",subcategoryName:"Biliary Infections (Cholangitis & Complicated Cholecystitis)",line:"First-Line — Acute Cholangitis (Grade I-II)",regimen:"Ceftriaxone 2g IV daily + Metronidazole 500mg IV q8h",notes:"TG18 first-line. Ceftriaxone excellent biliary penetration (40% biliary excretion). Metronidazole for anaerobes (important in biliary-enteric anastomosis or instrumented ducts). Add ampicillin 2g IV q4h if Enterococcal coverage desired (biliary infections have higher Enterococcal prevalence). Duration: 4-7 days post drainage (shorter if adequately drained).",drug:"ctx-metro-bil"},{id:"iai/biliary-iai/first-line-acute-cholangitis-grade-i-ii/pip-tazo-bil-2",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"biliary-iai",subcategoryName:"Biliary Infections (Cholangitis & Complicated Cholecystitis)",line:"First-Line — Acute Cholangitis (Grade I-II)",regimen:"Pip-tazo 4.5g IV q6h (extended infusion)",notes:"Single-agent alternative covering gram-negatives, anaerobes, and Enterococcus. Good biliary penetration. Particularly useful when Enterococcal coverage desired without adding a separate agent. For Grade II-III cholangitis with sepsis.",drug:"pip-tazo-bil"},{id:"iai/biliary-iai/first-line-severe-cholangitis-grade-iii-or-healt/meropenem-bil-1",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"biliary-iai",subcategoryName:"Biliary Infections (Cholangitis & Complicated Cholecystitis)",line:"First-Line — Severe Cholangitis (Grade III) or Healthcare-Associated Biliary",regimen:"Meropenem 1g IV q8h + Vancomycin IV (if VRE risk)",notes:"For severe (Grade III) cholangitis with organ dysfunction, healthcare-associated biliary infection, or prior resistant organisms. Broadest coverage. De-escalate based on bile and blood cultures at 48-72h.",drug:"meropenem-bil"},{id:"iai/biliary-iai/first-line-severe-cholangitis-grade-iii-or-healt/pip-tazo-vanco-bil-2",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"biliary-iai",subcategoryName:"Biliary Infections (Cholangitis & Complicated Cholecystitis)",line:"First-Line — Severe Cholangitis (Grade III) or Healthcare-Associated Biliary",regimen:"Pip-tazo 4.5g IV q6h (extended infusion) + Vancomycin IV",notes:"Alternative for severe cholangitis when carbapenem-sparing desired. Pip-tazo covers most gram-negatives + anaerobes + E. faecalis. Add vancomycin for E. faecium/VRE/MRSA coverage.",drug:"pip-tazo-vanco-bil"},{id:"iai/ca-iai-complicated/duration-stop-it-standard/duration-ciai-1",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"ca-iai-complicated",subcategoryName:"Community-Acquired Complicated IAI (cIAI)",line:"Duration — STOP-IT Standard",regimen:"4 days after adequate source control (STOP-IT trial standard)",notes:"STOP-IT trial (2015 NEJM): 4 fixed days of antibiotics after source control was equivalent to outcome-based longer courses. This is the new standard. KEY CAVEAT: adequate source control MUST be achieved. If source control is inadequate (persistent abscess, ongoing leak, unable to operate), longer courses may be needed — but the answer is better source control, not more antibiotics. Pharmacist role: antibiotic time-out at day 4, advocate for discontinuation if source controlled and clinically improving.",drug:"duration-ciai"},{id:"iai/ca-iai-complicated/first-line-high-risk-severe-ciai-apache-15-or-md/cefepime-metro-ciai-3",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"ca-iai-complicated",subcategoryName:"Community-Acquired Complicated IAI (cIAI)",line:"First-Line — High-Risk/Severe cIAI (APACHE >=15 or MDR Risk Factors)",regimen:"Cefepime 2g IV q8h + Metronidazole 500mg IV q8h",notes:"Alternative for severe cIAI with Pseudomonal concern. Cefepime provides anti-pseudomonal and AmpC-stable gram-negative coverage; metronidazole adds anaerobes. No inherent Enterococcal coverage. Consider adding ampicillin if biliary source or Enterococcal risk.",drug:"cefepime-metro-ciai",evidence:"B-II",evidenceSource:"SIS/IDSA 2017",evidenceSourceIds:["sis-2017-ciai"]},{id:"iai/ca-iai-complicated/first-line-high-risk-severe-ciai-apache-15-or-md/meropenem-ciai-2",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"ca-iai-complicated",subcategoryName:"Community-Acquired Complicated IAI (cIAI)",line:"First-Line — High-Risk/Severe cIAI (APACHE >=15 or MDR Risk Factors)",regimen:"Meropenem 1g IV q8h (extended infusion over 3h)",notes:"Reserve for: APACHE >=15, ESBL risk, prior resistant organisms, failed initial therapy. Broadest coverage. Always de-escalate based on cultures (within 48-72h). Meropenem should NOT be first-line for mild-moderate community-acquired IAI — this is carbapenem overuse and drives CRE.",drug:"meropenem-ciai",evidence:"B-II",evidenceSource:"SIS/IDSA 2017",evidenceSourceIds:["sis-2017-ciai"]},{id:"iai/ca-iai-complicated/first-line-high-risk-severe-ciai-apache-15-or-md/pip-tazo-ciai-1",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"ca-iai-complicated",subcategoryName:"Community-Acquired Complicated IAI (cIAI)",line:"First-Line — High-Risk/Severe cIAI (APACHE >=15 or MDR Risk Factors)",regimen:"Pip-tazo 4.5g IV q6h (extended infusion over 4h)",notes:"IDSA 2010 first-line for high-risk/severe community-acquired cIAI. Broadest non-carbapenem single-agent option: covers Enterobacterales, Pseudomonas, anaerobes, Enterococcus (faecalis), Streptococci, MSSA. Extended infusion optimizes PK for sicker patients. Duration: 4 days post source control (STOP-IT).",drug:"pip-tazo-ciai",evidence:"A-I",evidenceSource:"SIS/IDSA 2017",evidenceSourceIds:["sis-2017-ciai"]},{id:"iai/ca-iai-complicated/first-line-mild-moderate-ciai-apache-15-no-mdr-r/amp-sulb-ciai-3",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"ca-iai-complicated",subcategoryName:"Community-Acquired Complicated IAI (cIAI)",line:"First-Line — Mild-Moderate cIAI (APACHE <15, No MDR Risk)",regimen:"Ampicillin-sulbactam 3g IV q6h",notes:"IDSA 2010 recommended for mild-moderate cIAI. Covers Enterobacterales + anaerobes + Enterococcus + Streptococci. UNIQUE ADVANTAGE: the only first-line cIAI regimen with intrinsic Enterococcal coverage. Good choice for biliary-origin cIAI. LIMITATION: rising E. coli resistance (20-30% in many regions) — check local antibiogram. Not reliable for Pseudomonas.",drug:"amp-sulb-ciai",evidence:"B-II",evidenceSource:"SIS/IDSA 2017",evidenceSourceIds:["sis-2017-ciai"]},{id:"iai/ca-iai-complicated/first-line-mild-moderate-ciai-apache-15-no-mdr-r/ctx-metro-ciai-1",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"ca-iai-complicated",subcategoryName:"Community-Acquired Complicated IAI (cIAI)",line:"First-Line — Mild-Moderate cIAI (APACHE <15, No MDR Risk)",regimen:"Ceftriaxone 2g IV daily + Metronidazole 500mg IV q8h",notes:"IDSA 2010 recommended combination. Ceftriaxone covers enteric gram-negatives; metronidazole covers anaerobes (particularly B. fragilis). Simple, well-tolerated, once-daily ceftriaxone component. NO Pseudomonal or Enterococcal coverage — appropriate for community-acquired, mild-moderate cIAI. Duration: 4 days post source control (STOP-IT).",drug:"ctx-metro-ciai",evidence:"A-I",evidenceSource:"SIS/IDSA 2017",evidenceSourceIds:["sis-2017-ciai"]},{id:"iai/ca-iai-complicated/first-line-mild-moderate-ciai-apache-15-no-mdr-r/ertapenem-ciai-2",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"ca-iai-complicated",subcategoryName:"Community-Acquired Complicated IAI (cIAI)",line:"First-Line — Mild-Moderate cIAI (APACHE <15, No MDR Risk)",regimen:"Ertapenem 1g IV once daily",notes:"IDSA 2010 first-line single-agent option for mild-moderate cIAI. Covers Enterobacterales + anaerobes + Streptococci + MSSA in one drug. Once-daily = excellent for OPAT. Equivalent to pip-tazo in multiple RCTs. GAPS: no Pseudomonas, no Enterococcus, no MRSA. The narrowest carbapenem — minimal Pseudomonal selection pressure compared to meropenem.",drug:"ertapenem-ciai",evidence:"A-I",evidenceSource:"SIS/IDSA 2017",evidenceSourceIds:["sis-2017-ciai"]},{id:"iai/ha-iai/add-antifungal-if-candida-risk-factors/fluconazole-iai-1",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"ha-iai",subcategoryName:"Healthcare-Associated & Post-Operative IAI",line:"ADD Antifungal If Candida Risk Factors",regimen:"Fluconazole 400mg IV/PO daily (loading 800mg day 1) — or — Micafungin 100mg IV daily",notes:"Candida peritonitis risk factors: upper GI perforation (especially with acid suppression), recurrent GI surgery, anastomotic leak, immunosuppression, prolonged antibiotics, TPN, Candida in peritoneal cultures. IDSA 2010: empiric antifungal NOT routine — add when risk factors present or yeast seen on Gram stain. Fluconazole for susceptible Candida albicans; echinocandin (micafungin, caspofungin) for C. glabrata/C. krusei or critically ill. Source control is critical for Candida peritonitis.",drug:"fluconazole-iai"},{id:"iai/ha-iai/duration-healthcare-associated-iai/duration-ha-iai-1",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"ha-iai",subcategoryName:"Healthcare-Associated & Post-Operative IAI",line:"Duration — Healthcare-Associated IAI",regimen:"4-7 days after adequate source control; longer if source control inadequate or tertiary peritonitis",notes:"DURAPOP trial: 8 days was safe for postoperative peritonitis (vs 15 days). Apply STOP-IT principles: fixed short-course with adequate source control. Tertiary peritonitis is the exception — may require prolonged courses (2-4 weeks) due to ongoing infection with resistant organisms and often inadequate source control. Focus on optimizing source control rather than extending antibiotics.",drug:"duration-ha-iai"},{id:"iai/ha-iai/empiric-post-operative-healthcare-associated-cia/cefepime-metro-ha-3",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"ha-iai",subcategoryName:"Healthcare-Associated & Post-Operative IAI",line:"Empiric — Post-Operative / Healthcare-Associated cIAI",regimen:"Cefepime 2g IV q8h (extended infusion) + Metronidazole 500mg IV q8h + Vancomycin IV",notes:"Alternative triple therapy. Cefepime for anti-pseudomonal + AmpC stability; metronidazole for anaerobes; vancomycin for VRE/MRSA. More components but allows carbapenem-sparing approach when ESBL risk is not high.",drug:"cefepime-metro-ha",evidence:"B-II",evidenceSource:"SIS/IDSA 2017",evidenceSourceIds:["sis-2017-ciai"]},{id:"iai/ha-iai/empiric-post-operative-healthcare-associated-cia/meropenem-ha-iai-2",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"ha-iai",subcategoryName:"Healthcare-Associated & Post-Operative IAI",line:"Empiric — Post-Operative / Healthcare-Associated cIAI",regimen:"Meropenem 1g IV q8h (extended infusion) + Vancomycin IV",notes:"For patients with ESBL risk, prior resistant organisms, or severe sepsis/septic shock. Meropenem covers ESBL, AmpC, Pseudomonas, anaerobes. Vancomycin for VRE/MRSA. THIS is the appropriate use of meropenem — healthcare-associated cIAI with MDR risk, not routine community-acquired IAI.",drug:"meropenem-ha-iai",evidence:"A-I",evidenceSource:"SIS/IDSA 2017",evidenceSourceIds:["sis-2017-ciai"]},{id:"iai/ha-iai/empiric-post-operative-healthcare-associated-cia/pip-tazo-ha-iai-1",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"ha-iai",subcategoryName:"Healthcare-Associated & Post-Operative IAI",line:"Empiric — Post-Operative / Healthcare-Associated cIAI",regimen:"Pip-tazo 4.5g IV q6h (extended infusion) + Vancomycin IV",notes:"Standard empiric regimen for healthcare-associated IAI. Pip-tazo covers Pseudomonas, Enterobacterales, anaerobes, Enterococcus faecalis. Add vancomycin for VRE (E. faecium) and MRSA coverage in high-risk patients. De-escalate aggressively at 48-72h based on cultures.",drug:"pip-tazo-ha-iai",evidence:"A-I",evidenceSource:"SIS/IDSA 2017",evidenceSourceIds:["sis-2017-ciai"]},{id:"iai/ca-iai-uncomplicated/duration-uncomplicated-iai/duration-uncomplicated-1",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"ca-iai-uncomplicated",subcategoryName:"Uncomplicated IAI (Appendicitis, Cholecystitis)",line:"Duration — Uncomplicated IAI",regimen:"Single pre-op dose (appendectomy/cholecystectomy), or ≤24h post-op, or NO antibiotics (uncomplicated diverticulitis)",notes:"Uncomplicated appendicitis: Pre-op dose only. Uncomplicated cholecystitis: Pre-op dose to 24h max. Uncomplicated diverticulitis: Increasingly treated without antibiotics (bowel rest, observation). The era of 7-14 day antibiotic courses for uncomplicated IAI is over. Source control (surgery) is the definitive treatment.",drug:"duration-uncomplicated"},{id:"iai/ca-iai-uncomplicated/uncomplicated-appendicitis-peri-operative/cefazolin-appx-1",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"ca-iai-uncomplicated",subcategoryName:"Uncomplicated IAI (Appendicitis, Cholecystitis)",line:"Uncomplicated Appendicitis — Peri-Operative",regimen:"Cefazolin 2g IV + Metronidazole 500mg IV (single pre-op dose)",notes:"Standard peri-operative prophylaxis for appendectomy. Cefazolin covers enteric gram-positives and common Enterobacterales; metronidazole covers anaerobes (Bacteroides). SINGLE pre-operative dose is sufficient if appendix is non-perforated and no spillage. No post-operative antibiotics needed for uncomplicated appendicitis.",drug:"cefazolin-appx"},{id:"iai/ca-iai-uncomplicated/uncomplicated-appendicitis-peri-operative/ceftriaxone-appx-2",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"ca-iai-uncomplicated",subcategoryName:"Uncomplicated IAI (Appendicitis, Cholecystitis)",line:"Uncomplicated Appendicitis — Peri-Operative",regimen:"Ceftriaxone 2g IV + Metronidazole 500mg IV (single pre-op dose)",notes:"Alternative prophylaxis. Broader gram-negative coverage than cefazolin. Some institutions use this for appendectomy, but cefazolin + metronidazole is equally effective and narrower. Single dose; no post-op continuation.",drug:"ceftriaxone-appx"},{id:"iai/ca-iai-uncomplicated/uncomplicated-cholecystitis-peri-operative/cefazolin-chole-1",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"ca-iai-uncomplicated",subcategoryName:"Uncomplicated IAI (Appendicitis, Cholecystitis)",line:"Uncomplicated Cholecystitis — Peri-Operative",regimen:"Cefazolin 2g IV (single pre-op dose for early cholecystectomy)",notes:"TG18: for mild (Grade I) acute cholecystitis with early cholecystectomy (<72h), a single pre-operative dose is sufficient. No post-operative antibiotics unless gangrenous or perforated. Biliary pathogens: E. coli, Klebsiella, Enterococcus — cefazolin covers the first two.",drug:"cefazolin-chole"},{id:"iai/ca-iai-uncomplicated/uncomplicated-cholecystitis-peri-operative/ctx-metro-chole-2",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"ca-iai-uncomplicated",subcategoryName:"Uncomplicated IAI (Appendicitis, Cholecystitis)",line:"Uncomplicated Cholecystitis — Peri-Operative",regimen:"Ceftriaxone 2g IV daily + Metronidazole 500mg IV q8h",notes:"For moderate (Grade II) cholecystitis or delayed surgery. Continue until cholecystectomy or clinical resolution. Ceftriaxone has excellent biliary excretion (40% excreted in bile). Anaerobic coverage with metronidazole added for complicated biliary-enteric connections.",drug:"ctx-metro-chole"},{id:"iai/ca-iai-uncomplicated/uncomplicated-diverticulitis-outpatient/amox-clav-div-2",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"ca-iai-uncomplicated",subcategoryName:"Uncomplicated IAI (Appendicitis, Cholecystitis)",line:"Uncomplicated Diverticulitis — Outpatient",regimen:"Amoxicillin-clavulanate 875/125mg PO BID",notes:"Alternative single-agent oral option covering gram-negatives + anaerobes. Simpler regimen than cipro + metronidazole. Same caveat: may not be needed at all for uncomplicated diverticulitis per current evidence.",drug:"amox-clav-div"},{id:"iai/ca-iai-uncomplicated/uncomplicated-diverticulitis-outpatient/cipro-metro-div-1",diseaseId:"iai",diseaseName:"Intra-Abdominal Infections",diseaseIcon:"🫁",subcategoryId:"ca-iai-uncomplicated",subcategoryName:"Uncomplicated IAI (Appendicitis, Cholecystitis)",line:"Uncomplicated Diverticulitis — Outpatient",regimen:"Ciprofloxacin 500mg PO BID + Metronidazole 500mg PO TID",notes:"Traditional outpatient regimen. Covers enteric gram-negatives + anaerobes. HOWEVER: Recent evidence (DIABOLO trial 2017, AVOD trial) showed antibiotics provide NO benefit for uncomplicated diverticulitis (Hinchey Ia — phlegmon only). AGA 2021 guidelines conditionally recommend AGAINST routine antibiotics for uncomplicated diverticulitis in immunocompetent patients. Discuss with the team.",drug:"cipro-metro-div"},{id:"sepsis/sepsis-community/add-on-for-mrsa-coverage-when-risk-factors-prese/daptomycin-2",diseaseId:"sepsis",diseaseName:"Sepsis & Septic Shock",diseaseIcon:"🔴",subcategoryId:"sepsis-community",subcategoryName:"Community-Acquired Sepsis",line:"Add-On for MRSA Coverage (When Risk Factors Present)",regimen:"Daptomycin 8–10mg/kg IV q24h (high-dose for bacteremia/endocarditis)",notes:"Alternative to vancomycin for MRSA bacteremia — non-inferior to vancomycin in RCTs. Preferred if: vancomycin MIC ≥2, VRE enterococcal bacteremia, or prior vancomycin nephrotoxicity. Do NOT use for pneumonia (inactivated by pulmonary surfactant). Monitor CPK weekly for myopathy.",drug:"daptomycin",monographId:"daptomycin",evidence:"A-I",evidenceSource:"Fowler et al., NEJM 2006",evidenceSourceIds:["fowler-2006-daptomycin"]},{id:"sepsis/sepsis-community/add-on-for-mrsa-coverage-when-risk-factors-prese/vancomycin-1",diseaseId:"sepsis",diseaseName:"Sepsis & Septic Shock",diseaseIcon:"🔴",subcategoryId:"sepsis-community",subcategoryName:"Community-Acquired Sepsis",line:"Add-On for MRSA Coverage (When Risk Factors Present)",regimen:"Vancomycin IV — AUC-guided dosing (target AUC/MIC 400–600 per ASHP/IDSA 2020)",notes:"Add empirically when: prior MRSA infection/colonization, HD patient, IVDU, recent hospitalization within 90 days, suspected catheter-related BSI, skin/soft tissue source with MRSA risk, septic shock without clear source. De-escalate at 48–72h if blood cultures negative for MRSA and gram-positive not identified. AUC-guided dosing with pharmacy consult required.",drug:"vancomycin",monographId:"vancomycin",evidence:"A-I",evidenceSource:"SSC 2021; ASHP/IDSA Vancomycin Guidelines 2020",evidenceSourceIds:["ssc-2021","ashp-idsa-pids-2020-vancomycin"]},{id:"sepsis/sepsis-community/empiric-antifungal-only-if-specific-candida-risk/micafungin-1",diseaseId:"sepsis",diseaseName:"Sepsis & Septic Shock",diseaseIcon:"🔴",subcategoryId:"sepsis-community",subcategoryName:"Community-Acquired Sepsis",line:"Empiric Antifungal — Only if Specific Candida Risk Factors",regimen:"Micafungin 100mg IV q24h OR Caspofungin 70mg IV ×1 then 50mg IV q24h",notes:"Do NOT add empiric antifungals routinely — SSC 2021 recommends against empiric antifungal for sepsis without specific risk factors. Reserve for: TPN-dependent + broad-spectrum abx ≥5 days + septic shock without source; abdominal surgery with GI perforation + Candida colonization; immunocompromised + persistent fever. Echinocandins are first-line for candidemia per IDSA 2016. Obtain ophthalmology fundoscopic exam if Candida in blood (endophthalmitis changes management).",drug:"micafungin",monographId:"micafungin",evidence:"B-II",evidenceSource:"SSC 2021; IDSA Candidiasis 2016",evidenceSourceIds:["ssc-2021","idsa-candidiasis"]},{id:"sepsis/sepsis-community/first-line-empiric-no-mdr-mrsa-risk-factors/cefepime-3",diseaseId:"sepsis",diseaseName:"Sepsis & Septic Shock",diseaseIcon:"🔴",subcategoryId:"sepsis-community",subcategoryName:"Community-Acquired Sepsis",line:"First-Line Empiric — No MDR/MRSA Risk Factors",regimen:"Cefepime 2g IV q8h",notes:"Good gram-negative coverage including Pseudomonas aeruginosa. Appropriate when Pseudomonas risk present (structural lung disease, known colonization). No anaerobic coverage — add metronidazole 500mg IV q8h for abdominal source. Monitor for cefepime-induced neurotoxicity (encephalopathy, myoclonus) in renal impairment.",drug:"cefepime",monographId:"cefepime",evidence:"A-I",evidenceSource:"SSC 2021",evidenceSourceIds:["ssc-2021"]},{id:"sepsis/sepsis-community/first-line-empiric-no-mdr-mrsa-risk-factors/ceftriaxone-1",diseaseId:"sepsis",diseaseName:"Sepsis & Septic Shock",diseaseIcon:"🔴",subcategoryId:"sepsis-community",subcategoryName:"Community-Acquired Sepsis",line:"First-Line Empiric — No MDR/MRSA Risk Factors",regimen:"Ceftriaxone 2g IV q24h ± Azithromycin 500mg IV/PO q24h (if CAP)",notes:"Preferred for urinary, biliary, and community pneumonia sources. Add azithromycin if atypical pneumonia suspected (CAP). Not reliable for ESBL, AmpC, or Pseudomonas. Excellent CNS penetration for meningitis (2g IV q12h for meningitis dosing).",drug:"ceftriaxone",monographId:"ceftriaxone",evidence:"A-I",evidenceSource:"SSC 2021, IDSA CAP 2019",evidenceSourceIds:["ssc-2021","ats-idsa-2019-cap"]},{id:"sepsis/sepsis-community/first-line-empiric-no-mdr-mrsa-risk-factors/piperacillin-tazobactam-2",diseaseId:"sepsis",diseaseName:"Sepsis & Septic Shock",diseaseIcon:"🔴",subcategoryId:"sepsis-community",subcategoryName:"Community-Acquired Sepsis",line:"First-Line Empiric — No MDR/MRSA Risk Factors",regimen:"Piperacillin-Tazobactam 4.5g IV q8h over 4h (extended infusion preferred) OR 3.375g IV q6h",notes:"Broader empiric coverage including anaerobes, Enterococcus faecalis, and most Pseudomonas. Preferred when abdominal/biliary source suspected or polymicrobial coverage needed. CRITICAL: Do NOT use as definitive therapy for ESBL bacteremia (MERINO trial — 3.3× higher mortality vs. meropenem). Extended 4h infusion optimizes T>MIC target attainment.",drug:"piperacillin-tazobactam",evidence:"A-I",evidenceSource:"SSC 2021; MERINO Trial JAMA 2018",evidenceSourceIds:["ssc-2021","merino"]},{id:"sepsis/sepsis-hcap/first-line-empiric-healthcare-associated-sepsis-/vancomycin-meropenem-2",diseaseId:"sepsis",diseaseName:"Sepsis & Septic Shock",diseaseIcon:"🔴",subcategoryId:"sepsis-hcap",subcategoryName:"Healthcare-Associated Sepsis",line:"First-Line Empiric Healthcare-Associated Sepsis Coverage (MRSA + Gram-Negative)",regimen:"Vancomycin IV (AUC-guided) + Meropenem 2g IV q8h over 3h (extended infusion)",notes:"Preferred over pip-tazo combination when: prior ESBL isolate from patient, recent hospitalization in high-ESBL facility, abdominal source with high inoculum risk, immunocompromised, or local ESBL prevalence >20% in healthcare settings. Extended 3h infusion maximizes T>MIC for higher-MIC organisms (MIC 2–8 mg/L range).",drug:"vancomycin-meropenem",evidence:"A-I",evidenceSource:"SSC 2021; MERINO Trial",evidenceSourceIds:["ssc-2021","merino"]},{id:"sepsis/sepsis-hcap/first-line-empiric-healthcare-associated-sepsis-/vancomycin-piptazo-1",diseaseId:"sepsis",diseaseName:"Sepsis & Septic Shock",diseaseIcon:"🔴",subcategoryId:"sepsis-hcap",subcategoryName:"Healthcare-Associated Sepsis",line:"First-Line Empiric Healthcare-Associated Sepsis Coverage (MRSA + Gram-Negative)",regimen:"Vancomycin IV (AUC-guided) + Piperacillin-Tazobactam 4.5g IV q8h extended infusion",notes:"Standard empiric combination for healthcare-associated sepsis without prior MDR isolates. Covers MRSA (vancomycin) plus gram-negative pathogens including Pseudomonas (pip-tazo). De-escalate vancomycin if MRSA is not identified at 48–72 hours. Switch from pip-tazo to meropenem if ESBL is found in blood cultures (MERINO trial).",drug:"vancomycin-piptazo",evidence:"B-II",evidenceSource:"SSC 2021; ATS/IDSA 2016 HAP/VAP",evidenceSourceIds:["ssc-2021","ats-idsa-2016-hap-vap"]},{id:"sepsis/sepsis-hcap/suspected-candida-sepsis-high-risk-patients/micafungin-hcap-1",diseaseId:"sepsis",diseaseName:"Sepsis & Septic Shock",diseaseIcon:"🔴",subcategoryId:"sepsis-hcap",subcategoryName:"Healthcare-Associated Sepsis",line:"Suspected Candida Sepsis — High-Risk Patients",regimen:"Micafungin 100mg IV q24h (first-line) OR Caspofungin 70mg IV ×1 then 50mg IV q24h",notes:"Add empiric antifungal when multiple Candida risk factors are present in healthcare-associated sepsis: TPN dependence, broad-spectrum antibiotics for at least 5 days, septic shock without source, multi-site Candida colonization (at least 2 non-contiguous sites), recent abdominal surgery with GI perforation, or solid organ transplant. Fluconazole is acceptable only for hemodynamically stable patients with no prior azole exposure and low risk for resistant Candida.",drug:"micafungin-hcap",evidence:"B-II",evidenceSource:"SSC 2021; IDSA Candidiasis Guidelines 2016",evidenceSourceIds:["ssc-2021","idsa-candidiasis"]},{id:"sepsis/sepsis-hcap/suspected-carbapenem-resistant-organism-cro-imme/ceftazidime-avibactam-1",diseaseId:"sepsis",diseaseName:"Sepsis & Septic Shock",diseaseIcon:"🔴",subcategoryId:"sepsis-hcap",subcategoryName:"Healthcare-Associated Sepsis",line:"Suspected Carbapenem-Resistant Organism (CRO) — Immediately Consult ID",regimen:"Ceftazidime-Avibactam 2.5g IV q8h (for KPC-CRE) ± Aztreonam (for MBL-CRE/NDM)",notes:"For suspected KPC-producing CRE: ceftazidime-avibactam is first-line. For MBL-producing CRE (NDM, VIM, IMP): ceftazidime-avibactam does NOT cover MBLs — must add aztreonam (see Advanced & Resistant Pathogen Agents section for detailed management). Consult Infectious Diseases immediately. Obtain carbapenem resistance testing (CRE PCR panel, carbapenem MIC). Ceftazidime-avibactam + aztreonam combination covers all CRE classes.",drug:"ceftazidime-avibactam",monographId:"ceftazidime-avibactam",evidence:"B-II",evidenceSource:"IDSA CRE Guidance 2023",evidenceSourceIds:["idsa-2023-cre-guidance"]},{id:"sepsis/septic-shock/immediate-broad-spectrum-empiric-septic-shock-wi/vanco-meropenem-1",diseaseId:"sepsis",diseaseName:"Sepsis & Septic Shock",diseaseIcon:"🔴",subcategoryId:"septic-shock",subcategoryName:"Septic Shock",line:"Immediate Broad-Spectrum Empiric — Septic Shock (Within 1 Hour)",regimen:"Vancomycin IV (AUC-guided, 25–30 mg/kg loading dose) + Meropenem 2g IV q8h over 3h ± Micafungin 100mg IV q24h if Candida risk",notes:"SSC 2021 recommended combination for septic shock of unclear source or healthcare-associated. Covers MRSA (vanco), ESBL (mero), Pseudomonas (mero), anaerobes (mero). Add micafungin if Candida risk factors present (see criteria above). Administer vancomycin loading dose first (25–30 mg/kg IV over 1–2h) to achieve rapid therapeutic levels. De-escalate within 48–72h based on culture data.",drug:"vanco-meropenem",evidence:"A-I",evidenceSource:"SSC 2021",evidenceSourceIds:["ssc-2021"]},{id:"sepsis/septic-shock/vasopressor-and-adjunctive-therapy-non-antimicro/norepinephrine-1",diseaseId:"sepsis",diseaseName:"Sepsis & Septic Shock",diseaseIcon:"🔴",subcategoryId:"septic-shock",subcategoryName:"Septic Shock",line:"Vasopressor and Adjunctive Therapy (Non-Antimicrobial — For Reference)",regimen:"Norepinephrine 0.01–3 mcg/kg/min IV (first-line vasopressor; MAP target ≥65 mmHg)",notes:"SSC 2021 first-line vasopressor. Add vasopressin 0.03 units/min IV as vasopressor-sparing agent when NE >0.25 mcg/kg/min. Epinephrine as rescue third vasopressor. For refractory vasoplegic shock: hydrocortisone 200mg/day IV continuous infusion (ADRENAL trial: reduces vasopressor duration without clear 90-day mortality benefit). Angiotensin II (Giapreza) as salvage option for catecholamine-refractory shock. Target MAP ≥65 mmHg — higher targets (MAP 80–85) not beneficial except in chronic hypertension (SEPSISPAM trial).",drug:"norepinephrine",evidence:"A-I",evidenceSource:"SSC 2021; SEPSISPAM Trial NEJM 2014",evidenceSourceIds:["ssc-2021","sepsispam"]},{id:"ssti/diabetic-foot/duration-soft-tissue-vs-osteomyelitis/duration-dfi-osteo-2",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"diabetic-foot",subcategoryName:"Diabetic Foot Infections (DFI)",line:"Duration — Soft Tissue vs Osteomyelitis",regimen:"Osteomyelitis: 4-6 weeks (no surgery), 1-3 weeks (after complete resection)",notes:"If osteomyelitis is present: 4-6 weeks of antibiotic therapy if treated medically (no bone resection). If infected bone is completely resected (amputation, debridement with clean margins): 1-3 weeks of antibiotics may suffice (some experts use 5-7 days post-resection if clean margins confirmed). Bone culture guides targeted therapy. Oral step-down is supported by the OVIVA trial for osteomyelitis.",drug:"duration-dfi-osteo"},{id:"ssti/diabetic-foot/duration-soft-tissue-vs-osteomyelitis/duration-dfi-soft-1",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"diabetic-foot",subcategoryName:"Diabetic Foot Infections (DFI)",line:"Duration — Soft Tissue vs Osteomyelitis",regimen:"Soft tissue DFI: 1-2 weeks (mild), 2-3 weeks (moderate-severe)",notes:"IDSA 2023: shorter courses preferred for soft tissue DFI. Treat the INFECTION, not the wound — antibiotics do not heal wounds, they clear infection. A clean ulcer base without signs of infection does not require antibiotics regardless of appearance. Continuing antibiotics beyond the infectious period drives resistance and C. diff.",drug:"duration-dfi-soft"},{id:"ssti/diabetic-foot/first-line-mild-dfi-grade-2-outpatient/amox-clav-dfi-2",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"diabetic-foot",subcategoryName:"Diabetic Foot Infections (DFI)",line:"First-Line — Mild DFI (Grade 2, Outpatient)",regimen:"Amoxicillin-clavulanate 875/125mg PO BID",notes:"Broader option covering gram-positives + anaerobes + some gram-negatives. Useful for mild DFIs with wound features suggesting polymicrobial etiology (chronic ulcers, fetid discharge, deeper wounds). Duration: 1-2 weeks.",drug:"amox-clav-dfi"},{id:"ssti/diabetic-foot/first-line-mild-dfi-grade-2-outpatient/cephalexin-dfi-1",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"diabetic-foot",subcategoryName:"Diabetic Foot Infections (DFI)",line:"First-Line — Mild DFI (Grade 2, Outpatient)",regimen:"Cephalexin 500mg PO QID",notes:"For mild DFI, acute (<2 weeks), in antibiotic-naive patient. Targets gram-positive cocci (Streptococci, MSSA). Mild DFIs are predominantly gram-positive monomicrobial. NO MRSA coverage — add TMP-SMX or doxycycline if MRSA risk. Duration: 1-2 weeks.",drug:"cephalexin-dfi"},{id:"ssti/diabetic-foot/first-line-mild-dfi-grade-2-outpatient/clindamycin-dfi-3",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"diabetic-foot",subcategoryName:"Diabetic Foot Infections (DFI)",line:"First-Line — Mild DFI (Grade 2, Outpatient)",regimen:"Clindamycin 300mg PO TID + Ciprofloxacin 500mg PO BID",notes:"If MRSA risk + need for gram-negative coverage. Clindamycin covers MRSA + Streptococci + anaerobes; ciprofloxacin adds gram-negative coverage. Check local clindamycin susceptibility patterns.",drug:"clindamycin-dfi"},{id:"ssti/diabetic-foot/first-line-moderate-severe-dfi-grade-3-4-inpatie/ertapenem-dfi-2",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"diabetic-foot",subcategoryName:"Diabetic Foot Infections (DFI)",line:"First-Line — Moderate-Severe DFI (Grade 3-4, Inpatient)",regimen:"Ertapenem 1g IV daily + Vancomycin IV",notes:"Alternative backbone. Ertapenem covers Streptococci, MSSA, Enterobacterales, and anaerobes with convenient once-daily dosing (excellent for OPAT). Does NOT cover Pseudomonas — use pip-tazo or meropenem if Pseudomonas suspected (chronic wounds, prior Pseudomonas). Add vancomycin for MRSA.",drug:"ertapenem-dfi"},{id:"ssti/diabetic-foot/first-line-moderate-severe-dfi-grade-3-4-inpatie/meropenem-dfi-3",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"diabetic-foot",subcategoryName:"Diabetic Foot Infections (DFI)",line:"First-Line — Moderate-Severe DFI (Grade 3-4, Inpatient)",regimen:"Meropenem 1g IV q8h + Vancomycin IV",notes:"Reserve for severe DFI with risk for ESBL or MDR gram-negatives (prior antibiotics, prior resistant cultures, prolonged hospitalization). De-escalate aggressively based on cultures.",drug:"meropenem-dfi"},{id:"ssti/diabetic-foot/first-line-moderate-severe-dfi-grade-3-4-inpatie/pip-tazo-dfi-1",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"diabetic-foot",subcategoryName:"Diabetic Foot Infections (DFI)",line:"First-Line — Moderate-Severe DFI (Grade 3-4, Inpatient)",regimen:"Pip-tazo 4.5g IV q6h (extended infusion) + Vancomycin IV",notes:"Standard empiric regimen for moderate-severe DFI. Pip-tazo covers Streptococci, MSSA, Enterobacterales, Pseudomonas, and anaerobes. Vancomycin adds MRSA coverage. De-escalate based on deep wound cultures. This covers the typical polymicrobial flora of chronic DFIs.",drug:"pip-tazo-dfi"},{id:"ssti/necrotizing-ssti/adjunctive-toxin-suppression-critical-component/clindamycin-nsti-1",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"necrotizing-ssti",subcategoryName:"Necrotizing Soft Tissue Infections (NSTI / Necrotizing Fasciitis)",line:"Adjunctive — Toxin Suppression (Critical Component)",regimen:"Clindamycin 900mg IV q8h",notes:"NON-NEGOTIABLE component of NSTI therapy. Mechanism: inhibits ribosomal protein synthesis, thereby suppressing production of bacterial exotoxins (superantigens, cytolysins, tissue-destroying enzymes). Beta-lactams and vancomycin (cell wall agents) do NOT suppress toxin production — in fact, cell lysis from beta-lactams can RELEASE preformed toxins. Clindamycin addresses this by shutting down the toxin factory. Eagle effect: at high bacterial density (as in NSTI), beta-lactam killing slows because bacteria are in stationary phase with reduced PBP expression. Clindamycin is NOT affected by inoculum size. Continue until clinical improvement or de-escalation per ID.",drug:"clindamycin-nsti"},{id:"ssti/necrotizing-ssti/duration/duration-nsti-1",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"necrotizing-ssti",subcategoryName:"Necrotizing Soft Tissue Infections (NSTI / Necrotizing Fasciitis)",line:"Duration",regimen:"Continue until surgical debridement complete + clinical improvement, typically 2-4 weeks total",notes:"No fixed duration — guided by surgical findings and clinical response. Multiple debridements are common (every 24-48h until no further necrotic tissue). Antibiotics continue through the surgical phase. De-escalate based on cultures once pathogen identified. Transition to targeted therapy: Type I (polymicrobial) — may narrow to amp-sulbactam or pip-tazo; Type II (GAS) — penicillin G + clindamycin; Type II (MRSA) — vancomycin + clindamycin.",drug:"duration-nsti"},{id:"ssti/necrotizing-ssti/first-line-empiric-broad-spectrum-start-immediat/nsti-alt-2",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"necrotizing-ssti",subcategoryName:"Necrotizing Soft Tissue Infections (NSTI / Necrotizing Fasciitis)",line:"First-Line — Empiric Broad-Spectrum (Start Immediately, Before Surgery)",regimen:"Vancomycin + Meropenem 1g IV q8h + Clindamycin 900mg IV q8h",notes:"Alternative backbone using meropenem instead of pip-tazo. Preferred if: ESBL risk, prior resistant organisms, or concern for polymicrobial infection with resistant gram-negatives. Same triple-therapy rationale: MRSA + broad gram-negative/anaerobic + toxin suppression.",drug:"nsti-alt",evidence:"B-II",evidenceSource:"IDSA 2014",evidenceSourceIds:["idsa-2014-ssti"]},{id:"ssti/necrotizing-ssti/first-line-empiric-broad-spectrum-start-immediat/nsti-backbone-1",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"necrotizing-ssti",subcategoryName:"Necrotizing Soft Tissue Infections (NSTI / Necrotizing Fasciitis)",line:"First-Line — Empiric Broad-Spectrum (Start Immediately, Before Surgery)",regimen:"Vancomycin IV (AUC 400-600) + Piperacillin-tazobactam 4.5g IV q6h (extended infusion) + Clindamycin 900mg IV q8h",notes:"IDSA 2014 recommended triple therapy: (1) MRSA coverage (vancomycin), (2) Broad gram-negative + anaerobic coverage (pip-tazo), (3) Toxin suppression (clindamycin). Clindamycin is added specifically for its ribosomal-mediated suppression of Streptococcal exotoxins (SPE-A, SPE-B), Staphylococcal PVL, and Clostridial alpha-toxin. This toxin suppression reduces inflammatory cascade and improves survival. Do NOT omit clindamycin.",drug:"nsti-backbone",evidence:"A-I",evidenceSource:"IDSA 2014",evidenceSourceIds:["idsa-2014-ssti"]},{id:"ssti/nonpurulent-ssti/add-mrsa-coverage-if-risk-factors-present/linezolid-ssti-2",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"nonpurulent-ssti",subcategoryName:"Non-Purulent SSTI (Cellulitis & Erysipelas)",line:"ADD MRSA Coverage If Risk Factors Present",regimen:"Linezolid 600mg IV/PO BID",notes:"Alternative to vancomycin for MRSA cellulitis. 100% oral bioavailability. FDA-approved for complicated SSTIs. Advantage: PO = IV, no renal dosing, no levels to monitor. Disadvantage: cost, myelosuppression risk if >14 days, serotonin syndrome risk.",drug:"linezolid-ssti"},{id:"ssti/nonpurulent-ssti/add-mrsa-coverage-if-risk-factors-present/vancomycin-ssti-1",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"nonpurulent-ssti",subcategoryName:"Non-Purulent SSTI (Cellulitis & Erysipelas)",line:"ADD MRSA Coverage If Risk Factors Present",regimen:"Vancomycin IV (AUC/MIC 400-600) — add to cefazolin",notes:"Add MRSA coverage for: prior MRSA infection/colonization, IVDU, failed initial beta-lactam therapy, penetrating trauma, concurrent purulent wound. Continue cefazolin for Streptococcal coverage — vancomycin alone has suboptimal Streptococcal killing kinetics. De-escalate when cultures return.",drug:"vancomycin-ssti"},{id:"ssti/nonpurulent-ssti/duration/duration-cellulitis-1",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"nonpurulent-ssti",subcategoryName:"Non-Purulent SSTI (Cellulitis & Erysipelas)",line:"Duration",regimen:"5 days (IDSA 2014), extend to 7-10 days if slow clinical response",notes:"IDSA 2014 recommends 5 days for uncomplicated cellulitis, with extension if not improved. Multiple RCTs support 5-day courses as non-inferior to 10 days. Longer courses (10-14 days) may be needed for: immunosuppressed patients, slow-responding infections, cellulitis with associated bacteremia. Reassess at 48-72h — failure to improve should prompt imaging (abscess? necrotizing?) and broadening.",drug:"duration-cellulitis"},{id:"ssti/nonpurulent-ssti/first-line-mild-outpatient-oral/cephalexin-ssti-1",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"nonpurulent-ssti",subcategoryName:"Non-Purulent SSTI (Cellulitis & Erysipelas)",line:"First-Line — Mild (Outpatient, Oral)",regimen:"Cephalexin 500mg PO QID (or 1000mg PO BID)",notes:"IDSA 2014 first-line for non-purulent cellulitis. Targets Streptococci and MSSA. NO MRSA coverage. QID dosing is traditional but BID dosing of 1g achieves adequate T>MIC and improves adherence — many experts now prefer this. Duration: 5 days (IDSA), extend to 7-10 if slow response.",drug:"cephalexin-ssti",evidence:"A-I",evidenceSource:"IDSA 2014",evidenceSourceIds:["idsa-2014-ssti"]},{id:"ssti/nonpurulent-ssti/first-line-mild-outpatient-oral/clindamycin-ssti-oral-3",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"nonpurulent-ssti",subcategoryName:"Non-Purulent SSTI (Cellulitis & Erysipelas)",line:"First-Line — Mild (Outpatient, Oral)",regimen:"Clindamycin 300-450mg PO TID",notes:"Alternative if penicillin allergy. Covers Streptococci, MSSA, most CA-MRSA (check local susceptibility — resistance rising, now 15-25% in some areas). Also covers anaerobes. C. diff risk higher than beta-lactams. Use when MRSA coverage desired in outpatient non-purulent SSTI with risk factors.",drug:"clindamycin-ssti-oral",evidence:"B-II",evidenceSource:"IDSA 2014",evidenceSourceIds:["idsa-2014-ssti"]},{id:"ssti/nonpurulent-ssti/first-line-mild-outpatient-oral/dicloxacillin-ssti-2",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"nonpurulent-ssti",subcategoryName:"Non-Purulent SSTI (Cellulitis & Erysipelas)",line:"First-Line — Mild (Outpatient, Oral)",regimen:"Dicloxacillin 500mg PO QID",notes:"Alternative first-line. Anti-staphylococcal penicillin. Narrower spectrum than cephalexin. Must be taken on empty stomach (1h before or 2h after meals). Poor adherence due to QID + empty stomach. Cephalexin preferred by most clinicians.",drug:"dicloxacillin-ssti",evidence:"B-II",evidenceSource:"IDSA 2014",evidenceSourceIds:["idsa-2014-ssti"]},{id:"ssti/nonpurulent-ssti/first-line-moderate-severe-inpatient-iv/cefazolin-1",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"nonpurulent-ssti",subcategoryName:"Non-Purulent SSTI (Cellulitis & Erysipelas)",line:"First-Line — Moderate/Severe (Inpatient, IV)",regimen:"Cefazolin 2g IV q8h",notes:"IDSA 2014 first-line IV for non-purulent cellulitis requiring hospitalization. MSSA + Streptococcal coverage. The simplest, narrowest IV option. No MRSA coverage — add vancomycin only if MRSA risk factors present. Convert to oral cephalexin when improving.",drug:"cefazolin",monographId:"cefazolin"},{id:"ssti/nonpurulent-ssti/first-line-moderate-severe-inpatient-iv/nafcillin-ssti-2",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"nonpurulent-ssti",subcategoryName:"Non-Purulent SSTI (Cellulitis & Erysipelas)",line:"First-Line — Moderate/Severe (Inpatient, IV)",regimen:"Nafcillin 2g IV q4h (or Oxacillin 2g IV q4h)",notes:"Anti-staphylococcal penicillins. Narrowest anti-MSSA agents. Superior to vancomycin for MSSA (multiple studies show faster bactericidal activity). Disadvantages: q4h dosing, phlebitis, hepatotoxicity (oxacillin > nafcillin), interstitial nephritis. Cefazolin is generally preferred due to ease of dosing.",drug:"nafcillin-ssti"},{id:"ssti/purulent-ssti/duration/duration-purulent-1",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"purulent-ssti",subcategoryName:"Purulent SSTI (Abscess, Furuncle, Carbuncle)",line:"Duration",regimen:"5-7 days (outpatient); 7-14 days (severe/complicated)",notes:"Mild-moderate after I&D: 5-7 days. Severe: 7-14 days depending on response. Bacteremia from SSTI source: 14 days minimum for S. aureus (longer if endocarditis — see below). KEY: S. aureus bacteremia ALWAYS warrants echocardiography and ID consultation to rule out endocarditis — even if the apparent source is 'just' a skin infection.",drug:"duration-purulent"},{id:"ssti/purulent-ssti/first-line-mild-outpatient-after-i-d/clindamycin-ssti-3",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"purulent-ssti",subcategoryName:"Purulent SSTI (Abscess, Furuncle, Carbuncle)",line:"First-Line — Mild (Outpatient, After I&D)",regimen:"Clindamycin 300-450mg PO TID",notes:"ESTABLISH trials: equivalent to TMP-SMX. Covers MRSA + Streptococci + anaerobes. KEY LIMITATION: rising clindamycin resistance (15-25% in some areas). MUST check D-test for inducible clindamycin resistance (erythromycin-resistant, clindamycin-susceptible isolates need D-test). If D-test positive, clindamycin will fail. C. diff risk higher than TMP-SMX or doxycycline.",drug:"clindamycin-ssti",evidence:"A-I",evidenceSource:"IDSA 2014",evidenceSourceIds:["idsa-2014-ssti"]},{id:"ssti/purulent-ssti/first-line-mild-outpatient-after-i-d/doxycycline-ssti-2",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"purulent-ssti",subcategoryName:"Purulent SSTI (Abscess, Furuncle, Carbuncle)",line:"First-Line — Mild (Outpatient, After I&D)",regimen:"Doxycycline 100mg PO BID",notes:"ESTABLISH trials: equivalent to clindamycin for uncomplicated SSTI. Excellent CA-MRSA activity (>95%). Advantages: BID dosing, low C. diff risk, no renal dosing. Disadvantages: photosensitivity, esophageal ulceration (take with full glass of water, upright), limited Streptococcal coverage (a gap if surrounding cellulitis is significant). Duration: 5-7 days.",drug:"doxycycline-ssti",evidence:"A-I",evidenceSource:"IDSA 2014",evidenceSourceIds:["idsa-2014-ssti"]},{id:"ssti/purulent-ssti/first-line-mild-outpatient-after-i-d/tmp-smx-ssti-1",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"purulent-ssti",subcategoryName:"Purulent SSTI (Abscess, Furuncle, Carbuncle)",line:"First-Line — Mild (Outpatient, After I&D)",regimen:"TMP-SMX DS 1-2 tablets PO BID",notes:"IDSA 2014 + Talan 2016 trial first-line after I&D. Excellent CA-MRSA activity (>95% susceptibility). Talan trial showed adding TMP-SMX to I&D improved cure rates from 73.6% to 80.5%. DS = 160/800mg. Double-strength dosing (2 DS BID) used by some for larger abscesses. Duration: 5-7 days.",drug:"tmp-smx-ssti",evidence:"A-I",evidenceSource:"IDSA 2014",evidenceSourceIds:["idsa-2014-ssti"]},{id:"ssti/purulent-ssti/first-line-moderate-severe-inpatient-iv/cefazolin-purulent-4",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"purulent-ssti",subcategoryName:"Purulent SSTI (Abscess, Furuncle, Carbuncle)",line:"First-Line — Moderate/Severe (Inpatient, IV)",regimen:"Cefazolin 2g IV q8h (if MSSA confirmed or low MRSA suspicion)",notes:"Use when cultures confirm MSSA. SUPERIOR to vancomycin for MSSA. De-escalation target: once MSSA confirmed, switch from vancomycin to cefazolin. This is one of the highest-impact stewardship interventions in SSTI.",drug:"cefazolin-purulent"},{id:"ssti/purulent-ssti/first-line-moderate-severe-inpatient-iv/daptomycin-2",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"purulent-ssti",subcategoryName:"Purulent SSTI (Abscess, Furuncle, Carbuncle)",line:"First-Line — Moderate/Severe (Inpatient, IV)",regimen:"Daptomycin 4-6 mg/kg IV once daily",notes:"FDA-approved for complicated SSTIs at 4mg/kg. Many experts dose 6mg/kg for serious infections. Rapidly bactericidal against MRSA. MUST NOT use for pneumonia (inactivated by pulmonary surfactant). Advantages: once-daily dosing, no nephrotoxicity at standard doses. Monitor CPK weekly.",drug:"daptomycin",monographId:"daptomycin"},{id:"ssti/purulent-ssti/first-line-moderate-severe-inpatient-iv/linezolid-purulent-3",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"purulent-ssti",subcategoryName:"Purulent SSTI (Abscess, Furuncle, Carbuncle)",line:"First-Line — Moderate/Severe (Inpatient, IV)",regimen:"Linezolid 600mg IV/PO BID",notes:"FDA-approved for complicated SSTIs including MRSA. 100% PO bioavailability — can step down to oral immediately. Suppresses toxin production (PVL). Monitor CBC weekly for thrombocytopenia if >7 days.",drug:"linezolid-purulent"},{id:"ssti/purulent-ssti/first-line-moderate-severe-inpatient-iv/vancomycin-purulent-1",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"purulent-ssti",subcategoryName:"Purulent SSTI (Abscess, Furuncle, Carbuncle)",line:"First-Line — Moderate/Severe (Inpatient, IV)",regimen:"Vancomycin IV (AUC/MIC 400-600)",notes:"IDSA 2014 first-line IV for severe purulent SSTI (failed oral therapy, systemic toxicity, immunocompromised). Provides definitive MRSA coverage. AUC-guided dosing standard (2020 consensus). Convert to oral TMP-SMX or doxycycline when improving.",drug:"vancomycin-purulent"},{id:"ssti/purulent-ssti/i-d-without-antibiotics-when-to-consider/id-alone-1",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"purulent-ssti",subcategoryName:"Purulent SSTI (Abscess, Furuncle, Carbuncle)",line:"I&D Without Antibiotics — When to Consider",regimen:"I&D alone for small (<2cm), uncomplicated abscess in healthy patient",notes:"IDSA 2014 suggests I&D alone MAY be sufficient for small, uncomplicated abscesses in immunocompetent patients. HOWEVER: Talan 2016 trial showed antibiotics after I&D improved outcomes even for uncomplicated abscesses. Current practice has shifted toward adding a 5-day course of TMP-SMX or doxycycline after I&D for most abscesses. I&D alone may still be reasonable for very small (<2cm) abscesses that are completely drained with no surrounding cellulitis.",drug:"id-alone"},{id:"uti/pyelonephritis/adjunctive/supportive-1",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"pyelonephritis",subcategoryName:"Acute Pyelonephritis",line:"Adjunctive",regimen:"IV fluids, antipyretics, antiemetics",notes:"Aggressive hydration is critical. Urology consult if obstructive cause suspected — may require percutaneous nephrostomy or ureteral stent urgently.",drug:"supportive"},{id:"uti/pyelonephritis/inpatient-complicated-septic-unable-to-tolerate-/ceftriaxone-1",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"pyelonephritis",subcategoryName:"Acute Pyelonephritis",line:"Inpatient (Complicated, Septic, Unable to Tolerate PO)",regimen:"Ceftriaxone 2g IV daily",notes:"Workhorse empiric. Broad gram-negative coverage. Step down when clinically improved.",drug:"ceftriaxone",monographId:"ceftriaxone"},{id:"uti/pyelonephritis/inpatient-complicated-septic-unable-to-tolerate-/meropenem-3",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"pyelonephritis",subcategoryName:"Acute Pyelonephritis",line:"Inpatient (Complicated, Septic, Unable to Tolerate PO)",regimen:"Meropenem 1g IV q8h",notes:"Reserve for ESBL risk, prior MDR organisms, or septic shock. De-escalate aggressively.",drug:"meropenem",monographId:"meropenem"},{id:"uti/pyelonephritis/inpatient-complicated-septic-unable-to-tolerate-/pip-tazo-2",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"pyelonephritis",subcategoryName:"Acute Pyelonephritis",line:"Inpatient (Complicated, Septic, Unable to Tolerate PO)",regimen:"Piperacillin-tazobactam 3.375g IV q6h (or 4.5g q8h EI)",notes:"Use if Pseudomonas risk or healthcare-associated exposure. Extended infusion preferred.",drug:"pip-tazo",monographId:"pip-tazo"},{id:"uti/pyelonephritis/outpatient-uncomplicated-tolerating-po-not-septi/ceftriaxone-oral-step-3",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"pyelonephritis",subcategoryName:"Acute Pyelonephritis",line:"Outpatient (Uncomplicated, Tolerating PO, Not Septic)",regimen:"Ceftriaxone 1g IV/IM × 1 dose THEN oral step-down (cefpodoxime, TMP-SMX, or FQ per susceptibility)",notes:"Excellent strategy for ED-treat-and-release. The single IV dose provides immediate high tissue levels while you await culture results for definitive oral selection.",drug:"ceftriaxone-oral-step",evidence:"B-II",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]},{id:"uti/pyelonephritis/outpatient-uncomplicated-tolerating-po-not-septi/ciprofloxacin-1",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"pyelonephritis",subcategoryName:"Acute Pyelonephritis",line:"Outpatient (Uncomplicated, Tolerating PO, Not Septic)",regimen:"Ciprofloxacin 500mg PO BID × 7 days",notes:"IDSA first-line for outpatient pyelo IF local FQ resistance <10%. 7-day course is established.",drug:"ciprofloxacin",monographId:"ciprofloxacin",evidence:"A-I",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]},{id:"uti/pyelonephritis/outpatient-uncomplicated-tolerating-po-not-septi/tmp-smx-2",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"pyelonephritis",subcategoryName:"Acute Pyelonephritis",line:"Outpatient (Uncomplicated, Tolerating PO, Not Septic)",regimen:"TMP-SMX DS PO BID × 14 days",notes:"Alternative if FQ cannot be used. Requires 14 days (longer than FQ). IDSA recommends a one-time IV dose of ceftriaxone 1g or aminoglycoside with initiation if using TMP-SMX empirically (pending cultures).",drug:"tmp-smx",monographId:"tmp-smx",evidence:"B-II",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]},{id:"uti/cauti/duration/duration-guide-1",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"cauti",subcategoryName:"Catheter-Associated UTI (CAUTI)",line:"Duration",regimen:"7 days if rapid clinical response; 10-14 days if delayed response",notes:"IDSA 2010: 7 days is adequate for most CAUTI with prompt clinical improvement. Shorter courses reduce C. diff risk and resistance selection.",drug:"duration-guide"},{id:"uti/cauti/empiric-pending-cultures-always-de-escalate/ceftriaxone-1",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"cauti",subcategoryName:"Catheter-Associated UTI (CAUTI)",line:"Empiric (Pending Cultures — Always De-escalate)",regimen:"Ceftriaxone 1-2g IV daily",notes:"Reasonable empiric for non-critically ill. Narrow once cultures return. Always assess for Pseudomonas risk.",drug:"ceftriaxone",monographId:"ceftriaxone",evidence:"A-I",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]},{id:"uti/cauti/empiric-pending-cultures-always-de-escalate/ciprofloxacin-3",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"cauti",subcategoryName:"Catheter-Associated UTI (CAUTI)",line:"Empiric (Pending Cultures — Always De-escalate)",regimen:"Ciprofloxacin 500mg PO BID (if can take PO and not critically ill)",notes:"Only oral option with Pseudomonal activity. But FQ resistance is high in catheterized populations — empiric use risky without prior culture data.",drug:"ciprofloxacin",monographId:"ciprofloxacin",evidence:"B-II",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]},{id:"uti/cauti/empiric-pending-cultures-always-de-escalate/pip-tazo-2",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"cauti",subcategoryName:"Catheter-Associated UTI (CAUTI)",line:"Empiric (Pending Cultures — Always De-escalate)",regimen:"Piperacillin-tazobactam 4.5g IV q8h (EI over 4h)",notes:"Use if Pseudomonas or MDR risk (prior cultures, healthcare exposure). Extended infusion recommended.",drug:"pip-tazo",monographId:"pip-tazo",evidence:"B-II",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]},{id:"uti/complicated-uti/duration-idsa-2025-shorter-courses-endorsed/duration-bacteremia-3",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"complicated-uti",subcategoryName:"Complicated UTI",line:"Duration (IDSA 2025 — Shorter Courses Endorsed)",regimen:"cUTI with gram-negative bacteremia: 7 days total (low certainty evidence)",notes:"IDSA 2025 suggests 7 days even for BACTEREMIC cUTI, not 14 days. This is a landmark recommendation — shorter courses for bacteremic UTI are now guideline-endorsed. Count from first day of effective therapy.",drug:"duration-bacteremia"},{id:"uti/complicated-uti/duration-idsa-2025-shorter-courses-endorsed/duration-fq-1",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"complicated-uti",subcategoryName:"Complicated UTI",line:"Duration (IDSA 2025 — Shorter Courses Endorsed)",regimen:"Fluoroquinolone: 5-7 days total (moderate certainty evidence)",notes:"Counted from first day of EFFECTIVE therapy. Shorter than traditional 7-14 day recommendations. Practice-changing for stewardship.",drug:"duration-fq"},{id:"uti/complicated-uti/duration-idsa-2025-shorter-courses-endorsed/duration-non-fq-2",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"complicated-uti",subcategoryName:"Complicated UTI",line:"Duration (IDSA 2025 — Shorter Courses Endorsed)",regimen:"Non-fluoroquinolone: 7 days total (very low certainty evidence)",notes:"7 days is now the suggested standard, NOT 10-14 days. Applies to cephalosporins, pip-tazo, carbapenems. Exception: suspected prostatitis in men — may need 10-14 days.",drug:"duration-non-fq"},{id:"uti/complicated-uti/first-line-cuti-with-sepsis/ceftriaxone-sepsis-1",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"complicated-uti",subcategoryName:"Complicated UTI",line:"First-Line — cUTI WITH Sepsis",regimen:"Ceftriaxone 2g IV daily or Cefepime 2g IV q8h",notes:"IDSA 2025: same preferred classes but carbapenems now INCLUDED as first-line for sepsis (not restricted to ESBL). Priority shifts to ensuring early appropriate therapy — stewardship deferred to definitive phase.",drug:"ceftriaxone-sepsis"},{id:"uti/complicated-uti/first-line-cuti-with-sepsis/levofloxacin-sepsis-4",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"complicated-uti",subcategoryName:"Complicated UTI",line:"First-Line — cUTI WITH Sepsis",regimen:"Levofloxacin 750mg IV daily",notes:"FQs remain a preferred class even in sepsis IF no prior FQ exposure in 12 months. 100% bioavailability supports early PO switch once stable.",drug:"levofloxacin-sepsis"},{id:"uti/complicated-uti/first-line-cuti-with-sepsis/meropenem-3",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"complicated-uti",subcategoryName:"Complicated UTI",line:"First-Line — cUTI WITH Sepsis",regimen:"Meropenem 1g IV q8h (extended infusion over 3h)",notes:"IDSA 2025 includes carbapenems as first-line option for SEPSIS (unlike non-septic cUTI). Use if ESBL risk, prior MDR organisms, or septic shock. Antibiogram step: select agent with ≥90% susceptibility for septic shock, ≥80% for sepsis without shock.",drug:"meropenem",monographId:"meropenem"},{id:"uti/complicated-uti/first-line-cuti-with-sepsis/pip-tazo-sepsis-2",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"complicated-uti",subcategoryName:"Complicated UTI",line:"First-Line — cUTI WITH Sepsis",regimen:"Piperacillin-tazobactam 4.5g IV q6-8h (extended infusion)",notes:"Preferred in sepsis. Extended infusion standard of care. Consider if Pseudomonas risk based on prior cultures.",drug:"pip-tazo-sepsis"},{id:"uti/complicated-uti/first-line-cuti-without-sepsis/ceftriaxone-1",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"complicated-uti",subcategoryName:"Complicated UTI",line:"First-Line — cUTI WITHOUT Sepsis",regimen:"Ceftriaxone 1-2g IV daily (or cefepime 2g IV q8h if AmpC/Pseudomonas concern)",notes:"IDSA 2025 preferred: 3rd/4th-gen cephalosporins. Carbapenems are NOT first-line for non-septic cUTI — this is a key stewardship change. Reserve carbapenems for sepsis or confirmed ESBL.",drug:"ceftriaxone",monographId:"ceftriaxone",evidence:"A-I",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]},{id:"uti/complicated-uti/first-line-cuti-without-sepsis/ciprofloxacin-3",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"complicated-uti",subcategoryName:"Complicated UTI",line:"First-Line — cUTI WITHOUT Sepsis",regimen:"Ciprofloxacin 500mg PO BID or Levofloxacin 750mg PO daily",notes:"IDSA 2025 preferred IF no FQ exposure in past 12 months (Step 2). Advantage: oral administration avoids IV, enables outpatient treatment. AVOID if FQ used in prior 12 months — guideline-specific recommendation.",drug:"ciprofloxacin",monographId:"ciprofloxacin",evidence:"A-I",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]},{id:"uti/complicated-uti/first-line-cuti-without-sepsis/pip-tazo-2",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"complicated-uti",subcategoryName:"Complicated UTI",line:"First-Line — cUTI WITHOUT Sepsis",regimen:"Piperacillin-tazobactam 3.375g IV q6h (or 4.5g q8h extended infusion)",notes:"IDSA 2025 preferred empiric option. Extended infusion (over 4h) optimizes PK/PD. Appropriate when broader coverage desired (Pseudomonas risk).",drug:"pip-tazo",monographId:"pip-tazo",evidence:"A-I",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]},{id:"uti/complicated-uti/idsa-2025-four-step-approach/four-step-overview-1",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"complicated-uti",subcategoryName:"Complicated UTI",line:"IDSA 2025 Four-Step Approach",regimen:"Step 1: Severity (sepsis vs. non-sepsis) → Step 2: Resistance risk factors → Step 3: Patient-specific factors → Step 4: Antibiogram (sepsis only)",notes:"This structured approach replaces the old 'pick an antibiotic' model. Each step narrows the empiric selection. The guideline emphasizes that inappropriate empiric therapy has little impact on mortality in NON-SEPTIC cUTI (mortality ≤5%), but is critical in sepsis/septic shock.",drug:"four-step-overview"},{id:"uti/complicated-uti/iv-to-po-step-down-idsa-2025-formally-endorsed/iv-po-switch-1",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"complicated-uti",subcategoryName:"Complicated UTI",line:"IV-to-PO Step-Down (IDSA 2025 — Formally Endorsed)",regimen:"Switch when: clinically improving, able to take oral meds, effective oral option available",notes:"IDSA 2025 formally endorses early IV-to-PO transition, even in gram-negative bacteremia (conditional recommendation). Oral options: FQs (ciprofloxacin, levofloxacin), TMP-SMX, amox-clav (if susceptible). Effective oral agent must achieve therapeutic levels in urine AND tissue AND be active against the pathogen.",drug:"iv-po-switch"},{id:"uti/complicated-uti/newer-agents-reserve-not-first-line-per-idsa-202/newer-agents-1",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"complicated-uti",subcategoryName:"Complicated UTI",line:"Newer Agents (Reserve — NOT First-Line per IDSA 2025)",regimen:"Ceftazidime-avibactam, Meropenem-vaborbactam, Ceftolozane-tazobactam, Cefiderocol, Plazomicin",notes:"IDSA 2025 explicitly recommends AGAINST using novel BL-BLI agents and cefiderocol as empiric first-line, even in sepsis. Reserve for definitive therapy of MDR/XDR organisms (CRE, MBL-producers, DTR Pseudomonas). This is a major stewardship statement — protect these agents.",drug:"newer-agents"},{id:"uti/uncomplicated-cystitis/avoid-for-uncomplicated-cystitis/fluoroquinolones-1",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"uncomplicated-cystitis",subcategoryName:"Uncomplicated Cystitis",line:"AVOID for Uncomplicated Cystitis",regimen:"Ciprofloxacin, Levofloxacin",notes:"FDA boxed warning — reserve for infections with no other options. Massive collateral ecological damage. Risk of tendinopathy, aortic dissection, QT prolongation, CNS effects, peripheral neuropathy. IDSA explicitly recommends AGAINST for uncomplicated cystitis.",drug:"fluoroquinolones"},{id:"uti/uncomplicated-cystitis/first-line/fosfomycin-3",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"uncomplicated-cystitis",subcategoryName:"Uncomplicated Cystitis",line:"First-Line",regimen:"Fosfomycin trometamol 3g PO × 1 dose",notes:"Single-dose convenience. Slightly inferior efficacy vs. multi-day regimens per meta-analyses. Good for adherence-challenged patients. Mix in water, not hot beverages.",drug:"fosfomycin",monographId:"fosfomycin",evidence:"A-I",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]},{id:"uti/uncomplicated-cystitis/first-line/nitrofurantoin-1",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"uncomplicated-cystitis",subcategoryName:"Uncomplicated Cystitis",line:"First-Line",regimen:"Nitrofurantoin monohydrate/macrocrystals 100mg PO BID × 5 days",notes:"Preferred agent. COMBINE trial supports potential 3-day course. Avoid if CrCl <30 mL/min (though recent data supports use down to ~20). Not effective for anything beyond the bladder.",drug:"nitrofurantoin",monographId:"nitrofurantoin",evidence:"A-I",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]},{id:"uti/uncomplicated-cystitis/first-line/tmp-smx-2",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"uncomplicated-cystitis",subcategoryName:"Uncomplicated Cystitis",line:"First-Line",regimen:"TMP-SMX DS (160/800mg) PO BID × 3 days",notes:"Use only if local resistance <20%. Avoid if used in prior 3 months. Check sulfa allergy. 3-day course is well established.",drug:"tmp-smx",monographId:"tmp-smx",evidence:"A-I",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]},{id:"uti/uncomplicated-cystitis/second-line-use-when-first-line-agents-cannot-be/amox-clav-1",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"uncomplicated-cystitis",subcategoryName:"Uncomplicated Cystitis",line:"Second-Line (use when first-line agents cannot be used)",regimen:"Amoxicillin-Clavulanate 500/125mg PO BID × 5-7 days",notes:"Inferior efficacy to first-line agents for uncomplicated cystitis. More collateral damage. Reserve when others unavailable.",drug:"amox-clav",evidence:"B-II",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]},{id:"uti/uncomplicated-cystitis/second-line-use-when-first-line-agents-cannot-be/cefpodoxime-3",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"uncomplicated-cystitis",subcategoryName:"Uncomplicated Cystitis",line:"Second-Line (use when first-line agents cannot be used)",regimen:"Cefpodoxime 100mg PO BID × 5-7 days",notes:"Third-gen oral cephalosporin option. Broader spectrum than needed for most uncomplicated cases.",drug:"cefpodoxime",evidence:"B-II",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]},{id:"uti/uncomplicated-cystitis/second-line-use-when-first-line-agents-cannot-be/cephalexin-2",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"uncomplicated-cystitis",subcategoryName:"Uncomplicated Cystitis",line:"Second-Line (use when first-line agents cannot be used)",regimen:"Cephalexin 500mg PO BID-QID × 5-7 days",notes:"Reasonable alternative. Better tolerated than amox-clav. Limited guideline support as first choice.",drug:"cephalexin",evidence:"B-II",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]}],a=Object.fromEntries(i.map(e=>[e.id,e])),n={"ceftazidime-avibactam":[{id:"advanced-agents/cre-management/kpc-producing-cre/ceftazidime-avibactam-1",diseaseId:"advanced-agents",diseaseName:"Advanced & Resistant Pathogen Agents",diseaseIcon:"🛡",subcategoryId:"cre-management",subcategoryName:"Carbapenem-Resistant Enterobacteriaceae (CRE)",line:"KPC-producing CRE",regimen:"Ceftazidime-Avibactam 2.5g IV q8h (adjust for renal function)",notes:"Preferred for KPC-CRE and OXA-48. Does NOT cover NDM. Check local susceptibility.",drug:"ceftazidime-avibactam",monographId:"ceftazidime-avibactam",evidence:"A-II",evidenceSource:"IDSA 2022",evidenceSourceIds:["idsa-2022-amr"]},{id:"advanced-agents/cre-management/ndm-producing-cre/ceftazidime-avibactam-1",diseaseId:"advanced-agents",diseaseName:"Advanced & Resistant Pathogen Agents",diseaseIcon:"🛡",subcategoryId:"cre-management",subcategoryName:"Carbapenem-Resistant Enterobacteriaceae (CRE)",line:"NDM-producing CRE",regimen:"Ceftazidime-Avibactam 2.5g IV q8h + Aztreonam 2g IV q6h (extended infusion)",notes:"Combination required — CAZ-AVI restores aztreonam activity against MBL-producers. Ceftazidime-avibactam protects aztreonam from hydrolysis. ID consult mandatory.",drug:"ceftazidime-avibactam",monographId:"ceftazidime-avibactam",evidence:"B-II",evidenceSource:"IDSA 2022",evidenceSourceIds:["idsa-2022-amr"]},{id:"amr-gn/cre-kpc/preferred-kpc-producing-cre-non-urinary-infectio/ceftazidime-avibactam-2",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"cre-kpc",subcategoryName:"CRE — KPC-Producing Enterobacterales",line:"Preferred — KPC-Producing CRE (Non-Urinary Infections)",regimen:"Ceftazidime-avibactam 2.5g IV q8h (infused over 2h)",notes:"IDSA 2024 preferred. >95% activity against KPC-CRE. Avibactam inhibits KPC, ESBL, AmpC, and OXA-48-like enzymes. Most clinical experience of any novel BL-BLI for CRE. CAUTION: higher resistance emergence risk than mer-vab (KPC mutations in omega loop can cause caz-avi resistance). 2.5g = 2g ceftazidime + 0.5g avibactam.",drug:"ceftazidime-avibactam",monographId:"ceftazidime-avibactam"},{id:"sepsis/sepsis-hcap/suspected-carbapenem-resistant-organism-cro-imme/ceftazidime-avibactam-1",diseaseId:"sepsis",diseaseName:"Sepsis & Septic Shock",diseaseIcon:"🔴",subcategoryId:"sepsis-hcap",subcategoryName:"Healthcare-Associated Sepsis",line:"Suspected Carbapenem-Resistant Organism (CRO) — Immediately Consult ID",regimen:"Ceftazidime-Avibactam 2.5g IV q8h (for KPC-CRE) ± Aztreonam (for MBL-CRE/NDM)",notes:"For suspected KPC-producing CRE: ceftazidime-avibactam is first-line. For MBL-producing CRE (NDM, VIM, IMP): ceftazidime-avibactam does NOT cover MBLs — must add aztreonam (see Advanced & Resistant Pathogen Agents section for detailed management). Consult Infectious Diseases immediately. Obtain carbapenem resistance testing (CRE PCR panel, carbapenem MIC). Ceftazidime-avibactam + aztreonam combination covers all CRE classes.",drug:"ceftazidime-avibactam",monographId:"ceftazidime-avibactam",evidence:"B-II",evidenceSource:"IDSA CRE Guidance 2023",evidenceSourceIds:["idsa-2023-cre-guidance"]}],"meropenem-vaborbactam":[{id:"advanced-agents/cre-management/kpc-producing-cre/meropenem-vaborbactam-2",diseaseId:"advanced-agents",diseaseName:"Advanced & Resistant Pathogen Agents",diseaseIcon:"🛡",subcategoryId:"cre-management",subcategoryName:"Carbapenem-Resistant Enterobacteriaceae (CRE)",line:"KPC-producing CRE",regimen:"Meropenem-Vaborbactam 4g IV q8h (infuse over 3h)",notes:"Alternative for KPC-CRE. Does NOT cover NDM, OXA-48, or Acinetobacter.",drug:"meropenem-vaborbactam",monographId:"meropenem-vaborbactam",evidence:"A-II",evidenceSource:"IDSA 2022",evidenceSourceIds:["idsa-2022-amr"]},{id:"amr-gn/cre-kpc/preferred-kpc-producing-cre-non-urinary-infectio/meropenem-vaborbactam-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"cre-kpc",subcategoryName:"CRE — KPC-Producing Enterobacterales",line:"Preferred — KPC-Producing CRE (Non-Urinary Infections)",regimen:"Meropenem-vaborbactam 4g IV q8h (extended infusion over 3h)",notes:"IDSA 2024: slightly favored among the three preferred agents. TANGO II trial: 59% clinical cure vs 26% with BAT for CRE. >95% activity against KPC-producing CRE. Vaborbactam is a potent boronic acid inhibitor of KPCs. Lowest resistance emergence risk of the three preferred agents. 4g = 2g meropenem + 2g vaborbactam per dose.",drug:"meropenem-vaborbactam",monographId:"meropenem-vaborbactam"}],colistin:[{id:"advanced-agents/cre-management/salvage-pan-resistant/colistin-1",diseaseId:"advanced-agents",diseaseName:"Advanced & Resistant Pathogen Agents",diseaseIcon:"🛡",subcategoryId:"cre-management",subcategoryName:"Carbapenem-Resistant Enterobacteriaceae (CRE)",line:"Salvage / Pan-resistant",regimen:"Colistin (CMS) — load 9 MU IV, then 4.5 MU IV q12h (CrCl-adjusted), always in combination",notes:"Use only when all other options exhausted. Nephrotoxicity in 30-50%. Never monotherapy. Combination with meropenem, rifampin, or fosfomycin based on MIC data.",drug:"colistin",monographId:"colistin",evidence:"C-III",evidenceSource:"IDSA 2022",evidenceSourceIds:["idsa-2022-amr"]}],"ceftolozane-tazobactam":[{id:"advanced-agents/mdr-pseudomonas/preferred-dtr-pa/ceftolozane-tazobactam-1",diseaseId:"advanced-agents",diseaseName:"Advanced & Resistant Pathogen Agents",diseaseIcon:"🛡",subcategoryId:"mdr-pseudomonas",subcategoryName:"Difficult-to-Treat Pseudomonas aeruginosa (DTR-PA)",line:"Preferred (DTR-PA)",regimen:"Ceftolozane-Tazobactam 3g IV q8h (HAP/VAP: 1.5g q8h for cUTI/IAI) — standard infusion 1h",notes:"Excellent anti-pseudomonal activity. Stable against most Pseudomonas resistance mechanisms except MBL.",drug:"ceftolozane-tazobactam",monographId:"ceftolozane-tazobactam",evidence:"A-II",evidenceSource:"IDSA 2022",evidenceSourceIds:["idsa-2022-amr"]}],"imipenem-cilastatin-relebactam":[{id:"advanced-agents/mdr-pseudomonas/preferred-dtr-pa/imipenem-cilastatin-relebactam-2",diseaseId:"advanced-agents",diseaseName:"Advanced & Resistant Pathogen Agents",diseaseIcon:"🛡",subcategoryId:"mdr-pseudomonas",subcategoryName:"Difficult-to-Treat Pseudomonas aeruginosa (DTR-PA)",line:"Preferred (DTR-PA)",regimen:"Imipenem-Cilastatin-Relebactam 1.25g IV q6h (infuse over 30 min)",notes:"Active against KPC and AmpC producers. Restores imipenem activity. RESTORE-IMI trials support use.",drug:"imipenem-cilastatin-relebactam",monographId:"imipenem-cilastatin-relebactam",evidence:"A-II",evidenceSource:"IDSA 2022",evidenceSourceIds:["idsa-2022-amr"]}],cefepime:[{id:"amr-gn/ampc-e/preferred-invasive-infections-e-cloacae-k-aeroge/cefepime-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"ampc-e",subcategoryName:"AmpC β-Lactamase-Producing Enterobacterales (AmpC-E)",line:"Preferred — Invasive Infections (E. cloacae, K. aerogenes, C. freundii)",regimen:"Cefepime 2g IV q8h (extended infusion over 3h)",notes:"IDSA 2024 preferred for AmpC-E infections. Weak ampC inducer AND stable against AmpC hydrolysis (forms stable acyl enzyme complexes). Observational studies and meta-analysis show similar outcomes to carbapenems. No clinical trial exists comparing cefepime vs carbapenem for AmpC-E, but mechanism and observational data strongly support cefepime. CARBAPENEM-SPARING — this is the critical stewardship advantage.",drug:"cefepime",monographId:"cefepime"},{id:"cap/cap-icu/add-on-for-pseudomonas-risk-factors/cefepime-2",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-icu",subcategoryName:"Severe CAP / ICU Admission",line:"Add-On for Pseudomonas Risk Factors",regimen:"Cefepime 2g IV q8h (extended infusion)",notes:"Alternative anti-pseudomonal beta-lactam. Also covers SPACE organisms (AmpC producers) — better than ceftriaxone for Enterobacter, Citrobacter, Serratia.",drug:"cefepime",monographId:"cefepime"},{id:"febrile-neutropenia/high-risk-fn/monotherapy-antipseudomonal-beta-lactam-idsa-201/cefepime-1",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"high-risk-fn",subcategoryName:"High-Risk Febrile Neutropenia",line:"Monotherapy — Antipseudomonal Beta-Lactam (IDSA 2010 First-Line, A-I)",regimen:"Cefepime 2g IV q8h",notes:"IDSA 2010 preferred first-line monotherapy (A-I). Fourth-generation cephalosporin with excellent antipseudomonal activity and broad gram-negative + gram-positive spectrum. Does NOT cover MRSA, Enterococcus, or anaerobes. DOSING NOTE: 2g q8h is the standard for FN; continuous infusion (6g over 24h by elastomeric pump) has pharmacodynamic advantages for organisms with higher MICs. RENAL DOSING: CrCl 30–60 → 1–2g q12h; CrCl 11–29 → 1–2g q24h; HD → 0.5–1g after each HD session. CNS TOXICITY RISK: neurotoxicity (encephalopathy, myoclonus, seizures) at higher exposures — especially in renal failure. Monitor closely in elderly and renally impaired patients. Consider EEG if altered mental status develops on cefepime.",drug:"cefepime",monographId:"cefepime",evidence:"A-I",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"hap-vap/hap-no-mdr/first-line-monotherapy-standard-risk/cefepime-2",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"hap-no-mdr",subcategoryName:"HAP — No MDR Risk Factors, Not High Mortality Risk",line:"First-Line (Monotherapy — Standard Risk)",regimen:"Cefepime 2g IV q8h (extended infusion over 3-4h)",notes:"Alternative first-line. Covers gram-negatives including most Pseudomonas and AmpC producers (SPACE organisms). NO anaerobic coverage. NO MRSA coverage.",drug:"cefepime",monographId:"cefepime",evidence:"A-I",evidenceSource:"IDSA/ATS 2016",evidenceSourceIds:["ats-idsa-2016-hap-vap"]},{id:"sepsis/sepsis-community/first-line-empiric-no-mdr-mrsa-risk-factors/cefepime-3",diseaseId:"sepsis",diseaseName:"Sepsis & Septic Shock",diseaseIcon:"🔴",subcategoryId:"sepsis-community",subcategoryName:"Community-Acquired Sepsis",line:"First-Line Empiric — No MDR/MRSA Risk Factors",regimen:"Cefepime 2g IV q8h",notes:"Good gram-negative coverage including Pseudomonas aeruginosa. Appropriate when Pseudomonas risk present (structural lung disease, known colonization). No anaerobic coverage — add metronidazole 500mg IV q8h for abdominal source. Monitor for cefepime-induced neurotoxicity (encephalopathy, myoclonus) in renal impairment.",drug:"cefepime",monographId:"cefepime",evidence:"A-I",evidenceSource:"SSC 2021",evidenceSourceIds:["ssc-2021"]}],meropenem:[{id:"amr-gn/ampc-e/preferred-invasive-infections-e-cloacae-k-aeroge/meropenem-2",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"ampc-e",subcategoryName:"AmpC β-Lactamase-Producing Enterobacterales (AmpC-E)",line:"Preferred — Invasive Infections (E. cloacae, K. aerogenes, C. freundii)",regimen:"Meropenem 1g IV q8h (extended infusion)",notes:"Carbapenems are stable against AmpC hydrolysis. Use for AmpC-E when cefepime cannot be used (allergy, cefepime neurotoxicity, polymicrobial infection requiring broader coverage). Imipenem is a potent ampC inducer but remains stable to hydrolysis. Ertapenem reasonable for stable, non-critically ill.",drug:"meropenem",monographId:"meropenem"},{id:"amr-gn/esbl-e/preferred-non-urinary-infections-bsi-iai-pneumon/meropenem-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"esbl-e",subcategoryName:"ESBL-Producing Enterobacterales (ESBL-E)",line:"Preferred — Non-Urinary Infections (BSI, IAI, Pneumonia)",regimen:"Meropenem 1g IV q8h (extended infusion over 3h)",notes:"IDSA 2024 preferred for ESBL-E infections outside urinary tract. MERINO trial standard of care. Extended infusion optimizes T>MIC. For critically ill or hypoalbuminemic patients, use meropenem or imipenem — NOT ertapenem.",drug:"meropenem",monographId:"meropenem"},{id:"bacteremia-endocarditis/gram-negative-bacteremia/empiric-healthcare-associated-or-mdr-risk-factor/meropenem-2",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"gram-negative-bacteremia",subcategoryName:"Gram-Negative Bacteremia",line:"Empiric — Healthcare-Associated or MDR Risk Factors",regimen:"Meropenem 1g IV q8h (extended infusion over 3h preferred)",notes:"Reserve for high suspicion of ESBL or AmpC-producing organisms, or critically ill patients. Definitive therapy for confirmed ESBL bacteremia (per MERINO trial). De-escalate as soon as susceptibilities allow — carbapenem stewardship matters.",drug:"meropenem",monographId:"meropenem"},{id:"cap/cap-icu/add-on-for-pseudomonas-risk-factors/meropenem-3",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-icu",subcategoryName:"Severe CAP / ICU Admission",line:"Add-On for Pseudomonas Risk Factors",regimen:"Meropenem 1-2g IV q8h (extended infusion over 3h)",notes:"Reserve for severe septic shock, ESBL/MDR risk, or failure of other agents. Always de-escalate aggressively once cultures return. Extended infusion is standard of care in the ICU.",drug:"meropenem",monographId:"meropenem"},{id:"febrile-neutropenia/high-risk-fn/monotherapy-antipseudomonal-beta-lactam-idsa-201/meropenem-3",diseaseId:"febrile-neutropenia",diseaseName:"Febrile Neutropenia",diseaseIcon:"🩻",subcategoryId:"high-risk-fn",subcategoryName:"High-Risk Febrile Neutropenia",line:"Monotherapy — Antipseudomonal Beta-Lactam (IDSA 2010 First-Line, A-I)",regimen:"Meropenem 1g IV q8h (2g IV q8h for Pseudomonas or suspected resistant organisms)",notes:"IDSA 2010 alternative first-line monotherapy (A-I). Reserve as the broadest coverage option — covers Pseudomonas, ESBL producers, AmpC producers, anaerobes, streptococci. Preferred as empiric first-line in: (1) Patients with prior gram-negative bacteremia due to ESBL-producing organisms, (2) Recent hospitalization in regions with high ESBL prevalence, (3) Clinically unstable or septic shock presentations where broadest coverage is critical, (4) Suspected typhlitis or abdominal source. STEWARDSHIP NOTE: Carbapenems should not be used routinely as first-line when cefepime or pip-tazo are appropriate — carbapenem overuse drives carbapenem-resistant Enterobacterales (CRE) emergence. RENAL DOSING: CrCl 26–50 → 1g q12h; CrCl 10–25 → 500mg q12h; CrCl <10/HD → 500mg q24h.",drug:"meropenem",monographId:"meropenem",evidence:"A-I",evidenceSource:"IDSA 2010",evidenceSourceIds:["idsa-febrile-neutropenia"]},{id:"uti/pyelonephritis/inpatient-complicated-septic-unable-to-tolerate-/meropenem-3",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"pyelonephritis",subcategoryName:"Acute Pyelonephritis",line:"Inpatient (Complicated, Septic, Unable to Tolerate PO)",regimen:"Meropenem 1g IV q8h",notes:"Reserve for ESBL risk, prior MDR organisms, or septic shock. De-escalate aggressively.",drug:"meropenem",monographId:"meropenem"},{id:"uti/complicated-uti/first-line-cuti-with-sepsis/meropenem-3",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"complicated-uti",subcategoryName:"Complicated UTI",line:"First-Line — cUTI WITH Sepsis",regimen:"Meropenem 1g IV q8h (extended infusion over 3h)",notes:"IDSA 2025 includes carbapenems as first-line option for SEPSIS (unlike non-septic cUTI). Use if ESBL risk, prior MDR organisms, or septic shock. Antibiogram step: select agent with ≥90% susceptibility for septic shock, ≥80% for sepsis without shock.",drug:"meropenem",monographId:"meropenem"}],nitrofurantoin:[{id:"amr-gn/ampc-e/preferred-uncomplicated-cystitis/nitrofurantoin-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"ampc-e",subcategoryName:"AmpC β-Lactamase-Producing Enterobacterales (AmpC-E)",line:"Preferred — Uncomplicated Cystitis",regimen:"Nitrofurantoin 100mg PO BID × 5 days",notes:"IDSA 2024 preferred for AmpC-E uncomplicated cystitis. Not a beta-lactam — unaffected by AmpC. Ceftriaxone is also acceptable for uncomplicated cystitis (high urinary concentrations overcome AmpC concerns).",drug:"nitrofurantoin",monographId:"nitrofurantoin"},{id:"amr-gn/esbl-e/preferred-uncomplicated-cystitis/nitrofurantoin-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"esbl-e",subcategoryName:"ESBL-Producing Enterobacterales (ESBL-E)",line:"Preferred — Uncomplicated Cystitis",regimen:"Nitrofurantoin 100mg PO BID × 5 days",notes:"IDSA 2024 preferred for ESBL-E uncomplicated cystitis. NOT affected by ESBL enzymes (different mechanism). Achieves high urinary concentrations. Does NOT achieve systemic levels — for cystitis ONLY, never for pyelonephritis or bacteremia.",drug:"nitrofurantoin",monographId:"nitrofurantoin"},{id:"uti/uncomplicated-cystitis/first-line/nitrofurantoin-1",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"uncomplicated-cystitis",subcategoryName:"Uncomplicated Cystitis",line:"First-Line",regimen:"Nitrofurantoin monohydrate/macrocrystals 100mg PO BID × 5 days",notes:"Preferred agent. COMBINE trial supports potential 3-day course. Avoid if CrCl <30 mL/min (though recent data supports use down to ~20). Not effective for anything beyond the bladder.",drug:"nitrofurantoin",monographId:"nitrofurantoin",evidence:"A-I",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]}],"tmp-smx":[{id:"amr-gn/ampc-e/preferred-uncomplicated-cystitis/tmp-smx-2",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"ampc-e",subcategoryName:"AmpC β-Lactamase-Producing Enterobacterales (AmpC-E)",line:"Preferred — Uncomplicated Cystitis",regimen:"TMP-SMX DS 1 tab PO BID × 3 days",notes:"IDSA 2024 preferred for AmpC-E cystitis if susceptible. Not a beta-lactam substrate.",drug:"tmp-smx",monographId:"tmp-smx"},{id:"amr-gn/esbl-e/preferred-pyelonephritis-complicated-uti/tmp-smx-1",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"esbl-e",subcategoryName:"ESBL-Producing Enterobacterales (ESBL-E)",line:"Preferred — Pyelonephritis / Complicated UTI",regimen:"TMP-SMX DS 1 tab PO BID × 5-7 days",notes:"IDSA 2024 preferred for ESBL-E pyelonephritis/cUTI if susceptible. High urinary AND renal parenchymal concentrations. Oral step-down target from carbapenems. Achieves adequate serum levels for tissue penetration.",drug:"tmp-smx",monographId:"tmp-smx"},{id:"amr-gn/esbl-e/preferred-uncomplicated-cystitis/tmp-smx-2",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"esbl-e",subcategoryName:"ESBL-Producing Enterobacterales (ESBL-E)",line:"Preferred — Uncomplicated Cystitis",regimen:"TMP-SMX DS 1 tab PO BID × 3 days",notes:"IDSA 2024 preferred for ESBL-E uncomplicated cystitis IF susceptible. Not a beta-lactam — unaffected by ESBLs. Co-resistance is common (ESBL-E often carry additional resistance genes), so susceptibility must be confirmed.",drug:"tmp-smx",monographId:"tmp-smx"},{id:"uti/pyelonephritis/outpatient-uncomplicated-tolerating-po-not-septi/tmp-smx-2",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"pyelonephritis",subcategoryName:"Acute Pyelonephritis",line:"Outpatient (Uncomplicated, Tolerating PO, Not Septic)",regimen:"TMP-SMX DS PO BID × 14 days",notes:"Alternative if FQ cannot be used. Requires 14 days (longer than FQ). IDSA recommends a one-time IV dose of ceftriaxone 1g or aminoglycoside with initiation if using TMP-SMX empirically (pending cultures).",drug:"tmp-smx",monographId:"tmp-smx",evidence:"B-II",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]},{id:"uti/uncomplicated-cystitis/first-line/tmp-smx-2",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"uncomplicated-cystitis",subcategoryName:"Uncomplicated Cystitis",line:"First-Line",regimen:"TMP-SMX DS (160/800mg) PO BID × 3 days",notes:"Use only if local resistance <20%. Avoid if used in prior 3 months. Check sulfa allergy. 3-day course is well established.",drug:"tmp-smx",monographId:"tmp-smx",evidence:"A-I",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]}],cefiderocol:[{id:"amr-gn/cre-mbl/preferred-mbl-producing-cre-non-urinary-infectio/cefiderocol-2",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"cre-mbl",subcategoryName:"CRE — Metallo-β-Lactamase Producers (NDM, VIM, IMP)",line:"Preferred — MBL-Producing CRE (Non-Urinary Infections)",regimen:"Cefiderocol 2g IV q8h (infused over 3h)",notes:"IDSA 2024 preferred for MBL-CRE. Siderophore cephalosporin — enters bacteria via iron transporters, bypassing porin-dependent entry. Stable against MBL hydrolysis. ~92% activity against MBL-producing Enterobacterales. Limited clinical trial data specifically for MBL-CRE but clinical trial showed 80% cure vs 0% for BAT in MBL-E infections. Monitor for resistance emergence — described with and without prior cefiderocol exposure.",drug:"cefiderocol",monographId:"cefiderocol"}],ertapenem:[{id:"amr-gn/esbl-e/preferred-non-urinary-infections-bsi-iai-pneumon/ertapenem-2",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"esbl-e",subcategoryName:"ESBL-Producing Enterobacterales (ESBL-E)",line:"Preferred — Non-Urinary Infections (BSI, IAI, Pneumonia)",regimen:"Ertapenem 1g IV daily",notes:"IDSA 2024 preferred for non-critically ill with normal albumin. Once-daily dosing ideal for OPAT. Ertapenem clearance increases with hypoalbuminemia (highly protein-bound) — observational data showed 5× higher mortality in hypoalbuminemic patients receiving ertapenem vs meropenem.",drug:"ertapenem",monographId:"ertapenem"},{id:"amr-gn/esbl-e/preferred-pyelonephritis-complicated-uti/ertapenem-3",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"esbl-e",subcategoryName:"ESBL-Producing Enterobacterales (ESBL-E)",line:"Preferred — Pyelonephritis / Complicated UTI",regimen:"Ertapenem 1g IV daily",notes:"IDSA 2024 preferred when TMP-SMX/FQ are not options (resistance or toxicity). Transition to oral TMP-SMX or FQ when susceptible and clinically improving. NOT for critically ill or hypoalbuminemic patients — use meropenem instead.",drug:"ertapenem",monographId:"ertapenem"},{id:"bacteremia-endocarditis/opat-considerations/opat-friendly-agents-dosing-frequency-matters/ertapenem-4",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"opat-considerations",subcategoryName:"OPAT — Outpatient Parenteral Antibiotic Therapy",line:"OPAT-Friendly Agents — Dosing Frequency Matters",regimen:"Ertapenem 1g IV once daily",notes:"Once-daily carbapenem for ESBL infections, complex polymicrobial infections (including anaerobes). Does NOT cover Pseudomonas or Acinetobacter. Ideal for OPAT when broader coverage is needed. Seizure risk (lower than other carbapenems but still present, especially in renal impairment).",drug:"ertapenem",monographId:"ertapenem"}],ciprofloxacin:[{id:"amr-gn/esbl-e/preferred-pyelonephritis-complicated-uti/ciprofloxacin-2",diseaseId:"amr-gn",diseaseName:"AMR Gram-Negative Infections",diseaseIcon:"🛡️",subcategoryId:"esbl-e",subcategoryName:"ESBL-Producing Enterobacterales (ESBL-E)",line:"Preferred — Pyelonephritis / Complicated UTI",regimen:"Ciprofloxacin 500mg PO BID × 5-7 days (or Levofloxacin 750mg PO daily)",notes:"IDSA 2024 preferred for ESBL-E pyelonephritis/cUTI if susceptible. High bioavailability. However, ESBL-E frequently co-resistant to FQs. Reserve for confirmed susceptible isolates to limit further FQ selection pressure.",drug:"ciprofloxacin",monographId:"ciprofloxacin"},{id:"uti/pyelonephritis/outpatient-uncomplicated-tolerating-po-not-septi/ciprofloxacin-1",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"pyelonephritis",subcategoryName:"Acute Pyelonephritis",line:"Outpatient (Uncomplicated, Tolerating PO, Not Septic)",regimen:"Ciprofloxacin 500mg PO BID × 7 days",notes:"IDSA first-line for outpatient pyelo IF local FQ resistance <10%. 7-day course is established.",drug:"ciprofloxacin",monographId:"ciprofloxacin",evidence:"A-I",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]},{id:"uti/cauti/empiric-pending-cultures-always-de-escalate/ciprofloxacin-3",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"cauti",subcategoryName:"Catheter-Associated UTI (CAUTI)",line:"Empiric (Pending Cultures — Always De-escalate)",regimen:"Ciprofloxacin 500mg PO BID (if can take PO and not critically ill)",notes:"Only oral option with Pseudomonal activity. But FQ resistance is high in catheterized populations — empiric use risky without prior culture data.",drug:"ciprofloxacin",monographId:"ciprofloxacin",evidence:"B-II",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]},{id:"uti/complicated-uti/first-line-cuti-without-sepsis/ciprofloxacin-3",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"complicated-uti",subcategoryName:"Complicated UTI",line:"First-Line — cUTI WITHOUT Sepsis",regimen:"Ciprofloxacin 500mg PO BID or Levofloxacin 750mg PO daily",notes:"IDSA 2025 preferred IF no FQ exposure in past 12 months (Step 2). Advantage: oral administration avoids IV, enables outpatient treatment. AVOID if FQ used in prior 12 months — guideline-specific recommendation.",drug:"ciprofloxacin",monographId:"ciprofloxacin",evidence:"A-I",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]}],ceftriaxone:[{id:"bacteremia-endocarditis/gram-negative-bacteremia/empiric-community-acquired-low-resistance-risk/ceftriaxone-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"gram-negative-bacteremia",subcategoryName:"Gram-Negative Bacteremia",line:"Empiric — Community-Acquired, Low Resistance Risk",regimen:"Ceftriaxone 2g IV daily",notes:"Excellent first-line empiric for community-acquired GN bacteremia from urinary or intra-abdominal source. Covers most community E. coli, Klebsiella, Proteus. Does NOT cover ESBL producers, AmpC producers (Enterobacter, Citrobacter, Serratia), or Pseudomonas. Add metronidazole if intra-abdominal source suspected (anaerobic coverage).",drug:"ceftriaxone",monographId:"ceftriaxone"},{id:"bacteremia-endocarditis/native-valve-ie/streptococcal-native-valve-ie-viridans-group-s-g/ceftriaxone-2",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"native-valve-ie",subcategoryName:"Native Valve Infective Endocarditis",line:"Streptococcal Native Valve IE (Viridans group, S. gallolyticus)",regimen:"Ceftriaxone 2g IV once daily × 4 weeks",notes:"Equivalent efficacy to penicillin G. MAJOR ADVANTAGE: once-daily dosing makes it the preferred agent for OPAT. Can combine with gentamicin for 2-week short course (same criteria as penicillin). S. gallolyticus (formerly S. bovis) endocarditis: ALWAYS get colonoscopy — strong association with colorectal neoplasia (adenomas and carcinomas).",drug:"ceftriaxone",monographId:"ceftriaxone"},{id:"bacteremia-endocarditis/opat-considerations/opat-friendly-agents-dosing-frequency-matters/ceftriaxone-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"opat-considerations",subcategoryName:"OPAT — Outpatient Parenteral Antibiotic Therapy",line:"OPAT-Friendly Agents — Dosing Frequency Matters",regimen:"Ceftriaxone 2g IV once daily",notes:"THE ideal OPAT antibiotic — once-daily dosing, stable in elastomeric pump, broad spectrum, well-tolerated. First-line for Streptococcal IE, GN bacteremia step-down, many osteomyelitis regimens. Biliary sludging/pseudolithiasis risk with prolonged use — monitor LFTs, warn patients about RUQ pain.",drug:"ceftriaxone",monographId:"ceftriaxone"},{id:"bone-joint/septic-arthritis/empiric-pending-cultures/ceftriaxone-2",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"septic-arthritis",subcategoryName:"Septic Arthritis (Native Joint)",line:"Empiric — Pending Cultures",regimen:"Ceftriaxone 2g IV daily (add to vancomycin if GN risk)",notes:"For gram-negative coverage in high-risk patients. Also first-line empiric in suspected gonococcal arthritis (sexually active young adult with migratory polyarthralgia → monoarthritis + skin lesions). NAAT for GC/CT on urogenital, rectal, and pharyngeal sites.",drug:"ceftriaxone",monographId:"ceftriaxone"},{id:"bone-joint/vertebral-osteomyelitis/pathogen-directed-therapy-after-culture-results/ceftriaxone-3",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"vertebral-osteomyelitis",subcategoryName:"Vertebral Osteomyelitis (Native Spine)",line:"Pathogen-Directed Therapy (After Culture Results)",regimen:"Ceftriaxone 2g IV daily × 6 weeks (Streptococci, susceptible GN)",notes:"Once-daily dosing makes this ideal for OPAT. Excellent for Streptococcal vertebral osteomyelitis and susceptible gram-negative infections. Oral step-down: levofloxacin 750mg daily (if susceptible) or amoxicillin 1g TID (for Streptococci).",drug:"ceftriaxone",monographId:"ceftriaxone"},{id:"cap/cap-inpatient/first-line-combination-preferred-by-ats-idsa/ceftriaxone-1",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-inpatient",subcategoryName:"Inpatient CAP (Non-ICU)",line:"First-Line (Combination — Preferred by ATS/IDSA)",regimen:"Ceftriaxone 1-2g IV daily + Azithromycin 500mg IV/PO daily",notes:"The classic inpatient CAP regimen. Beta-lactam covers typicals; macrolide adds atypical coverage + immunomodulatory effects. ATS/IDSA 2019 preferred combination. Note: CAP-START suggests beta-lactam monotherapy may suffice — but most US institutions still use combination.",drug:"ceftriaxone",monographId:"ceftriaxone",evidence:"A-I",evidenceSource:"IDSA/ATS 2019",evidenceSourceIds:["ats-idsa-2019-cap"]},{id:"cap/cap-icu/first-line-always-combination-for-severe-cap/ceftriaxone-1",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-icu",subcategoryName:"Severe CAP / ICU Admission",line:"First-Line (ALWAYS Combination for Severe CAP)",regimen:"Ceftriaxone 2g IV daily + Azithromycin 500mg IV daily",notes:"ATS/IDSA standard for severe CAP. The macrolide is STRONGLY recommended here (not optional like non-ICU). Macrolide immunomodulatory effect is most impactful in severe/bacteremic disease. Duration: minimum 5 days, typically 7 days.",drug:"ceftriaxone",monographId:"ceftriaxone",evidence:"A-I",evidenceSource:"IDSA/ATS 2019",evidenceSourceIds:["ats-idsa-2019-cap"]},{id:"sepsis/sepsis-community/first-line-empiric-no-mdr-mrsa-risk-factors/ceftriaxone-1",diseaseId:"sepsis",diseaseName:"Sepsis & Septic Shock",diseaseIcon:"🔴",subcategoryId:"sepsis-community",subcategoryName:"Community-Acquired Sepsis",line:"First-Line Empiric — No MDR/MRSA Risk Factors",regimen:"Ceftriaxone 2g IV q24h ± Azithromycin 500mg IV/PO q24h (if CAP)",notes:"Preferred for urinary, biliary, and community pneumonia sources. Add azithromycin if atypical pneumonia suspected (CAP). Not reliable for ESBL, AmpC, or Pseudomonas. Excellent CNS penetration for meningitis (2g IV q12h for meningitis dosing).",drug:"ceftriaxone",monographId:"ceftriaxone",evidence:"A-I",evidenceSource:"SSC 2021, IDSA CAP 2019",evidenceSourceIds:["ssc-2021","ats-idsa-2019-cap"]},{id:"uti/pyelonephritis/inpatient-complicated-septic-unable-to-tolerate-/ceftriaxone-1",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"pyelonephritis",subcategoryName:"Acute Pyelonephritis",line:"Inpatient (Complicated, Septic, Unable to Tolerate PO)",regimen:"Ceftriaxone 2g IV daily",notes:"Workhorse empiric. Broad gram-negative coverage. Step down when clinically improved.",drug:"ceftriaxone",monographId:"ceftriaxone"},{id:"uti/cauti/empiric-pending-cultures-always-de-escalate/ceftriaxone-1",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"cauti",subcategoryName:"Catheter-Associated UTI (CAUTI)",line:"Empiric (Pending Cultures — Always De-escalate)",regimen:"Ceftriaxone 1-2g IV daily",notes:"Reasonable empiric for non-critically ill. Narrow once cultures return. Always assess for Pseudomonas risk.",drug:"ceftriaxone",monographId:"ceftriaxone",evidence:"A-I",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]},{id:"uti/complicated-uti/first-line-cuti-without-sepsis/ceftriaxone-1",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"complicated-uti",subcategoryName:"Complicated UTI",line:"First-Line — cUTI WITHOUT Sepsis",regimen:"Ceftriaxone 1-2g IV daily (or cefepime 2g IV q8h if AmpC/Pseudomonas concern)",notes:"IDSA 2025 preferred: 3rd/4th-gen cephalosporins. Carbapenems are NOT first-line for non-septic cUTI — this is a key stewardship change. Reserve carbapenems for sepsis or confirmed ESBL.",drug:"ceftriaxone",monographId:"ceftriaxone",evidence:"A-I",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]}],daptomycin:[{id:"bacteremia-endocarditis/native-valve-ie/mrsa-native-valve-ie/daptomycin-2",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"native-valve-ie",subcategoryName:"Native Valve Infective Endocarditis",line:"MRSA Native Valve IE",regimen:"Daptomycin 8-10 mg/kg IV daily × 6 weeks",notes:"FDA-approved for right-sided S. aureus IE at 6 mg/kg, but most experts use 8-10 mg/kg for all IE. Preferred over vancomycin for MRSA IE by many ID pharmacists because of: concentration-dependent bactericidal activity, less nephrotoxicity, once-daily dosing, no need for therapeutic drug monitoring (just CPK). AHA guidelines list vancomycin as first-line and daptomycin as alternative, but practice is shifting.",drug:"daptomycin",monographId:"daptomycin"},{id:"bacteremia-endocarditis/opat-considerations/opat-friendly-agents-dosing-frequency-matters/daptomycin-3",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"opat-considerations",subcategoryName:"OPAT — Outpatient Parenteral Antibiotic Therapy",line:"OPAT-Friendly Agents — Dosing Frequency Matters",regimen:"Daptomycin 6-10 mg/kg IV once daily",notes:"Excellent OPAT agent for MRSA/VRE: once-daily dosing, no therapeutic drug monitoring needed (just weekly CPK), minimal drug interactions. Gravity infusion over 30 min or IV push over 2 min (push approved for doses ≤500mg). Cost is the main limitation.",drug:"daptomycin",monographId:"daptomycin"},{id:"bacteremia-endocarditis/sab-workup/empiric-pending-susceptibilities/daptomycin-2",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"sab-workup",subcategoryName:"S. aureus Bacteremia — Workup & Risk Stratification",line:"Empiric — Pending Susceptibilities",regimen:"Daptomycin 6-10 mg/kg IV once daily",notes:"Alternative empiric agent when vancomycin cannot be used (allergy, intolerance, renal toxicity). Use ≥8 mg/kg for suspected endocarditis or complicated infections. Rapidly bactericidal. CONTRAINDICATED in pneumonia (surfactant inactivation). If MSSA returns, still de-escalate to beta-lactam.",drug:"daptomycin",monographId:"daptomycin",evidence:"B-II",evidenceSource:"AHA 2015 IE Guideline",evidenceSourceIds:["aha-2015-ie"]},{id:"bacteremia-endocarditis/sab-workup/mrsa-definitive-therapy/daptomycin-2",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"sab-workup",subcategoryName:"S. aureus Bacteremia — Workup & Risk Stratification",line:"MRSA Definitive Therapy",regimen:"Daptomycin 8-10 mg/kg IV once daily",notes:"Preferred alternative to vancomycin for MRSA bacteremia when: vancomycin MIC ≥2, vancomycin intolerance/nephrotoxicity, persistent bacteremia on vancomycin >3-5 days. Dose at ≥8 mg/kg for bacteremia (6 mg/kg is the IE/bacteremia approved dose but many experts go higher). Monitor CPK weekly. If daptomycin MIC ≥2-4, consider ceftaroline or salvage regimens.",drug:"daptomycin",monographId:"daptomycin"},{id:"sepsis/sepsis-community/add-on-for-mrsa-coverage-when-risk-factors-prese/daptomycin-2",diseaseId:"sepsis",diseaseName:"Sepsis & Septic Shock",diseaseIcon:"🔴",subcategoryId:"sepsis-community",subcategoryName:"Community-Acquired Sepsis",line:"Add-On for MRSA Coverage (When Risk Factors Present)",regimen:"Daptomycin 8–10mg/kg IV q24h (high-dose for bacteremia/endocarditis)",notes:"Alternative to vancomycin for MRSA bacteremia — non-inferior to vancomycin in RCTs. Preferred if: vancomycin MIC ≥2, VRE enterococcal bacteremia, or prior vancomycin nephrotoxicity. Do NOT use for pneumonia (inactivated by pulmonary surfactant). Monitor CPK weekly for myopathy.",drug:"daptomycin",monographId:"daptomycin",evidence:"A-I",evidenceSource:"Fowler et al., NEJM 2006",evidenceSourceIds:["fowler-2006-daptomycin"]},{id:"ssti/purulent-ssti/first-line-moderate-severe-inpatient-iv/daptomycin-2",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"purulent-ssti",subcategoryName:"Purulent SSTI (Abscess, Furuncle, Carbuncle)",line:"First-Line — Moderate/Severe (Inpatient, IV)",regimen:"Daptomycin 4-6 mg/kg IV once daily",notes:"FDA-approved for complicated SSTIs at 4mg/kg. Many experts dose 6mg/kg for serious infections. Rapidly bactericidal against MRSA. MUST NOT use for pneumonia (inactivated by pulmonary surfactant). Advantages: once-daily dosing, no nephrotoxicity at standard doses. Monitor CPK weekly.",drug:"daptomycin",monographId:"daptomycin"}],vancomycin:[{id:"bacteremia-endocarditis/native-valve-ie/mrsa-native-valve-ie/vancomycin-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"native-valve-ie",subcategoryName:"Native Valve Infective Endocarditis",line:"MRSA Native Valve IE",regimen:"Vancomycin IV (AUC/MIC 400-600) × 6 weeks",notes:"Standard therapy for MRSA IE. AUC-guided dosing with Bayesian software. Monitor renal function closely — 6 weeks of vancomycin carries significant nephrotoxicity risk. Consider early switch to daptomycin if renal function deteriorates.",drug:"vancomycin",monographId:"vancomycin"},{id:"bacteremia-endocarditis/sab-workup/empiric-pending-susceptibilities/vancomycin-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"sab-workup",subcategoryName:"S. aureus Bacteremia — Workup & Risk Stratification",line:"Empiric — Pending Susceptibilities",regimen:"Vancomycin IV (AUC/MIC target 400-600)",notes:"Empiric first-line for SAB until MSSA vs MRSA is determined. AUC-guided dosing is now the standard (2020 consensus) — replaces trough-based dosing. Typical loading dose: 25-30 mg/kg (actual body weight), then maintenance guided by AUC. CRITICAL: once susceptibilities return, de-escalate MSSA to cefazolin/nafcillin immediately — vancomycin is INFERIOR to beta-lactams for MSSA (slower bacteremia clearance, higher mortality in some studies).",drug:"vancomycin",monographId:"vancomycin",evidence:"A-I",evidenceSource:"AHA 2015 IE Guideline",evidenceSourceIds:["aha-2015-ie"]},{id:"bacteremia-endocarditis/sab-workup/mrsa-definitive-therapy/vancomycin-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"sab-workup",subcategoryName:"S. aureus Bacteremia — Workup & Risk Stratification",line:"MRSA Definitive Therapy",regimen:"Vancomycin IV (AUC/MIC 400-600)",notes:"Standard of care for MRSA bacteremia. AUC-guided dosing with Bayesian software is preferred. If vancomycin MIC ≥2 by broth microdilution (≥2 by E-test is less reliable), consider switching to daptomycin — treatment failure risk increases with higher MICs (MIC creep). Do NOT add rifampicin routinely (ARREST trial — no benefit, added toxicity). Duration: 14 days minimum for uncomplicated, 4-6 weeks for IE/complicated.",drug:"vancomycin",monographId:"vancomycin"},{id:"bone-joint/septic-arthritis/empiric-pending-cultures/vancomycin-1",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"septic-arthritis",subcategoryName:"Septic Arthritis (Native Joint)",line:"Empiric — Pending Cultures",regimen:"Vancomycin IV (AUC-guided)",notes:"First-line empiric for native joint septic arthritis. Covers MRSA and MSSA (though inferior to beta-lactams for MSSA — will de-escalate once cultures return). Most septic arthritis is gram-positive (S. aureus 40-60%, Streptococci 15-20%). Add gram-negative coverage (ceftriaxone) if: immunocompromised, IDU, healthcare-associated, GI/GU source suspected.",drug:"vancomycin",monographId:"vancomycin"},{id:"bone-joint/vertebral-osteomyelitis/empiric-when-antibiotics-cannot-wait/vancomycin-1",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"vertebral-osteomyelitis",subcategoryName:"Vertebral Osteomyelitis (Native Spine)",line:"Empiric — When Antibiotics Cannot Wait",regimen:"Vancomycin IV (AUC-guided) + Ceftriaxone 2g IV daily",notes:"Covers MRSA + MSSA + Streptococci + most Enterobacterales. This is the standard empiric combination when you must start before cultures. Vancomycin for MRSA, ceftriaxone for gram-negatives and Streptococci. If cultures return MSSA, de-escalate to cefazolin immediately. If epidural abscess with concern for Pseudomonas (post-procedural, healthcare-associated): substitute cefepime for ceftriaxone.",drug:"vancomycin",monographId:"vancomycin"},{id:"bone-joint/vertebral-osteomyelitis/pathogen-directed-therapy-after-culture-results/vancomycin-2",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"vertebral-osteomyelitis",subcategoryName:"Vertebral Osteomyelitis (Native Spine)",line:"Pathogen-Directed Therapy (After Culture Results)",regimen:"Vancomycin IV (AUC-guided) × 6 weeks (MRSA)",notes:"Standard for MRSA vertebral osteomyelitis. AUC/MIC 400-600. Monitor renal function closely over 6-week course. Oral step-down options for MRSA: TMP-SMX DS 2 tabs BID, linezolid 600mg BID (monitor for myelosuppression — limit to 4-6 weeks if possible), or doxycycline 100mg BID (if susceptible). Some ID physicians use daptomycin as the initial IV agent then step down.",drug:"vancomycin",monographId:"vancomycin"},{id:"cap/cap-icu/add-on-for-mrsa-risk-factors/vancomycin-1",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-icu",subcategoryName:"Severe CAP / ICU Admission",line:"Add-On for MRSA Risk Factors",regimen:"Vancomycin IV (AUC/MIC-guided dosing, target AUC 400-600)",notes:"Add if: prior MRSA infection/colonization, IVDU, post-influenza necrotizing pneumonia, cavitation/empyema. Check nasal MRSA swab — if negative, de-escalate within 48h. AUC-guided dosing is now preferred over trough-based (2020 vancomycin consensus guidelines).",drug:"vancomycin",monographId:"vancomycin"},{id:"hap-vap/hap-mdr-risk/add-mrsa-coverage-if-risk-factors-present/vancomycin-1",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"hap-mdr-risk",subcategoryName:"HAP — MDR Risk Factors OR High Mortality Risk",line:"ADD MRSA Coverage (if risk factors present)",regimen:"Vancomycin IV — AUC/MIC-guided dosing (target AUC 400-600 mg·h/L)",notes:"ATS/IDSA 2016: add MRSA coverage if: IV antibiotics in prior 90 days, unit with >20% MRSA prevalence (or unknown), or prior MRSA colonization/infection. AUC-guided dosing is now standard (2020 vancomycin consensus). Check nasal MRSA swab — if negative, de-escalate within 48-72h.",drug:"vancomycin",monographId:"vancomycin",evidence:"A-I",evidenceSource:"IDSA/ATS 2016",evidenceSourceIds:["ats-idsa-2016-hap-vap"]},{id:"sepsis/sepsis-community/add-on-for-mrsa-coverage-when-risk-factors-prese/vancomycin-1",diseaseId:"sepsis",diseaseName:"Sepsis & Septic Shock",diseaseIcon:"🔴",subcategoryId:"sepsis-community",subcategoryName:"Community-Acquired Sepsis",line:"Add-On for MRSA Coverage (When Risk Factors Present)",regimen:"Vancomycin IV — AUC-guided dosing (target AUC/MIC 400–600 per ASHP/IDSA 2020)",notes:"Add empirically when: prior MRSA infection/colonization, HD patient, IVDU, recent hospitalization within 90 days, suspected catheter-related BSI, skin/soft tissue source with MRSA risk, septic shock without clear source. De-escalate at 48–72h if blood cultures negative for MRSA and gram-positive not identified. AUC-guided dosing with pharmacy consult required.",drug:"vancomycin",monographId:"vancomycin",evidence:"A-I",evidenceSource:"SSC 2021; ASHP/IDSA Vancomycin Guidelines 2020",evidenceSourceIds:["ssc-2021","ashp-idsa-pids-2020-vancomycin"]}],cefazolin:[{id:"bacteremia-endocarditis/native-valve-ie/mssa-native-valve-ie/cefazolin-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"native-valve-ie",subcategoryName:"Native Valve Infective Endocarditis",line:"MSSA Native Valve IE",regimen:"Cefazolin 2g IV q8h × 6 weeks",notes:"Preferred over nafcillin/oxacillin based on safety profile and practical advantages (q8h dosing enables OPAT). Non-inferior to nafcillin in multiple observational studies. AHA 2015 lists nafcillin/oxacillin as first-line but most ID pharmacists and many ID physicians have shifted to cefazolin.",drug:"cefazolin",monographId:"cefazolin",evidence:"A-I",evidenceSource:"AHA 2015 IE Guideline",evidenceSourceIds:["aha-2015-ie"]},{id:"bacteremia-endocarditis/opat-considerations/opat-friendly-agents-dosing-frequency-matters/cefazolin-2",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"opat-considerations",subcategoryName:"OPAT — Outpatient Parenteral Antibiotic Therapy",line:"OPAT-Friendly Agents — Dosing Frequency Matters",regimen:"Cefazolin 2g IV q8h (or q12h with probenecid in select cases)",notes:"Workhorse for MSSA infections (bacteremia, endocarditis, osteomyelitis). Q8h dosing is manageable with elastomeric pump (24h pump refilled daily by home health). The probenecid trick (1g PO BID) extends half-life for potential q12h dosing — used at some OPAT programs, limited evidence.",drug:"cefazolin",monographId:"cefazolin"},{id:"bacteremia-endocarditis/sab-workup/mssa-definitive-therapy/cefazolin-1",diseaseId:"bacteremia-endocarditis",diseaseName:"Bacteremia & Endocarditis",diseaseIcon:"🩸",subcategoryId:"sab-workup",subcategoryName:"S. aureus Bacteremia — Workup & Risk Stratification",line:"MSSA Definitive Therapy",regimen:"Cefazolin 2g IV q8h",notes:"PREFERRED agent for MSSA bacteremia and MSSA IE (native valve). Multiple observational studies and meta-analyses show non-inferiority or superiority to nafcillin/oxacillin with fewer adverse effects (less nephrotoxicity, less hepatotoxicity, less phlebitis). Q8h dosing is practical for OPAT. Duration: 14 days for uncomplicated SAB, 4-6 weeks for IE or complicated SAB.",drug:"cefazolin",monographId:"cefazolin",evidence:"A-I",evidenceSource:"AHA 2015 IE Guideline",evidenceSourceIds:["aha-2015-ie"]},{id:"bone-joint/septic-arthritis/pathogen-directed-therapy/cefazolin-1",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"septic-arthritis",subcategoryName:"Septic Arthritis (Native Joint)",line:"Pathogen-Directed Therapy",regimen:"Cefazolin 2g IV q8h × 3-4 weeks (MSSA)",notes:"De-escalate from vancomycin upon MSSA confirmation. Duration: 3-4 weeks for native joint septic arthritis (shorter than osteomyelitis if no bone involvement). Oral step-down per OVIVA: consider after 1-2 weeks IV if clinically responding, using bone-penetrating oral agents.",drug:"cefazolin",monographId:"cefazolin"},{id:"bone-joint/vertebral-osteomyelitis/pathogen-directed-therapy-after-culture-results/cefazolin-1",diseaseId:"bone-joint",diseaseName:"Bone & Joint Infections",diseaseIcon:"🦴",subcategoryId:"vertebral-osteomyelitis",subcategoryName:"Vertebral Osteomyelitis (Native Spine)",line:"Pathogen-Directed Therapy (After Culture Results)",regimen:"Cefazolin 2g IV q8h × 6 weeks (MSSA)",notes:"PREFERRED for MSSA vertebral osteomyelitis. Transition to oral step-down after initial IV period per OVIVA data: high-dose oral agents with bone penetration (e.g., levofloxacin 750mg daily + rifampin 300-450mg BID for Staph, or TMP-SMX DS 2 tabs BID for MSSA). CRP trending guides response.",drug:"cefazolin",monographId:"cefazolin"},{id:"ssti/nonpurulent-ssti/first-line-moderate-severe-inpatient-iv/cefazolin-1",diseaseId:"ssti",diseaseName:"Skin & Soft Tissue Infections",diseaseIcon:"🩹",subcategoryId:"nonpurulent-ssti",subcategoryName:"Non-Purulent SSTI (Cellulitis & Erysipelas)",line:"First-Line — Moderate/Severe (Inpatient, IV)",regimen:"Cefazolin 2g IV q8h",notes:"IDSA 2014 first-line IV for non-purulent cellulitis requiring hospitalization. MSSA + Streptococcal coverage. The simplest, narrowest IV option. No MRSA coverage — add vancomycin only if MRSA risk factors present. Convert to oral cephalexin when improving.",drug:"cefazolin",monographId:"cefazolin"}],bezlotoxumab:[{id:"c-difficile/first-recurrence/adjunctive-recurrence-prevention/bezlotoxumab-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"first-recurrence",subcategoryName:"First Recurrence",line:"Adjunctive — Recurrence Prevention",regimen:"Bezlotoxumab 10 mg/kg IV × 1 dose (during CDI antibiotic treatment)",notes:"Strongly consider for first recurrence — the MODIFY trials enrolled patients with recurrent CDI and showed benefit. Give as single infusion during the CDI treatment course. Particularly indicated if: age ≥65, immunocompromised, severe CDI, CDI while on concurrent antibiotics, NAP1/027 strain. NNT ~8-10. Cost ~$4,500 but may be cost-effective if it prevents hospitalization for subsequent recurrence.",drug:"bezlotoxumab",monographId:"bezlotoxumab"},{id:"c-difficile/initial-severe/adjunctive-recurrence-prevention-in-severe-cdi/bezlotoxumab-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"initial-severe",subcategoryName:"Initial Episode — Severe CDI",line:"Adjunctive — Recurrence Prevention in Severe CDI",regimen:"Bezlotoxumab 10 mg/kg IV × 1 dose (during CDI antibiotic treatment)",notes:"Consider bezlotoxumab for severe CDI patients at high recurrence risk: age ≥65, immunocompromised, prior CDI episode, severe CDI (this category), NAP1/027 strain. The MODIFY trials showed ~10% absolute reduction in recurrence. NNT ~8-10. Given as a single infusion during the CDI treatment course. Does NOT treat active CDI — it prevents recurrence by neutralizing toxin B. Cost: ~$4,500 per infusion. CAUTION: heart failure exacerbation reported in patients with underlying CHF — use with caution in decompensated HF.",drug:"bezlotoxumab",monographId:"bezlotoxumab"},{id:"c-difficile/multiple-recurrences/adjunctive-for-multiple-recurrences/bezlotoxumab-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"multiple-recurrences",subcategoryName:"Multiple Recurrences (≥2nd Recurrence)",line:"Adjunctive for Multiple Recurrences",regimen:"Bezlotoxumab 10 mg/kg IV × 1 (during CDI antibiotic treatment, before FMT)",notes:"Can be used in combination with FMT for multiply recurrent CDI. Give during the antibiotic treatment phase (before FMT). Neutralizes toxin B to reduce recurrence risk while microbiome restoration occurs. Cost-effective in multiply recurrent patients given the high per-episode hospitalization cost.",drug:"bezlotoxumab",monographId:"bezlotoxumab"}],"vancomycin-oral":[{id:"c-difficile/first-recurrence/alternative-first-recurrence/vancomycin-oral-2",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"first-recurrence",subcategoryName:"First Recurrence",line:"Alternative — First Recurrence",regimen:"Vancomycin 125mg PO QID × 10 days (if initial episode treated with metronidazole)",notes:"If the initial episode was treated with metronidazole (which it shouldn't have been per 2021 guidelines, but sometimes is), a standard vancomycin course is appropriate for first recurrence. This effectively 'upgrades' therapy.",drug:"vancomycin-oral",monographId:"vancomycin-oral"},{id:"c-difficile/fulminant/fulminant-cdi-standard-medical-therapy/vancomycin-oral-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"fulminant",subcategoryName:"Fulminant CDI (Previously 'Severe, Complicated')",line:"Fulminant CDI — Standard Medical Therapy",regimen:"Vancomycin 500mg PO (or via NG tube) QID",notes:"HIGHER DOSE than standard CDI — 500mg QID (not 125mg). The rationale: in fulminant disease with ileus, drug delivery to the colon may be impaired. Higher oral doses may achieve better colonic concentrations. Administered PO or via nasogastric tube if the patient cannot swallow. Fidaxomicin is NOT well-studied in fulminant CDI — vancomycin is the standard here.",drug:"vancomycin-oral",monographId:"vancomycin-oral"},{id:"c-difficile/initial-non-severe/alternative-first-line/vancomycin-oral-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"initial-non-severe",subcategoryName:"Initial Episode — Non-Severe CDI",line:"Alternative — First-Line",regimen:"Vancomycin 125mg PO QID × 10 days",notes:"Standard of care before 2021 guideline update. Still highly effective for initial cure (clinical cure rate ~90%). IDSA/SHEA 2021 made this 'alternative' rather than 'preferred' because of higher recurrence rate compared to fidaxomicin. If fidaxomicin is unavailable or cost-prohibitive, oral vancomycin remains an excellent option. Do NOT increase the dose to 250mg or 500mg for non-severe CDI — no added benefit, only added cost. IV vancomycin does NOT work for CDI (does not reach the colon).",drug:"vancomycin-oral",monographId:"vancomycin-oral"},{id:"c-difficile/initial-severe/preferred-severe-cdi-idsa-shea-2021/vancomycin-oral-2",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"initial-severe",subcategoryName:"Initial Episode — Severe CDI",line:"Preferred — Severe CDI (IDSA/SHEA 2021)",regimen:"Vancomycin 125mg PO QID × 10 days",notes:"Alternative first-line for severe CDI. Same dose as non-severe — 125mg QID is sufficient. Clinical cure rates are high (~85-90%). The distinction between 'preferred' (fidaxomicin) and 'alternative' (vancomycin) is driven by recurrence data, not acute cure rates. If fidaxomicin is unavailable, vancomycin is the standard.",drug:"vancomycin-oral",monographId:"vancomycin-oral"}],fidaxomicin:[{id:"c-difficile/first-recurrence/preferred-first-recurrence-idsa-shea-2021/fidaxomicin-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"first-recurrence",subcategoryName:"First Recurrence",line:"Preferred — First Recurrence (IDSA/SHEA 2021)",regimen:"Fidaxomicin 200mg PO BID × 10 days",notes:"STRONGLY preferred for first recurrence (IDSA/SHEA 2021). If the initial episode was treated with vancomycin, switching to fidaxomicin reduces subsequent recurrence by ~50% (EXTEND trial). If the initial episode was treated with fidaxomicin and still recurred, fidaxomicin can be repeated — there is no evidence of diminishing returns. The narrow spectrum preserving protective anaerobes is the key mechanistic advantage.",drug:"fidaxomicin",monographId:"fidaxomicin"},{id:"c-difficile/initial-non-severe/preferred-first-line-idsa-shea-2021/fidaxomicin-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"initial-non-severe",subcategoryName:"Initial Episode — Non-Severe CDI",line:"Preferred — First-Line (IDSA/SHEA 2021)",regimen:"Fidaxomicin 200mg PO BID × 10 days",notes:"IDSA/SHEA 2021 PREFERRED over vancomycin for initial CDI (conditional recommendation based on EXTEND trial data). Advantage: 50% lower recurrence rate compared to vancomycin for non-NAP1 strains. Mechanism of benefit: narrow-spectrum macrolide that kills C. diff while sparing protective anaerobes (Bacteroides). Allows microbiome recovery. LIMITATION: cost (~$3,000-5,000/course vs ~$50-100 for vancomycin). For non-severe initial CDI, both are effective — the fidaxomicin advantage is primarily in reducing RECURRENCE.",drug:"fidaxomicin",monographId:"fidaxomicin",evidence:"A-I",evidenceSource:"IDSA/SHEA 2021",evidenceSourceIds:["idsa-shea-2021-cdi"]},{id:"c-difficile/initial-severe/preferred-severe-cdi-idsa-shea-2021/fidaxomicin-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"initial-severe",subcategoryName:"Initial Episode — Severe CDI",line:"Preferred — Severe CDI (IDSA/SHEA 2021)",regimen:"Fidaxomicin 200mg PO BID × 10 days",notes:"IDSA/SHEA 2021 lists fidaxomicin as preferred for severe CDI as well (conditional recommendation). The EXTEND trial included severe CDI patients and fidaxomicin maintained its recurrence advantage. Same dosing as non-severe. If the patient progresses to fulminant despite fidaxomicin, transition to the fulminant CDI protocol.",drug:"fidaxomicin",monographId:"fidaxomicin"}],metronidazole:[{id:"c-difficile/fulminant/fulminant-cdi-standard-medical-therapy/metronidazole-2",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"fulminant",subcategoryName:"Fulminant CDI (Previously 'Severe, Complicated')",line:"Fulminant CDI — Standard Medical Therapy",regimen:"Metronidazole 500mg IV q8h",notes:"ADJUNCTIVE to oral/rectal vancomycin — IV metronidazole reaches colonic tissue via systemic circulation. This is the ONE remaining indication where IV metronidazole adds value in CDI. When the colon is atonic (ileus), oral drugs cannot reliably reach the diseased tissue. IV metronidazole provides a secondary route of drug delivery. Duration: until clinical improvement or colectomy.",drug:"metronidazole",monographId:"metronidazole"},{id:"c-difficile/initial-non-severe/not-recommended-metronidazole-for-cdi-idsa-shea-/metronidazole-1",diseaseId:"c-difficile",diseaseName:"Clostridioides difficile Infection",diseaseIcon:"🦠",subcategoryId:"initial-non-severe",subcategoryName:"Initial Episode — Non-Severe CDI",line:"Not Recommended — Metronidazole for CDI (IDSA/SHEA 2021)",regimen:"Metronidazole 500mg PO TID × 10 days",notes:"DOWNGRADED in 2017 guidelines, further de-emphasized in 2021. Inferior to vancomycin for clinical cure (especially for severe CDI) and has higher recurrence rates. IDSA/SHEA 2021: metronidazole should ONLY be used when vancomycin and fidaxomicin are unavailable. Some guidelines allow metronidazole for non-severe INITIAL episode only, but this is increasingly seen as suboptimal. The only remaining role for metronidazole in CDI: IV metronidazole as ADJUNCTIVE therapy in fulminant CDI (reaches colonic tissue via systemic circulation when oral drugs cannot reach the colon due to ileus).",drug:"metronidazole",monographId:"metronidazole"}],clindamycin:[{id:"cap/aspiration-pneumonia/alternatives/clindamycin-2",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"aspiration-pneumonia",subcategoryName:"Aspiration Pneumonia",line:"Alternatives",regimen:"Clindamycin 600mg IV q8h (or 300-450mg PO QID)",notes:"Traditional aspiration pneumonia drug — excellent anaerobic and streptococcal coverage. Fallen somewhat out of favor due to high C. diff risk. Still useful for penicillin-allergic patients or lung abscess.",drug:"clindamycin",monographId:"clindamycin"}],"ampicillin-sulbactam":[{id:"cap/cap-inpatient/first-line-combination-preferred-by-ats-idsa/ampicillin-sulbactam-2",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-inpatient",subcategoryName:"Inpatient CAP (Non-ICU)",line:"First-Line (Combination — Preferred by ATS/IDSA)",regimen:"Ampicillin-Sulbactam 3g IV q6h + Azithromycin 500mg IV/PO daily",notes:"Alternative beta-lactam backbone. Better anaerobic coverage than ceftriaxone (relevant if aspiration component suspected). Covers H. influenzae and M. catarrhalis beta-lactamase producers.",drug:"ampicillin-sulbactam",monographId:"ampicillin-sulbactam",evidence:"A-I",evidenceSource:"IDSA/ATS 2019",evidenceSourceIds:["ats-idsa-2019-cap"]}],levofloxacin:[{id:"cap/cap-inpatient/second-line-monotherapy-respiratory-fq/levofloxacin-1",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-inpatient",subcategoryName:"Inpatient CAP (Non-ICU)",line:"Second-Line (Monotherapy — Respiratory FQ)",regimen:"Levofloxacin 750mg IV/PO daily",notes:"Monotherapy alternative. Covers typicals + atypicals in one drug. 100% oral bioavailability — switch to PO as soon as patient can swallow. Reserve for beta-lactam allergy or when combination therapy not feasible.",drug:"levofloxacin",monographId:"levofloxacin"},{id:"cap/cap-outpatient-comorbid/second-line-monotherapy-respiratory-fluoroquinol/levofloxacin-1",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-outpatient-comorbid",subcategoryName:"Outpatient CAP — With Comorbidities",line:"Second-Line (Monotherapy — Respiratory Fluoroquinolone)",regimen:"Levofloxacin 750mg PO daily × 5 days",notes:"Respiratory FQ covers typicals + atypicals in one agent. Reserve as second-line per ATS/IDSA due to FDA boxed warnings and collateral damage. Appropriate when beta-lactam allergy is severe or combination therapy not feasible.",drug:"levofloxacin",monographId:"levofloxacin"},{id:"hap-vap/hap-no-mdr/first-line-monotherapy-standard-risk/levofloxacin-3",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"hap-no-mdr",subcategoryName:"HAP — No MDR Risk Factors, Not High Mortality Risk",line:"First-Line (Monotherapy — Standard Risk)",regimen:"Levofloxacin 750mg IV daily",notes:"ATS/IDSA lists as an option. Covers typicals + atypicals. BUT: high rates of FQ resistance in hospital-acquired gram-negatives limit utility. Check local antibiogram before selecting. 100% bioavailability — PO = IV.",drug:"levofloxacin",monographId:"levofloxacin",evidence:"B-II",evidenceSource:"IDSA/ATS 2016",evidenceSourceIds:["ats-idsa-2016-hap-vap"]}],moxifloxacin:[{id:"cap/cap-inpatient/second-line-monotherapy-respiratory-fq/moxifloxacin-2",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-inpatient",subcategoryName:"Inpatient CAP (Non-ICU)",line:"Second-Line (Monotherapy — Respiratory FQ)",regimen:"Moxifloxacin 400mg IV/PO daily",notes:"Superior pneumococcal activity vs. levo. NO Pseudomonal coverage. Higher QT prolongation risk. No IV-to-PO dose change needed. No renal adjustment.",drug:"moxifloxacin",monographId:"moxifloxacin"},{id:"cap/cap-outpatient-comorbid/second-line-monotherapy-respiratory-fluoroquinol/moxifloxacin-2",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-outpatient-comorbid",subcategoryName:"Outpatient CAP — With Comorbidities",line:"Second-Line (Monotherapy — Respiratory Fluoroquinolone)",regimen:"Moxifloxacin 400mg PO daily × 5 days",notes:"Best anti-pneumococcal FQ. Excellent bioavailability. NO Pseudomonas activity (unlike levo). Higher QT risk than levofloxacin. No renal adjustment needed. AVOID if any QT concern.",drug:"moxifloxacin",monographId:"moxifloxacin"}],amoxicillin:[{id:"cap/cap-outpatient-healthy/first-line-pick-one-monotherapy/amoxicillin-1",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-outpatient-healthy",subcategoryName:"Outpatient CAP — No Comorbidities",line:"First-Line (Pick ONE — Monotherapy)",regimen:"Amoxicillin 1g PO TID × 5 days",notes:"ATS/IDSA 2019 first-line. HIGH-DOSE (1g, not 500mg) targets intermediate-resistant S. pneumoniae. Excellent safety profile. STEP trial supports even 3-day courses if rapid clinical improvement.",drug:"amoxicillin",monographId:"amoxicillin",evidence:"A-I",evidenceSource:"IDSA/ATS 2019",evidenceSourceIds:["ats-idsa-2019-cap"]}],azithromycin:[{id:"cap/cap-outpatient-healthy/first-line-pick-one-monotherapy/azithromycin-3",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-outpatient-healthy",subcategoryName:"Outpatient CAP — No Comorbidities",line:"First-Line (Pick ONE — Monotherapy)",regimen:"Azithromycin 500mg PO day 1, then 250mg daily × 4 days (Z-pack)",notes:"Covers atypicals well. HOWEVER: Rising S. pneumoniae macrolide resistance (~30-40% in US) is a concern. ATS/IDSA 2019 only recommends as monotherapy where local pneumococcal macrolide resistance <25%. QT risk. Many ID physicians now prefer doxycycline over azithromycin.",drug:"azithromycin",monographId:"azithromycin",evidence:"A-I",evidenceSource:"IDSA/ATS 2019",evidenceSourceIds:["ats-idsa-2019-cap"]}],doxycycline:[{id:"cap/cap-outpatient-healthy/first-line-pick-one-monotherapy/doxycycline-2",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-outpatient-healthy",subcategoryName:"Outpatient CAP — No Comorbidities",line:"First-Line (Pick ONE — Monotherapy)",regimen:"Doxycycline 100mg PO BID × 5 days",notes:"Covers typicals AND atypicals (Mycoplasma, Chlamydophila). Good alternative for penicillin-allergic patients. Avoids azithromycin resistance selection. Well-tolerated.",drug:"doxycycline",monographId:"doxycycline",evidence:"A-I",evidenceSource:"IDSA/ATS 2019",evidenceSourceIds:["ats-idsa-2019-cap"]}],linezolid:[{id:"cap/cap-icu/add-on-for-mrsa-risk-factors/linezolid-2",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-icu",subcategoryName:"Severe CAP / ICU Admission",line:"Add-On for MRSA Risk Factors",regimen:"Linezolid 600mg IV/PO BID",notes:"Alternative to vancomycin for MRSA pneumonia. Some data suggests better lung penetration. 100% oral bioavailability. Myelosuppression risk with courses >14 days. Monitor CBC weekly. Serotonin syndrome risk with SSRIs/MAOIs.",drug:"linezolid",monographId:"linezolid"},{id:"hap-vap/hap-mdr-risk/add-mrsa-coverage-if-risk-factors-present/linezolid-2",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"hap-mdr-risk",subcategoryName:"HAP — MDR Risk Factors OR High Mortality Risk",line:"ADD MRSA Coverage (if risk factors present)",regimen:"Linezolid 600mg IV/PO BID",notes:"Alternative to vancomycin. Potential advantages in pneumonia: better lung penetration, 100% oral bioavailability, no renal dosing. ZEPHyR trial showed linezolid non-inferior to vancomycin for MRSA nosocomial pneumonia with some secondary outcome advantages. Risk: myelosuppression (>14 days), serotonin syndrome with SSRIs.",drug:"linezolid",monographId:"linezolid",evidence:"A-I",evidenceSource:"IDSA/ATS 2016",evidenceSourceIds:["ats-idsa-2016-hap-vap"]}],"pip-tazo":[{id:"cap/cap-icu/add-on-for-pseudomonas-risk-factors/pip-tazo-1",diseaseId:"cap",diseaseName:"Community-Acquired Pneumonia",diseaseIcon:"🫁",subcategoryId:"cap-icu",subcategoryName:"Severe CAP / ICU Admission",line:"Add-On for Pseudomonas Risk Factors",regimen:"Piperacillin-tazobactam 4.5g IV q6h (extended infusion over 4h)",notes:"Replace ceftriaxone with pip-tazo + azithromycin or FQ. Extended infusion critical for optimizing time above MIC. Consider adding an aminoglycoside or anti-pseudomonal FQ for double coverage in critically ill.",drug:"pip-tazo",monographId:"pip-tazo"},{id:"uti/pyelonephritis/inpatient-complicated-septic-unable-to-tolerate-/pip-tazo-2",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"pyelonephritis",subcategoryName:"Acute Pyelonephritis",line:"Inpatient (Complicated, Septic, Unable to Tolerate PO)",regimen:"Piperacillin-tazobactam 3.375g IV q6h (or 4.5g q8h EI)",notes:"Use if Pseudomonas risk or healthcare-associated exposure. Extended infusion preferred.",drug:"pip-tazo",monographId:"pip-tazo"},{id:"uti/cauti/empiric-pending-cultures-always-de-escalate/pip-tazo-2",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"cauti",subcategoryName:"Catheter-Associated UTI (CAUTI)",line:"Empiric (Pending Cultures — Always De-escalate)",regimen:"Piperacillin-tazobactam 4.5g IV q8h (EI over 4h)",notes:"Use if Pseudomonas or MDR risk (prior cultures, healthcare exposure). Extended infusion recommended.",drug:"pip-tazo",monographId:"pip-tazo",evidence:"B-II",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]},{id:"uti/complicated-uti/first-line-cuti-without-sepsis/pip-tazo-2",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"complicated-uti",subcategoryName:"Complicated UTI",line:"First-Line — cUTI WITHOUT Sepsis",regimen:"Piperacillin-tazobactam 3.375g IV q6h (or 4.5g q8h extended infusion)",notes:"IDSA 2025 preferred empiric option. Extended infusion (over 4h) optimizes PK/PD. Appropriate when broader coverage desired (Pseudomonas risk).",drug:"pip-tazo",monographId:"pip-tazo",evidence:"A-I",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]}],fluconazole:[{id:"fungal-infections/antifungal-stewardship/stewardship-echinocandin-to-fluconazole-de-escal/fluconazole-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"antifungal-stewardship",subcategoryName:"Antifungal Stewardship & De-escalation",line:"Stewardship — Echinocandin-to-Fluconazole De-escalation",regimen:"Switch echinocandin → fluconazole 400 mg PO daily",notes:"CRITERIA FOR SAFE DE-ESCALATION: (1) Candida species confirmed susceptible to fluconazole (C. albicans, C. tropicalis, C. parapsilosis with MIC ≤2), (2) patient clinically improving (afebrile, hemodynamically stable, off vasopressors), (3) blood cultures clearing, (4) no metastatic complications (endophthalmitis, endocarditis, osteomyelitis), (5) able to tolerate oral medications. Average time to de-escalation: 5–7 days. This is the single highest-impact antifungal stewardship intervention.",drug:"fluconazole",monographId:"fluconazole"},{id:"fungal-infections/antifungal-stewardship/stewardship-iv-to-po-azole-conversion/fluconazole-2",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"antifungal-stewardship",subcategoryName:"Antifungal Stewardship & De-escalation",line:"Stewardship — IV-to-PO Azole Conversion",regimen:"Switch fluconazole IV → same dose PO",notes:"Fluconazole oral bioavailability ~90%. Same dose IV and PO. One of the easiest IV-to-PO conversions in all of infectious disease. No food restrictions. Pharmacy should proactively recommend this conversion.",drug:"fluconazole",monographId:"fluconazole"},{id:"fungal-infections/antifungal-stewardship/stewardship-prophylaxis-review/fluconazole-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"antifungal-stewardship",subcategoryName:"Antifungal Stewardship & De-escalation",line:"Stewardship — Prophylaxis Review",regimen:"Review appropriateness of antifungal prophylaxis",notes:"Appropriate prophylaxis: (1) Fluconazole 400 mg daily for allogeneic HSCT (engraftment through day +75), (2) Posaconazole 300 mg daily for AML/MDS induction chemotherapy with expected neutropenia >7 days, (3) Fluconazole 400 mg daily for high-risk liver transplant recipients. INAPPROPRIATE (common): continuing prophylaxis beyond risk period, prophylaxis in ICU patients without neutropenia (routine fluconazole in surgical ICU not recommended by guidelines), prophylaxis based solely on positive BDG without clinical correlation.",drug:"fluconazole",monographId:"fluconazole"},{id:"fungal-infections/candidemia/alternative-de-escalation-fluconazole-susceptibl/fluconazole-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"candidemia",subcategoryName:"Candidemia & Invasive Candidiasis",line:"Alternative — De-escalation / Fluconazole-Susceptible",regimen:"Fluconazole 800 mg (12 mg/kg) IV/PO load × 1, then 400 mg (6 mg/kg) IV/PO daily",notes:"STEP-DOWN therapy once: (1) patient is clinically stable, (2) Candida species confirmed susceptible (MIC ≤2 mcg/mL), (3) blood cultures are clearing, (4) no metastatic complications. Loading dose is critical and frequently omitted. IV-to-PO switch: bioavailability is ~90%, so same dose PO. NOT appropriate for C. glabrata (dose-dependent susceptibility), C. krusei (intrinsically resistant), or critically ill patients on vasopressors.",drug:"fluconazole",monographId:"fluconazole"},{id:"fungal-infections/cryptococcal-meningitis/alternative-induction-resource-limited/fluconazole-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"cryptococcal-meningitis",subcategoryName:"Cryptococcal Meningitis",line:"Alternative — Induction (Resource-Limited)",regimen:"Fluconazole 1200 mg PO daily + Flucytosine 25 mg/kg PO q6h × 2 weeks",notes:"ACTHUNG trial: High-dose fluconazole + flucytosine is the best oral-only induction option. Faster CSF sterilization than fluconazole monotherapy. Important in resource-limited settings without amphotericin B access. Also validated: single high-dose amphotericin B liposomal (10 mg/kg × 1) + flucytosine + fluconazole (AMBITION trial) as simplified induction.",drug:"fluconazole",monographId:"fluconazole"},{id:"fungal-infections/cryptococcal-meningitis/consolidation-week-2-10/fluconazole-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"cryptococcal-meningitis",subcategoryName:"Cryptococcal Meningitis",line:"Consolidation (Week 2–10)",regimen:"Fluconazole 400–800 mg PO daily × 8 weeks",notes:"Begin after successful 2-week induction (clinical improvement, CSF sterilizing). Higher dose (800 mg) preferred in HIV patients. Continue with ART optimization — but timing of ART initiation is critical (see pearls).",drug:"fluconazole",monographId:"fluconazole"},{id:"fungal-infections/cryptococcal-meningitis/maintenance-week-10/fluconazole-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"cryptococcal-meningitis",subcategoryName:"Cryptococcal Meningitis",line:"Maintenance (Week 10+)",regimen:"Fluconazole 200 mg PO daily — continue until CD4 >100 × 1 year + undetectable viral load",notes:"Secondary prophylaxis. Can discontinue once immune reconstitution achieved: CD4 >100 for ≥1 year on ART with suppressed viral load. If CD4 drops below 100 again, restart maintenance fluconazole.",drug:"fluconazole",monographId:"fluconazole"}],voriconazole:[{id:"fungal-infections/antifungal-stewardship/stewardship-iv-to-po-azole-conversion/voriconazole-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"antifungal-stewardship",subcategoryName:"Antifungal Stewardship & De-escalation",line:"Stewardship — IV-to-PO Azole Conversion",regimen:"Switch voriconazole IV → voriconazole 200 mg PO q12h",notes:"Voriconazole oral bioavailability >96% — IV offers no pharmacokinetic advantage over PO. Switch as soon as patient can tolerate oral medications. IMPORTANT: Avoid taking with high-fat meals (reduces absorption by 34%). Also: PO tablets may actually give MORE predictable levels than IV in patients with renal impairment (avoids cyclodextrin accumulation).",drug:"voriconazole",monographId:"voriconazole"},{id:"fungal-infections/antifungal-stewardship/stewardship-tdm-optimization/voriconazole-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"antifungal-stewardship",subcategoryName:"Antifungal Stewardship & De-escalation",line:"Stewardship — TDM Optimization",regimen:"Voriconazole trough target: 1.0–5.5 mcg/mL",notes:"TDM schedule: Day 5 (steady state), then weekly until therapeutic and stable, then with dose changes, interacting drug changes, or clinical failure. Subtherapeutic (<1.0): Increase dose by 50%. Supratherapeutic (>5.5): Hold 1 dose, reduce by 50%, recheck in 3–5 days. CYP2C19 genotyping: Consider in patients with extreme levels despite standard dosing (PM vs UM phenotype). Posaconazole: Trough >1.0 mcg/mL for prophylaxis, >1.0–1.5 for treatment. Itraconazole: Trough >0.5 for prophylaxis, >1.0 for treatment.",drug:"voriconazole",monographId:"voriconazole"},{id:"fungal-infections/invasive-aspergillosis/preferred-first-line/voriconazole-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"invasive-aspergillosis",subcategoryName:"Invasive Pulmonary Aspergillosis",line:"Preferred — First-Line",regimen:"Voriconazole 6 mg/kg IV q12h × 2 doses (load), then 4 mg/kg IV q12h; PO: 200 mg q12h (≥40 kg)",notes:"IDSA 2016 first-line based on Herbrecht 2002 NEJM trial. THERAPEUTIC DRUG MONITORING IS MANDATORY — target trough 1.0–5.5 mcg/mL. Subtherapeutic levels (<1.0) associated with treatment failure, supratherapeutic (>5.5) associated with hepatotoxicity and neurotoxicity. Highly variable pharmacokinetics (CYP2C19 polymorphisms). Obtain first trough on day 5 of therapy. IV formulation contains sulfobutyl ether β-cyclodextrin (SBECD) — accumulates in CrCl <50, switch to PO if possible (PO bioavailability >96%).",drug:"voriconazole",monographId:"voriconazole"}],micafungin:[{id:"fungal-infections/candidemia/preferred-first-line-empiric/micafungin-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"candidemia",subcategoryName:"Candidemia & Invasive Candidiasis",line:"Preferred — First-Line Empiric",regimen:"Micafungin 100 mg IV once daily",notes:"IDSA 2016 first-line for candidemia regardless of severity or species. Echinocandins preferred over fluconazole because: (1) broader spectrum covering C. glabrata and C. krusei, (2) fungicidal vs. fungistatic, (3) better outcomes in RCTs (Reboli 2007). Continue until species identification and susceptibility allow de-escalation.",drug:"micafungin",monographId:"micafungin"},{id:"fungal-infections/invasive-aspergillosis/alternative-echinocandin-combination/micafungin-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"invasive-aspergillosis",subcategoryName:"Invasive Pulmonary Aspergillosis",line:"Alternative — Echinocandin Combination",regimen:"Voriconazole (standard dosing) + Micafungin 150 mg IV daily OR Caspofungin 70/50 mg IV daily",notes:"Combination therapy based on Marr 2015 trial: trend toward mortality benefit (19.3% vs 27.5%) that was not statistically significant overall, but subgroup with galactomannan-positive IA showed significant benefit. Consider combination in: (1) proven/probable IA with high fungal burden, (2) breakthrough on azole prophylaxis, (3) hematologic malignancy with prolonged neutropenia. NOT universally recommended — discuss with ID.",drug:"micafungin",monographId:"micafungin"},{id:"sepsis/sepsis-community/empiric-antifungal-only-if-specific-candida-risk/micafungin-1",diseaseId:"sepsis",diseaseName:"Sepsis & Septic Shock",diseaseIcon:"🔴",subcategoryId:"sepsis-community",subcategoryName:"Community-Acquired Sepsis",line:"Empiric Antifungal — Only if Specific Candida Risk Factors",regimen:"Micafungin 100mg IV q24h OR Caspofungin 70mg IV ×1 then 50mg IV q24h",notes:"Do NOT add empiric antifungals routinely — SSC 2021 recommends against empiric antifungal for sepsis without specific risk factors. Reserve for: TPN-dependent + broad-spectrum abx ≥5 days + septic shock without source; abdominal surgery with GI perforation + Candida colonization; immunocompromised + persistent fever. Echinocandins are first-line for candidemia per IDSA 2016. Obtain ophthalmology fundoscopic exam if Candida in blood (endophthalmitis changes management).",drug:"micafungin",monographId:"micafungin",evidence:"B-II",evidenceSource:"SSC 2021; IDSA Candidiasis 2016",evidenceSourceIds:["ssc-2021","idsa-candidiasis"]}],"amphotericin-b":[{id:"fungal-infections/candidemia/reserve-amphotericin-b/amphotericin-b-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"candidemia",subcategoryName:"Candidemia & Invasive Candidiasis",line:"Reserve — Amphotericin B",regimen:"Amphotericin B liposomal (AmBisome) 3–5 mg/kg IV daily",notes:"Reserve for: (1) echinocandin-resistant Candida (rare but increasing), (2) CNS candidiasis (echinocandins do not penetrate CNS), (3) endocarditis (in combination), (4) C. auris with pan-echinocandin resistance. Always use LIPID formulation — conventional amphotericin B deoxycholate has unacceptable nephrotoxicity. Monitor: daily BMP (creatinine, potassium, magnesium), CBC.",drug:"amphotericin-b",monographId:"amphotericin-b"},{id:"fungal-infections/cryptococcal-meningitis/preferred-induction-hiv-associated/amphotericin-b-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"cryptococcal-meningitis",subcategoryName:"Cryptococcal Meningitis",line:"Preferred — Induction (HIV-associated)",regimen:"Amphotericin B liposomal 3–4 mg/kg IV daily + Flucytosine 25 mg/kg PO q6h × 2 weeks",notes:"ACTHUNG trial + AMBITION trial evidence. Amphotericin B + flucytosine is the MOST EFFECTIVE induction regimen, achieving the fastest CSF sterilization (~1 week). Flucytosine is critical — do NOT omit. If flucytosine unavailable, amphotericin B + fluconazole 800 mg daily is an alternative but inferior induction. Monitor flucytosine levels (target peak 30–80 mcg/mL), CBC (myelosuppression), and renal function daily.",drug:"amphotericin-b",monographId:"amphotericin-b"},{id:"fungal-infections/invasive-aspergillosis/salvage-therapy/amphotericin-b-1",diseaseId:"fungal-infections",diseaseName:"Fungal Infections",diseaseIcon:"🍄",subcategoryId:"invasive-aspergillosis",subcategoryName:"Invasive Pulmonary Aspergillosis",line:"Salvage Therapy",regimen:"Amphotericin B liposomal (AmBisome) 3–5 mg/kg IV daily",notes:"Salvage for voriconazole/isavuconazole failure or intolerance. Higher doses (5 mg/kg) used in severe disease or CNS involvement. Also first-line if mucormycosis suspected (voriconazole has NO Mucorales activity). Monitor nephrotoxicity, electrolytes daily.",drug:"amphotericin-b",monographId:"amphotericin-b"}],aztreonam:[{id:"hap-vap/hap-mdr-risk/add-second-anti-pseudomonal-agent-if-mdr-pseudom/aztreonam-4",diseaseId:"hap-vap",diseaseName:"Hospital-Acquired & Ventilator-Associated Pneumonia",diseaseIcon:"🏥",subcategoryId:"hap-mdr-risk",subcategoryName:"HAP — MDR Risk Factors OR High Mortality Risk",line:"ADD Second Anti-Pseudomonal Agent (if MDR Pseudomonas risk)",regimen:"Aztreonam 2g IV q8h",notes:"Monobactam — NO cross-allergenicity with penicillins (safe in true penicillin allergy). Anti-pseudomonal. Covers gram-negatives only — no gram-positive or anaerobic activity. Useful in penicillin/cephalosporin allergy with Pseudomonas risk.",drug:"aztreonam",monographId:"aztreonam"}],fosfomycin:[{id:"uti/uncomplicated-cystitis/first-line/fosfomycin-3",diseaseId:"uti",diseaseName:"Urinary Tract Infections",diseaseIcon:"🔬",subcategoryId:"uncomplicated-cystitis",subcategoryName:"Uncomplicated Cystitis",line:"First-Line",regimen:"Fosfomycin trometamol 3g PO × 1 dose",notes:"Single-dose convenience. Slightly inferior efficacy vs. multi-day regimens per meta-analyses. Good for adherence-challenged patients. Mix in water, not hot beverages.",drug:"fosfomycin",monographId:"fosfomycin",evidence:"A-I",evidenceSource:"IDSA 2011",evidenceSourceIds:["idsa-escmid-2011-uti"]}]};export{a as REGIMEN_BY_ID,i as REGIMEN_CATALOG,n as REGIMEN_XREF_BY_MONOGRAPH_ID};
